async function init() {
  state.catalogue = await loadCatalogue(state.spriteSet);
  state.enemy.catalogue = await loadJson("./public/monsters/layers.json").catch(() => null);
  state.spellIndex = await loadJson("./public/spellfx/index.json").catch(() => ({ spells: [] }));
  state.itemData = await loadJson("./src/data/items.json").catch(() => ({ items: [] }));
  await applyItemIconAtlas(state.itemData);
  state.mapTileIndex = await loadJson("./public/maptiles/index.json").catch(() => ({ sets: [] }));
  state.mapObjectIndex = await loadJson("./public/mapobjects/index.json").catch(() => ({ sets: [] }));
  state.mapStampIndex = await loadJson(`./public/mapstamps/index.json?v=${MAP_STAMP_ASSET_VERSION}`).catch(() => ({ stamps: [] }));
  state.sfxManifest = await loadJson("./public/audio/sfx/manifest.json").catch(() => ({ byKey: {}, groups: [] }));
  state.prototypeStats.playerId = loadPrototypeStatsPlayerId();
  state.cloudSave.recoveryCode = loadOrCreateCloudRecoveryCode();
  state.cloudSave.lastSavedAt = loadCloudSavedAt();
  await loadPrototypeStatsConfig();
  state.mapSet = state.mapTileIndex.sets.find((set) => set.id === state.mapSet)?.id ?? state.mapTileIndex.sets[0]?.id ?? state.mapSet;
  state.warriorSkillAtlases = await loadWarriorSkillAtlases();
  state.wizardSpellAtlases = await loadCombatSpellAtlases(WIZARD_COMBAT_SPELLS);
  state.taoistSpellAtlases = await loadCombatSpellAtlases(TAOIST_COMBAT_SPELLS);
  state.taoistDefenceBuffImpactAtlases = Object.fromEntries(
    (await Promise.all(
      Object.entries(TAOIST_DEFENCE_BUFF_IMPACT_FX).map(async ([spellId, fxId]) => [
        spellId,
        await loadJson(`./public/spellfx/${fxId}/atlas.json`).catch(() => null),
      ]),
    )).filter(([, atlas]) => atlas),
  );
  state.taoPetAtlases = Object.fromEntries(
    await Promise.all(
      [
        CRYSTAL_SUMMON_SKELETON_PET_INDEX,
        CRYSTAL_SUMMON_SHINSU_PET_INDEX,
        CRYSTAL_SUMMON_SHINSU_VISIBLE_PET_INDEX,
        CRYSTAL_SUMMON_HOLY_DEVA_PET_INDEX,
      ].map(async (index) => [
        index,
        await loadJson(`./public/monsters/monster/${index}.json`).catch(() => null),
      ]),
    ),
  );
  state.taoPetAtlas = state.taoPetAtlases[CRYSTAL_SUMMON_SKELETON_PET_INDEX] ?? null;
  state.levelUpAtlas = await loadJson(`./public/spellfx/${LEVEL_UP_FX_ID}/atlas.json`).catch(() => null);
  state.healingRestoreAtlas = await loadJson(`./public/spellfx/${HEALING_RESTORE_FX_ID}/atlas.json`).catch(() => null);
  state.townIdleTeleportAtlas = await loadJson(`./public/spellfx/${TOWN_IDLE_TELEPORT_FX_ID}/atlas.json`).catch(() => null);
  state.townIdleReviveAtlas = await loadJson(`./public/spellfx/${REVIVE_FX_ID}/atlas.json`).catch(() => null);
  state.mapLightningAtlas = await loadJson(`./public/spellfx/${MAP_LIGHTNING_FX_ID}/atlas.json`).catch(() => null);
  state.mapHellFireAtlas = await loadJson(`./public/spellfx/${MAP_HELL_FIRE_FX_ID}/atlas.json`).catch(() => null);
  if (state.townIdleTeleportAtlas) await preloadSpellAtlasSheets(TOWN_IDLE_TELEPORT_FX_ID, state.townIdleTeleportAtlas);
  if (state.townIdleReviveAtlas) await preloadSpellAtlasSheets(REVIVE_FX_ID, state.townIdleReviveAtlas);
  if (state.mapLightningAtlas) await preloadSpellAtlasSheets(MAP_LIGHTNING_FX_ID, state.mapLightningAtlas);
  if (state.mapHellFireAtlas) await preloadSpellAtlasSheets(MAP_HELL_FIRE_FX_ID, state.mapHellFireAtlas);
  state.townNpcAtlases = await loadTownNpcAtlases();
  state.characterStateItems = {
    ...CHARACTER_PAPER_DOLL_FRAMES,
    ...(await loadJson("./public/ui/character/stateitems.json").catch(() => ({}))),
  };
  await applyStateItemAtlas(state.characterStateItems);
  const loadedSave = loadSavedGameState();
  if (!loadedSave) {
    state.characters = createDefaultCharacterStates();
    applyCharacterState("Warrior", state.characters.Warrior);
  }
  resetBattleForCurrentMode(loadedSave);
  applyPendingOfflineProgress();
  checkAchievementsForCurrentCharacter();
  maybeActivateDemoImport();

  renderLayerControls();
  renderEnemyControls();
  renderSpellControls();
  renderMapControls();
  renderGamePanel();
  renderSceneOverlay();
  renderOfflineReport();
  renderPrototypeStatsNotice();
  renderDemoLiveSiteBanner();
  renderDemoLiveSiteBar();
  renderUpdateAvailableBar();
  renderDemoImportWindow();
  renderCombatSkillBar();
  renderZoneEditor();
  renderActionControls();
  bindControls();
  reconcileSceneWindowPositions();
  syncFullscreenToggle();
  bindBossDamageReportControls();
  syncSceneWindowStackFromState();
  syncBackgroundMusic();
  await reloadAtlases();
  await reloadEnemyAtlas();
  saveReady = true;
  saveGameState(true);
  state.cloudSave.lastAttemptAt = performance.now();
  lastSimulationAt = performance.now();
  installTestHarness();
  requestAnimationFrame(tick);
}

function installTestHarness() {
  if (!TEST_HARNESS) return;
  window.__lomTest = {
    inspectInventory() {
      const zone = activeZone();
      const enemy = state.battle.enemy;
      return {
        itemCount: state.inventory.items.length,
        itemIds: state.inventory.items.map((entry) => entry.itemId),
        itemDataCount: state.itemData?.items?.length ?? 0,
        zoneId: zone?.id ?? null,
        dropCandidates: zone ? zoneDropCandidates(zone, enemy).length : 0,
        mode: state.game.mode,
        running: Boolean(state.battle.running),
      };
    },
    runOfflineZoneProgress(elapsedMs) {
      if (state.game.mode !== "zone" || !state.battle.running) {
        return {
          error: "not in zone combat",
          mode: state.game.mode,
          running: Boolean(state.battle.running),
        };
      }
      const zone = activeZone();
      if (!zone) return { error: "no active zone" };
      const limitMs = Math.max(0, Math.trunc(Number(elapsedMs) || 0));
      let report;
      suppressSimulationRender = true;
      try {
        report = simulateOfflineProgress(zone, {
          elapsedMs: Math.min(limitMs, OFFLINE_PROGRESS_CAP_MS),
          capped: limitMs > OFFLINE_PROGRESS_CAP_MS,
        });
      } finally {
        suppressSimulationRender = false;
      }
      if (!report) return { error: "no report" };
      const playerMp = state.battle.player?.mp ?? 0;
      return {
        kills: report.kills,
        xp: report.xp,
        gold: report.gold,
        elapsedMs: report.elapsedMs,
        playerHp: state.battle.player?.hp ?? 0,
        playerMp,
        playerMaxMp: state.battle.player?.maxMp ?? 0,
        playerDied: Boolean(report.diedAtMs),
        levels: [...(report.levels ?? [])],
        damageTaken: report.damageTaken ?? 0,
      };
    },
    runOfflineMiningProgress(elapsedMs) {
      if (state.game.mode !== "mining") {
        return { error: "not mining", mode: state.game.mode };
      }
      if (state.paused) return { error: "paused" };
      const limitMs = Math.max(0, Math.trunc(Number(elapsedMs) || 0));
      let report;
      suppressSimulationRender = true;
      try {
        report = simulateOfflineMining({
          elapsedMs: Math.min(limitMs, OFFLINE_PROGRESS_CAP_MS),
          capped: limitMs > OFFLINE_PROGRESS_CAP_MS,
        });
      } finally {
        suppressSimulationRender = false;
      }
      if (!report) return { error: "no report" };
      const drops = {};
      for (const [label, count] of report.drops ?? []) drops[label] = count;
      const ignoredDrops = {};
      for (const [label, count] of report.ignoredDrops ?? []) ignoredDrops[label] = count;
      return {
        swings: report.swings,
        hits: report.hits,
        elapsedMs: report.elapsedMs,
        drops,
        ignoredDrops,
        inventoryItems: state.inventory.items.length,
      };
    },
    grantTeleportRing() {
      markUnlockOwned(TELEPORT_RING_UNLOCK_KEY);
      applyOwnedUnlocks();
      renderGamePanel();
      return {
        owned: teleportRingOwned(),
        buttonHidden: document.getElementById("teleportRingButton")?.hidden ?? null,
      };
    },
    openTeleportRingMenu() {
      openScene("teleportRing");
      const buttons = [...document.querySelectorAll("[data-teleport-ring-zone]")];
      return buttons.map((button) => ({
        zoneId: button.dataset.teleportRingZone,
        text: button.textContent.replace(/\s+/g, " ").trim(),
      }));
    },
  };
}

async function preloadSpellAtlasSheets(spellId, atlas) {
  if (!atlas) return;
  const sheets = new Set();
  for (const layer of atlas.layers ?? []) {
    if (layer.sheet) sheets.add(layer.sheet);
  }
  for (const key of ["projectile", "impact", "ground", "storm", "cast", "charge"]) {
    if (atlas[key]?.sheet) sheets.add(atlas[key].sheet);
  }
  for (const sheet of atlas.sheets ?? []) {
    if (sheet) sheets.add(sheet);
  }
  if (atlas.sheet) sheets.add(atlas.sheet);
  await Promise.all(
    [...sheets].map((sheet) => loadCachedImage(`./public/spellfx/${spellId}/${sheet}`).catch(() => null)),
  );
}

async function loadWarriorSkillAtlases() {
  const entries = await Promise.all(
    WARRIOR_COMBAT_SKILLS.filter((skill) => skill.id !== "None").map(async (skill) => [
      skill.id,
      await loadJson(`./public/spellfx/${skill.id}/atlas.json`).catch(() => null),
    ]),
  );
  const atlases = Object.fromEntries(entries.filter(([, atlas]) => atlas));
  await Promise.all(Object.entries(atlases).map(([spellId, atlas]) => preloadSpellAtlasSheets(spellId, atlas)));
  return atlases;
}

async function loadCombatSpellAtlases(spells) {
  const entries = await Promise.all(
    spells.map(async (spell) => [
      spell.id,
      await loadJson(`./public/spellfx/${spell.id}/atlas.json`).catch(() => null),
    ]),
  );
  const atlases = Object.fromEntries(entries.filter(([, atlas]) => atlas));
  await Promise.all(Object.entries(atlases).map(([spellId, atlas]) => preloadSpellAtlasSheets(spellId, atlas)));
  return atlases;
}

async function loadTownNpcAtlases() {
  const sprites = [...new Set(TOWN_NPCS.map((npc) => npc.sprite).filter(Boolean))];
  const entries = await Promise.all(
    sprites.map(async (sprite) => [
      sprite,
      await loadJson(`./public/npcs/${sprite}/atlas.json`).catch(() => null),
    ]),
  );
  return Object.fromEntries(entries.filter(([, atlas]) => atlas));
}

function resetBattleForCurrentMode(loadedSave = false) {
  const zone = activeZone();
  if (state.game.mode === "mining" && zone) {
    ensureMiningSpotId(false);
    state.showEnemies = true;
    resetBattle();
    ensureMapStampArenaLock();
    state.battle.cameraX = state.battle.playerX - playerScreenX();
    state.battle.enemy = null;
    state.battle.running = false;
    state.battle.phase = "idle";
    restorePendingSavedPlayerResources();
    const spot = activeMiningSpot();
    state.battle.log = [loadedSave ? `Save loaded at ${spot?.label ?? zone.label}.` : `Mining at ${spot?.label ?? zone.label}.`];
    applyEquippedVisualIndexes();
    queueVisualAtlasReload(["weapon"]);
    setPlayerAction("mine", performance.now(), true);
    return;
  }
  if (state.game.mode === "zone" && zone) {
    state.showEnemies = true;
    resetBattle(randomZoneEnemyTemplate(zone).id);
    restorePendingSavedPlayerResources();
    state.battle.log = [loadedSave ? `Save loaded in ${zone.label}.` : `Teleported to ${zone.label}.`];
    if ((state.battle.player?.hp ?? 0) <= 0) {
      finishBattle(performance.now());
      setPlayerAction("die", performance.now());
      return;
    }
    startBattle();
    return;
  }

  state.game.mode = "town";
  state.game.activeZoneId = null;
  state.showEnemies = false;
  resetBattle();
  restorePendingSavedPlayerResources();
  if (loadedSave) state.battle.log = ["Save loaded."];
}

function createSaveSnapshot() {
  if (bossPartyOnField()) {
    const leaderClassId = bossPartyLeaderClassId();
    if (normalizeCharacterId(state.activeCharacterId) === leaderClassId) {
      syncBossPartyControlledMemberFromState(leaderClassId);
    } else {
      captureActiveCharacterState();
    }
    syncBossPartyMembersToCharacters(state.battle.bossParty, { applyControlled: false });
  } else {
    captureActiveCharacterState();
  }
  const activeCharacter = state.characters[state.activeCharacterId] ?? serializeCurrentCharacterState();
  const groupDungeonRun = groupDungeonOfflineRunSnapshot?.()
    ?? sanitizeGroupDungeonOfflineRun?.(activeCharacter.game?.groupDungeonRun, activeCharacter.game?.activeZoneId, state.activeCharacterId)
    ?? null;
  return {
    version: SAVE_VERSION,
    savedAt: Date.now(),
    activeCharacterId: state.activeCharacterId,
    groupDungeonRun,
    characters: serializeCharactersState(),
    account: {
      storage: cloneStorageState(state.account.storage),
      upgrades: cloneAccountUpgradeState(state.account.upgrades),
      rebirthPoints: accountRebirthPoints(),
      bossRespawns: { ...accountBossRespawns() },
      stats: sanitizeAccountStats(state.account.stats),
      codex: cloneAccountCodexState(state.account.codex),
      achievements: cloneAccountAchievementState(state.account.achievements),
      ownedUnlocks: sanitizeOwnedUnlocks(state.account.ownedUnlocks),
    },
    game: {
      ...activeCharacter.game,
      progress: { ...activeCharacter.game.progress },
      dropPity: { ...activeCharacter.game.dropPity },
      bossRespawns: { ...activeCharacter.game.bossRespawns },
      bossKills: { ...activeCharacter.game.bossKills },
      recentLoot: [...activeCharacter.game.recentLoot],
    },
    inventory: cloneInventoryStateIncludingWeaponRefineStaged(activeCharacter.inventory),
    hotbar: cloneHotbarState(activeCharacter.hotbar),
    magic: cloneMagicState(activeCharacter.magic),
    battle: {
      combatClass: state.battle.combatClass,
      ...activeCharacter.battle,
    },
    indexes: {
      armour: state.indexes.armour,
      hair: state.indexes.hair,
      weapon: state.indexes.weapon,
    },
    characterTab: state.characterTab,
    settings: {
      musicSettingsVersion: MUSIC_SETTINGS_VERSION,
      musicEnabled: Boolean(state.settings.musicEnabled),
      musicVolume: normalizedVolume(state.settings.musicVolume),
      musicMode: normalizedMusicMode(state.settings.musicMode),
      musicTrackId: currentMusicTrack()?.id ?? BACKGROUND_MUSIC_TRACKS[0]?.id ?? null,
      sfxEnabled: Boolean(state.settings.sfxEnabled),
      sfxVolume: normalizedVolume(state.settings.sfxVolume),
      prototypeStatsEnabled: Boolean(state.settings.prototypeStatsEnabled),
      prototypeStatsNoticeVersion: Math.max(0, Math.trunc(Number(state.settings.prototypeStatsNoticeVersion) || 0)),
      prototypeResetNoticeVersion: Math.max(0, Math.trunc(Number(state.settings.prototypeResetNoticeVersion) || 0)),
      prototypeResetNoticeLastSeenAt: Math.max(0, Math.trunc(Number(state.settings.prototypeResetNoticeLastSeenAt) || 0)),
      cloudBackupNoticeVersion: Math.max(0, Math.trunc(Number(state.settings.cloudBackupNoticeVersion) || 0)),
      cloudBackupNoticeLastSeenAt: Math.max(0, Math.trunc(Number(state.settings.cloudBackupNoticeLastSeenAt) || 0)),
      demoLiveSiteBannerLastSeenAt: Math.max(0, Math.trunc(Number(state.settings.demoLiveSiteBannerLastSeenAt) || 0)),
      unfairSkillPurgeVersion: Math.max(0, Math.trunc(Number(state.settings.unfairSkillPurgeVersion) || 0)),
      sceneWindowPositions: {
        character: state.settings.sceneWindowPositions?.character ?? null,
        inventory: state.settings.sceneWindowPositions?.inventory ?? null,
      },
    },
  };
}

function saveGameState(force = false) {
  if (!saveReady && !force) return false;
  try {
    localStorage.setItem(SAVE_KEY, JSON.stringify(createSaveSnapshot()));
    lastSaveAt = performance.now();
    return true;
  } catch (err) {
    console.warn("Unable to save game state", err);
    return false;
  }
}

function saveImportBlockedReason() {
  if (bossPartyOnField()) return "Return to town before importing a save.";
  return null;
}

function exportSaveDownloadName() {
  const stamp = new Date().toISOString().slice(0, 10);
  return `lom-idle-v2-save-${stamp}.json`;
}

function exportGameSave() {
  try {
    const snapshot = createSaveSnapshot();
    const json = JSON.stringify(snapshot, null, 2);
    const blob = new Blob([json], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = exportSaveDownloadName();
    link.click();
    URL.revokeObjectURL(url);
    pushBattleLog("Save exported.");
    playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
    return true;
  } catch (err) {
    console.warn("Unable to export game save", err);
    window.alert("Export failed. Try again after returning to town.");
    return false;
  }
}

function clearTransientBattleForSaveImport() {
  stopOneStepTest();
  state.continuousWalk = false;
  state.battle.bossParty = null;
  dismissBattleCompanions();
  state.battle.pendingImpact = null;
  state.battle.pendingEnemyStrike = null;
  state.battle.pendingEnemyStruck = false;
  state.battle.pendingHeal = null;
  state.battle.pendingPoison = null;
  state.battle.pendingPetAttack = null;
  state.battle.pendingTwinDrakeHits = [];
  clearSlashingBurstPendingState();
  state.battle.groundSpellEffects = [];
  state.battle.attachedSpellFx = [];
  clearTwinDrakePendingState();
}

async function replaceCurrentGameWithSnapshot(snapshot, successMessage) {
  const blockReason = saveImportBlockedReason();
  if (blockReason) {
    window.alert(blockReason);
    return false;
  }

  saveReady = false;
  clearTransientBattleForSaveImport();
  if (!applySaveSnapshot(snapshot)) {
    saveReady = true;
    window.alert("Could not apply that save.");
    return false;
  }

  saveGameState(true);
  resetBattleForCurrentMode(true);
  applyPendingOfflineProgress();
  await reloadAtlases();
  await reloadEnemyAtlas();
  saveReady = true;
  invalidateUi();
  renderLayerControls();
  renderMapControls();
  renderGamePanel();
  renderBattlePanel();
  renderSceneOverlay();
  renderOfflineReport();
  renderCombatSkillBar();
  renderHotbar();
  render();
  closeScene("options");
  pushBattleLog(successMessage);
  playSfx("ui.teleport", { volume: 0.42, throttleMs: 300 });
  return true;
}

async function importGameSaveFromText(rawText) {
  const blockReason = saveImportBlockedReason();
  if (blockReason) {
    window.alert(blockReason);
    return false;
  }

  const parsed = parseSaveSnapshotText(rawText);
  if (!parsed.ok) {
    window.alert(parsed.error);
    return false;
  }

  if (!window.confirm("Import this save? Progress on this device will be replaced.")) {
    return false;
  }

  return replaceCurrentGameWithSnapshot(parsed.snapshot, "Save imported.");
}

function loadSavedGameState() {
  let snapshot;
  try {
    const raw = localStorage.getItem(SAVE_KEY);
    if (!raw) return false;
    const parsed = parseSaveSnapshotText(raw);
    if (!parsed.ok) return false;
    snapshot = parsed.snapshot;
  } catch (err) {
    console.warn("Unable to load game state", err);
    return false;
  }

  return applySaveSnapshot(snapshot);
}

function accountRestoreOptions() {
  return {
    characterIds: CHARACTER_IDS,
    sanitizeStorage: sanitizeStorageState,
    sanitizeUpgrades: sanitizeAccountUpgradeState,
    sanitizeBossRespawns,
    sanitizeAccountStats,
    sanitizeCodex: sanitizeAccountCodexState,
    sanitizeAchievements: sanitizeAccountAchievementState,
    sanitizeOwnedUnlocks,
    sanitizeBossKills,
  };
}

// One-time purge of skills/books obtained via the old test bookstore exploit.
// These high-level books (lvl 36-60) could not have been earned legitimately in
// the exploit window, so any save that predates this migration has them stripped
// exactly once. Bump UNFAIR_SKILL_PURGE_VERSION only to re-run a future purge.
const UNFAIR_SKILL_PURGE_VERSION = 1;
const UNFAIR_PURGE_SPELL_IDS = new Set([
  "LionRoar",
  "Reincarnation",
  "BladeAvalanche",
  "CrossHalfMoon",
  "SummonHolyDeva",
  "HealingCircle",
  "ProtectionField",
  "Curse",
  "Mirroring",
  "FlameField",
  "Plague",
  "PoisonCloud",
  "Blizzard",
  "Rage",
  "Fury",
  "PetEnhancer",
  "MagicBooster",
  "MeteorStrike",
  "ImmortalSkin",
]);
const UNFAIR_PURGE_BOOK_ITEM_IDS = new Set([
  "book-lion-roar",
  "book-reincarnation",
  "book-blade-avalanche",
  "book-cross-half-moon",
  "book-summon-holy-deva",
  "book-healing-circle",
  "book-protection-field",
  "book-curse",
  "book-mirroring",
  "book-flame-field",
  "book-plague",
  "book-poison-cloud",
  "book-blizzard",
  "book-rage",
  "book-fury",
  "book-pet-enhancer",
  "book-magic-booster",
  "book-meteor-strike",
  "book-immortal-skin",
]);

function purgeUnfairBooksFromContainer(container) {
  if (!container || !Array.isArray(container.items)) return false;
  const before = container.items.length;
  container.items = container.items.filter((entry) => !UNFAIR_PURGE_BOOK_ITEM_IDS.has(entry?.itemId));
  return container.items.length !== before;
}

function purgeUnfairSkillsFromCharacter(character) {
  let changed = false;
  const learned = character?.magic?.learned;
  if (learned && typeof learned === "object") {
    for (const spellId of Object.keys(learned)) {
      if (UNFAIR_PURGE_SPELL_IDS.has(spellId)) {
        delete learned[spellId];
        changed = true;
      }
    }
  }
  if (purgeUnfairBooksFromContainer(character?.inventory)) changed = true;
  return changed;
}

// Runs against the already-restored state.characters + state.account.storage.
// Returns true when the migration executed (so the caller stamps the version),
// regardless of whether anything was actually removed.
function maybePurgeUnfairSkills(snapshot) {
  const seenVersion = Math.max(0, Math.trunc(Number(snapshot?.settings?.unfairSkillPurgeVersion) || 0));
  if (seenVersion >= UNFAIR_SKILL_PURGE_VERSION) return false;
  for (const character of Object.values(state.characters ?? {})) {
    purgeUnfairSkillsFromCharacter(character);
  }
  purgeUnfairBooksFromContainer(state.account?.storage);
  return true;
}

function applySaveSnapshot(snapshot) {
  if (!snapshot) return false;

  state.characters = restoreCharactersState(snapshot);
  const { account, hadUnpaidStoragePage2 } = restoreAccountFromSnapshot(
    snapshot,
    state.characters,
    accountRestoreOptions(),
  );
  state.account = account;
  const ranUnfairSkillPurge = maybePurgeUnfairSkills(snapshot);
  syncAccountBossKillsToCharacters();
  syncAccountBossRespawnsToCharacters();
  const uiMeta = restoreSaveUiMeta(snapshot, {
    characterTabIds: CHARACTER_TABS.map((tab) => tab.id),
    normalizeCharacterId,
  });
  state.activeCharacterId = uiMeta.activeCharacterId;
  applyCharacterState(state.activeCharacterId, state.characters[state.activeCharacterId]);
  applyOwnedUnlocks();
  if (hadUnpaidStoragePage2 && state.account.storage.pagesUnlocked === 1) {
    state.storagePage = 0;
    pushBattleLog("Storage page 2 was reset. Unlock it for 1,000,000 gold when you're ready.");
  }
  restoreSettingsState(snapshot);
  if (ranUnfairSkillPurge) {
    state.settings.unfairSkillPurgeVersion = UNFAIR_SKILL_PURGE_VERSION;
  }
  state.indexes.armour = 0;
  state.indexes.hair = uiMeta.hairIndex;
  state.indexes.weapon = null;
  applyEquippedVisualIndexes();
  state.characterTab = uiMeta.characterTab;
  const groupDungeonRun = resolveSavedGroupDungeonRun(
    snapshot,
    state.game.activeZoneId,
    state.activeCharacterId,
    {
      characterIds: CHARACTER_IDS,
      sanitizeGroupDungeonRun: (run, zoneId, classId) =>
        sanitizeGroupDungeonOfflineRun?.(run, zoneId, classId) ?? null,
      groupDungeonWaveSpawnCount,
      findZone: (zoneId) => PROTOTYPE_ZONES.find((entry) => entry.id === zoneId),
      charactersFallback: state.characters,
    },
  );
  if (groupDungeonRun?.zoneId === state.game.activeZoneId) {
    state.game.groupDungeonRun = groupDungeonRun;
    state.pendingBossAssistSelection = groupDungeonRun.classIds.filter((classId) => classId !== state.activeCharacterId);
    state.bossAssistSelection = [...state.pendingBossAssistSelection];
  } else {
    state.game.groupDungeonRun = null;
    state.pendingBossAssistSelection = [];
    state.bossAssistSelection = [];
  }
  pendingOfflineProgress = createPendingOfflineProgress({
    ...snapshot,
    game: state.game,
    battle: {
      ...(snapshot.battle ?? {}),
      ...(state.characters[state.activeCharacterId]?.battle ?? {}),
      combatClass: state.activeCharacterId,
    },
  });
  return true;
}

function normalizeCharacterId(classId) {
  const candidate = String(classId ?? "");
  const match = CHARACTER_SELECT_CLASSES.find((entry) => entry.id === candidate && !entry.disabled);
  return match?.id ?? "Warrior";
}

function createDefaultCharacterStates() {
  return Object.fromEntries(CHARACTER_IDS.map((classId) => [classId, createDefaultCharacterState(classId)]));
}

function createDefaultStorageState() {
  return {
    pagesUnlocked: 1,
    page2Purchased: false,
    tokenPageUnlocked: false,
    maxSlots: STORAGE_BASE_SLOTS,
    nextInstanceId: 1,
    items: [],
  };
}

function createDefaultAccountStats() {
  return {
    rebirthCount: 0,
    rebirthPointsGained: 0,
    rebirthPointsSpent: 0,
    bossKills: {},
  };
}

function createDefaultAccountUpgradeState() {
  return {
    tiers: {},
  };
}

function createDefaultAccountCodexState() {
  return {
    items: {},
  };
}

function createDefaultAccountAchievementState() {
  return {
    enabled: false,
    unlocked: {},
  };
}

function createDefaultCharacterState(classId) {
  const inventory = createStarterInventoryState(classId);
  return {
    classId,
    game: {
      mode: "town",
      activeZoneId: null,
      kills: 0,
      zoneKills: 0,
      distance: 0,
      playtimeMs: 0,
      lastReward: null,
      recentLoot: [],
      dropPity: {},
      bossRespawns: {},
      bossKills: {},
      progress: {
        level: PLAYER_TEMPLATE.level,
        experience: PLAYER_TEMPLATE.experience,
        gold: inventory.gold,
      },
      starterGearVersion: STARTER_GEAR_VERSION,
      miningNextRollAt: 0,
      miningSpotId: null,
      groupDungeonRun: null,
    },
    inventory,
    hotbar: { slots: Array(HOTBAR_SLOT_COUNT).fill(null) },
    magic: { learned: {} },
    battle: {
      running: false,
      paused: false,
      playerHp: null,
      playerMp: null,
      potHealthAmount: 0,
      potManaAmount: 0,
      healAmount: 0,
      vampAmount: 0,
      statBuffs: [],
      petStatBuffs: [],
    },
  };
}

function createStarterInventoryState(classId) {
  const inventory = {
    gold: PLAYER_TEMPLATE.gold,
    pagesUnlocked: 1,
    goldPageUnlocked: false,
    tokenPageUnlocked: false,
    maxSlots: INVENTORY_BASE_SLOTS,
    nextInstanceId: 1,
    items: [],
    equipment: Object.fromEntries(EQUIPMENT_SLOTS.map((slot) => [slot.id, null])),
  };
  const starterItems = ["Warrior", "Wizard", "Taoist"].includes(classId)
    ? [["wooden-sword", 1], ["base-dress", 1], ["hp-drug-small", 5], ["mp-drug-small", 5]]
    : [["base-dress", 1], ["hp-drug-small", 5], ["mp-drug-small", 5]];
  for (const [itemId, quantity] of starterItems) addStarterInventoryEntry(inventory, itemId, quantity);
  return inventory;
}

function addStarterInventoryEntry(inventory, itemId, quantity = 1) {
  const item = itemDefinition(itemId);
  if (!item) return;
  const entry = {
    id: `item-${inventory.nextInstanceId}`,
    itemId,
    quantity: Math.max(1, Math.trunc(Number(quantity) || 1)),
    slot: nextFreeSlotInInventoryState(inventory),
    ...normalizeInventoryEntryFields({}, item),
  };
  inventory.nextInstanceId += 1;
  inventory.items.push(entry);
}

function nextFreeSlotInInventoryState(inventory) {
  syncInventoryCapacity(inventory);
  const used = new Set();
  for (const entry of inventory.items ?? []) {
    const slot = entry.slot;
    if (Number.isInteger(slot) && slot >= 0 && slot < inventory.maxSlots) used.add(slot);
  }
  for (let slot = 0; slot < inventory.maxSlots; slot++) {
    if (!used.has(slot)) return slot;
  }
  return null;
}

function characterRestoreOptions() {
  return {
    characterIds: CHARACTER_IDS,
    createDefaultCharacter: createDefaultCharacterState,
    normalizeCharacterId,
    starterGearVersion: STARTER_GEAR_VERSION,
    backfillStarterItem: backfillInventoryItem,
    sanitizeGame: (game, gold, classId) => sanitizeCharacterGameState(game, gold, classId),
    sanitizeInventory: sanitizeInventoryState,
    sanitizeHotbar: sanitizeHotbarState,
    sanitizeMagic: (_classId, magic) => sanitizeMagicState(magic),
    sanitizeBattle: sanitizeCharacterBattleState,
    retiredWizardSpells: RETIRED_TEST_DEFAULT_WIZARD_SPELLS,
  };
}

function restoreCharactersState(snapshot) {
  return restoreCharactersFromSnapshot(snapshot, characterRestoreOptions());
}

function backfillInventoryItem(inventory, itemId, quantity = 1) {
  if (!inventory || inventory.items?.some((entry) => entry.itemId === itemId)) return false;
  addStarterInventoryEntry(inventory, itemId, quantity);
  return true;
}

function sanitizeCharacterGameState(savedGame, fallbackGold = PLAYER_TEMPLATE.gold, fallbackClassId = state.activeCharacterId) {
  return sanitizeCharacterGameStateCore(savedGame, {
    fallbackGold,
    fallbackLevel: PLAYER_TEMPLATE.level,
    zoneIds: PROTOTYPE_ZONES.map((zone) => zone.id),
    miningZoneId: MINING_ZONE_ID,
    resolveMiningSpotId: (spotId) => miningSpotById(spotId)?.id ?? null,
    sanitizeDropPity,
    sanitizeBossRespawns,
    sanitizeBossKills,
    sanitizeGroupDungeonRun: (run, activeZoneId, classId) =>
      sanitizeGroupDungeonOfflineRun?.(run, activeZoneId, classId) ?? null,
    fallbackClassId,
  });
}

function sanitizeBossRespawns(respawns = {}) {
  return sanitizeBossRespawnsCore(respawns, zoneTracksBossRespawn);
}

function sanitizeAccountStats(saved = {}) {
  return sanitizeAccountStatsCore(saved, zoneTracksBossRespawn);
}

function ensureAccountStats() {
  state.account.stats = sanitizeAccountStats(state.account?.stats);
}

function accountBossKills() {
  ensureAccountStats();
  return { ...sanitizeBossKills(state.account.stats.bossKills) };
}

function syncAccountBossKillsToCharacters() {
  const kills = accountBossKills();
  state.game.bossKills = { ...kills };
  for (const classId of CHARACTER_IDS) {
    const character = state.characters[classId];
    if (!character) continue;
    character.game.bossKills = { ...kills };
  }
}

function migrateAccountStats() {
  ensureAccountStats();
  state.account.stats.bossKills = mergeAccountBossKills(
    state.account.stats.bossKills,
    state.characters,
    accountRestoreOptions(),
  );
  syncAccountBossKillsToCharacters();
}

function trackRebirthPointsGained(quantity) {
  const amount = Math.max(0, Math.trunc(Number(quantity) || 0));
  if (amount <= 0) return;
  ensureAccountStats();
  state.account.stats.rebirthPointsGained += amount;
}

function trackRebirthPointsSpent(quantity) {
  const amount = Math.max(0, Math.trunc(Number(quantity) || 0));
  if (amount <= 0) return;
  ensureAccountStats();
  state.account.stats.rebirthPointsSpent += amount;
}

function accountTotalGold() {
  captureActiveCharacterState();
  let total = 0;
  for (const classId of CHARACTER_IDS) {
    const character = state.characters[classId];
    total += Math.max(0, Math.trunc(Number(character?.game?.progress?.gold ?? character?.inventory?.gold) || 0));
  }
  return total;
}

function accountStatsSnapshot() {
  ensureAccountStats();
  captureActiveCharacterState();
  const bossKills = accountBossKills();
  const characterLevels = {};
  for (const classId of CHARACTER_IDS) {
    const progress = state.characters[classId]?.game?.progress;
    characterLevels[classId] = Math.max(1, Math.trunc(Number(progress?.level) || 1));
  }
  return {
    rebirthCount: state.account.stats.rebirthCount,
    rebirthPointsGained: state.account.stats.rebirthPointsGained,
    rebirthPointsSpent: state.account.stats.rebirthPointsSpent,
    rebirthPointsHeld: accountRebirthPoints(),
    awakeningSoulsHeld: accountAwakenedSoulCount(),
    totalGold: accountTotalGold(),
    bossKills,
    bossKillsTotal: Object.values(bossKills).reduce((sum, count) => sum + Math.max(0, Math.trunc(Number(count) || 0)), 0),
    characterLevels,
    highestCharacterLevel: Math.max(1, ...Object.values(characterLevels)),
  };
}

function sanitizeBossKills(kills = {}) {
  return sanitizeBossKillsCore(kills, zoneTracksBossRespawn);
}

function sanitizeInventoryState(savedInventory = {}, savedHotbar = {}, fallbackGold = 0) {
  return sanitizeInventoryStateCore(savedInventory, savedHotbar, {
    fallbackGold,
    equipmentSlotIds: EQUIPMENT_SLOTS.map((slot) => slot.id),
    pageSize: INVENTORY_PAGE_SIZE,
    maxSlots: INVENTORY_MAX_SLOTS,
    maxPages: inventoryPageCount(),
    normalizeEntryFields: (savedEntry) => normalizeInventoryEntryFields(savedEntry),
  });
}

function sanitizeStorageState(savedStorage = {}) {
  const storage = sanitizeStorageStateCore(savedStorage, {
    pageSize: STORAGE_PAGE_SIZE,
    baseSlots: STORAGE_BASE_SLOTS,
    maxPages: storagePageCount(),
    normalizeEntryFields: (savedEntry) => normalizeInventoryEntryFields(savedEntry),
  });
  syncStorageCapacity(storage);
  ensureStorageSlots(storage);
  return storage;
}

// Keeps only recognised one-off unlock keys (the account-wide storage page and
// each character's inventory page). Server reconciliation is the real authority.
function sanitizeOwnedUnlocks(owned) {
  const valid = new Set([
    STORAGE_PAGE_UNLOCK_KEY,
    TELEPORT_RING_UNLOCK_KEY,
    ...CHARACTER_IDS.map((classId) => inventoryPageUnlockKey(classId)),
  ]);
  const result = {};
  if (owned && typeof owned === "object") {
    for (const [key, value] of Object.entries(owned)) {
      if (value && valid.has(key)) result[key] = true;
    }
  }
  return result;
}

function sanitizeAccountUpgradeState(savedUpgrades = {}) {
  return sanitizeAccountUpgradeStateCore(savedUpgrades, ACCOUNT_UPGRADE_DEFS, {
    rebirthBaseStatUpgradeIds: REBIRTH_BASE_STAT_UPGRADE_IDS,
    legacyStatUpgradeId: LEGACY_REBIRTH_BASE_STAT_UPGRADE_ID,
  });
}

function sanitizeAccountCodexState(savedCodex = {}) {
  const codex = createDefaultAccountCodexState();
  const savedItems = savedCodex?.items && typeof savedCodex.items === "object" ? savedCodex.items : {};
  for (const [rawItemId, rawEntry] of Object.entries(savedItems)) {
    const item = itemDefinition(rawItemId);
    if (!item) continue;
    const sources = {};
    const rawSources = rawEntry?.sources && typeof rawEntry.sources === "object" ? rawEntry.sources : {};
    for (const [rawSourceId, rawSource] of Object.entries(rawSources)) {
      const sourceId = String(rawSource?.id ?? rawSourceId ?? "").trim();
      const label = String(rawSource?.label ?? "").trim();
      if (!sourceId || !label) continue;
      sources[sourceId] = {
        id: sourceId,
        label,
        count: Math.max(1, Math.trunc(Number(rawSource?.count) || 1)),
        firstSeenAt: Math.max(0, Math.trunc(Number(rawSource?.firstSeenAt) || Number(rawEntry?.firstSeenAt) || 0)),
        lastSeenAt: Math.max(0, Math.trunc(Number(rawSource?.lastSeenAt) || Number(rawEntry?.lastSeenAt) || 0)),
      };
    }
    codex.items[item.id] = {
      itemId: item.id,
      firstSeenAt: Math.max(0, Math.trunc(Number(rawEntry?.firstSeenAt) || 0)),
      lastSeenAt: Math.max(0, Math.trunc(Number(rawEntry?.lastSeenAt) || 0)),
      sources,
    };
  }
  return codex;
}

function cloneAccountCodexState(codex) {
  return sanitizeAccountCodexState(codex);
}

function sanitizeAccountAchievementState(savedAchievements = {}) {
  const achievements = createDefaultAccountAchievementState();
  achievements.enabled = savedAchievements?.enabled === true;
  const savedUnlocked = savedAchievements?.unlocked && typeof savedAchievements.unlocked === "object"
    ? savedAchievements.unlocked
    : {};
  for (const def of ACHIEVEMENT_DEFS) {
    const raw = savedUnlocked[def.id];
    if (!raw) continue;
    achievements.unlocked[def.id] = {
      id: def.id,
      unlockedAt: Math.max(0, Math.trunc(Number(raw.unlockedAt) || 0)),
      characterId: normalizeCharacterId(raw.characterId ?? state.activeCharacterId),
      rewardClaimed: raw.rewardClaimed !== false,
    };
  }
  return achievements;
}

function cloneAccountAchievementState(achievements) {
  return sanitizeAccountAchievementState(achievements);
}

function awakeningSoulQuantityInInventory(inventory, itemId = AWAKENING_SOUL_ITEM_ID) {
  return (inventory?.items ?? [])
    .filter((entry) => entry.itemId === itemId)
    .reduce((total, entry) => total + Math.max(1, Math.trunc(Number(entry.quantity) || 1)), 0);
}

function accountAwakenedSoulCount() {
  captureActiveCharacterState();
  let total = 0;
  for (const classId of CHARACTER_IDS) {
    total += awakeningSoulQuantityInInventory(state.characters[classId]?.inventory);
  }
  for (const entry of storageEntries()) {
    if (entry.itemId === AWAKENING_SOUL_ITEM_ID) {
      total += Math.max(1, Math.trunc(Number(entry.quantity) || 1));
    }
  }
  return total;
}

function canPerformRebirth() {
  if (!REBIRTH_ENABLED) return false;
  return accountAwakenedSoulCount() >= 1;
}

function payAccountAwakeningSouls(quantity) {
  const cost = Math.max(1, Math.trunc(Number(quantity) || 1));
  if (accountAwakenedSoulCount() < cost) return false;
  let remaining = cost;
  captureActiveCharacterState();
  for (const classId of CHARACTER_IDS) {
    remaining = deductItemQuantityFromInventoryState(state.characters[classId]?.inventory, AWAKENING_SOUL_ITEM_ID, remaining);
    if (remaining <= 0) break;
  }
  if (remaining > 0) remaining = deductItemQuantityFromStorage(AWAKENING_SOUL_ITEM_ID, remaining);
  applyCharacterState(state.activeCharacterId, state.characters[state.activeCharacterId]);
  return remaining <= 0;
}

function ensureAccountAchievements() {
  state.account.achievements = sanitizeAccountAchievementState(state.account?.achievements);
  return state.account.achievements;
}

function achievementsEnabled() {
  return ACHIEVEMENTS_TEST_ACCESS || ensureAccountAchievements().enabled === true;
}

function achievementsPurchased() {
  return ensureAccountAchievements().enabled === true;
}

function achievementUnlocked(achievementId) {
  return Boolean(ensureAccountAchievements().unlocked?.[achievementId]);
}

function unlockAchievementsFeature() {
  const achievements = ensureAccountAchievements();
  if (achievements.enabled) return false;
  if (!payAccountAwakeningSouls(ACHIEVEMENT_UNLOCK_SOUL_COST)) {
    pushBattleLog(`Need ${ACHIEVEMENT_UNLOCK_SOUL_COST} Awakening Souls to unlock Achievements.`);
    battlePanelSignature = "";
    renderBattlePanel();
    return false;
  }
  achievements.enabled = true;
  pushBattleLog("Achievements unlocked.");
  addLootNotice("Achievements Unlocked", "level");
  playSfx("ui.gold", { volume: 0.55, throttleMs: 80 });
  sceneSignature = "";
  gamePanelSignature = "";
  battlePanelSignature = "";
  syncAchievementsNavigation();
  syncCashShopNavigation();
  renderSceneOverlay();
  renderGamePanel();
  renderBattlePanel();
  saveGameState(true);
  checkAchievementsForCurrentCharacter();
  return true;
}

function unlockAchievement(def, options = {}) {
  if (!def || achievementUnlocked(def.id)) return false;
  const characterId = normalizeCharacterId(options.characterId ?? state.activeCharacterId);
  const achievements = ensureAccountAchievements();
  achievements.unlocked[def.id] = {
    id: def.id,
    unlockedAt: Date.now(),
    characterId,
    rewardClaimed: false,
  };
  addLootNotice(`Achievement Unlocked: ${def.label}`, "level");
  pushBattleLog(`Achievement Unlocked: ${def.label}. Claim its reward from Achievements.`);
  playSfx("level.up", { volume: 0.65, throttleMs: 500 });
  sceneSignature = "";
  gamePanelSignature = "";
  battlePanelSignature = "";
  playerHudSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  renderBattlePanel();
  renderPlayerResourceHud();
  saveGameState(true);
  return true;
}

function achievementRewardLabel(def) {
  const gold = Math.max(0, Math.trunc(Number(def?.reward?.gold) || 0));
  if (gold > 0) return `${gold.toLocaleString()} gold`;
  const xpBonus = Math.max(0, Number(def?.reward?.xpBonusPercent) || 0);
  if (xpBonus > 0) return `Permanent +${xpBonus}% XP`;
  const quantity = Math.max(0, Math.trunc(Number(def?.reward?.quantity) || 0));
  const item = itemDefinition(def?.reward?.itemId);
  if (item && quantity > 0) return `${quantity} ${item.name}${quantity === 1 ? "" : "s"}`;
  return "No reward";
}

function inventoryStateCapacityForItem(inventory, item) {
  if (!inventory || !item) return 0;
  syncInventoryCapacity(inventory);
  const maxStack = maxItemStack(item);
  const partialSpace = isStackableItem(item)
    ? (inventory.items ?? [])
      .filter((entry) => entry.itemId === item.id)
      .reduce((sum, entry) => sum + Math.max(0, maxStack - Math.max(1, Math.trunc(Number(entry.quantity) || 1))), 0)
    : 0;
  const usedSlots = new Set((inventory.items ?? [])
    .map((entry) => entry.slot)
    .filter((slot) => Number.isInteger(slot) && slot >= 0 && slot < inventory.maxSlots)).size;
  const freeSlots = Math.max(0, inventory.maxSlots - usedSlots);
  return partialSpace + freeSlots * (isStackableItem(item) ? maxStack : 1);
}

function addItemQuantityToInventoryState(inventory, itemId, quantity) {
  const item = itemDefinition(itemId);
  if (!inventory || !item) return 0;
  let remaining = Math.max(0, Math.trunc(Number(quantity) || 0));
  let added = 0;
  const maxStack = maxItemStack(item);
  while (remaining > 0) {
    if (isStackableItem(item)) {
      const existing = (inventory.items ?? []).find((entry) => entry.itemId === itemId && entry.quantity < maxStack);
      if (existing) {
        const amount = Math.min(remaining, maxStack - existing.quantity);
        existing.quantity += amount;
        remaining -= amount;
        added += amount;
        continue;
      }
    }
    const slot = nextFreeSlotInInventoryState(inventory);
    if (!Number.isInteger(slot)) break;
    const amount = isStackableItem(item) ? Math.min(remaining, maxStack) : 1;
    inventory.items.push({
      id: `item-${inventory.nextInstanceId}`,
      itemId,
      quantity: amount,
      slot,
      ...normalizeInventoryEntryFields({}, item),
    });
    inventory.nextInstanceId += 1;
    remaining -= amount;
    added += amount;
  }
  return added;
}

function claimAchievementReward(achievementId) {
  const def = ACHIEVEMENT_DEFS.find((entry) => entry.id === achievementId);
  const achievements = ensureAccountAchievements();
  const record = achievements.unlocked?.[achievementId];
  if (!def || !record || record.rewardClaimed === true) return false;

  const characterId = normalizeCharacterId(record.characterId);
  const gold = Math.max(0, Math.trunc(Number(def.reward?.gold) || 0));
  const itemId = String(def.reward?.itemId ?? "");
  const itemQuantity = Math.max(0, Math.trunc(Number(def.reward?.quantity) || 0));
  captureActiveCharacterState();
  const character = state.characters[characterId];
  if (!character) return false;
  const targetInventory = characterId === state.activeCharacterId ? state.inventory : character.inventory;

  if (itemId && itemQuantity > 0) {
    const item = itemDefinition(itemId);
    if (!item || inventoryStateCapacityForItem(targetInventory, item) < itemQuantity) {
      pushBattleLog(`Need inventory space on ${characterId} to claim ${def.label}.`);
      addLootNotice(`${characterId} inventory full`, "full");
      battlePanelSignature = "";
      renderBattlePanel();
      return false;
    }
    if (addItemQuantityToInventoryState(targetInventory, itemId, itemQuantity) !== itemQuantity) return false;
  }

  if (gold > 0) {
    targetInventory.gold = Math.max(0, Math.trunc(Number(targetInventory.gold) || 0)) + gold;
    character.inventory.gold = targetInventory.gold;
    character.game.progress.gold = targetInventory.gold;
    if (characterId === state.activeCharacterId) {
      state.inventory.gold = targetInventory.gold;
      state.game.progress.gold = targetInventory.gold;
      state.battle.gold = targetInventory.gold;
    }
  }
  record.rewardClaimed = true;
  addLootNotice(`Achievement Reward: ${def.label}`, "level");
  if (gold > 0) addLootNotice(`+${gold.toLocaleString()} gold for ${characterId}`, "gold");
  if (itemId && itemQuantity > 0) addLootNotice(`+${achievementRewardLabel(def)} for ${characterId}`, "item");
  if (Number(def.reward?.xpBonusPercent) > 0) addLootNotice(achievementRewardLabel(def), "level");
  pushBattleLog(`Claimed ${def.label}: ${achievementRewardLabel(def)} for ${characterId}.`);
  playSfx("ui.gold", { volume: 0.6, throttleMs: 120 });
  sceneSignature = "";
  gamePanelSignature = "";
  battlePanelSignature = "";
  playerHudSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  renderBattlePanel();
  renderPlayerResourceHud();
  saveGameState(true);
  return true;
}

function checkAchievementsForCurrentCharacter() {
  if (!achievementsEnabled()) return;
  checkLevelAchievements(state.game.progress.level, state.activeCharacterId);
  for (const def of ACHIEVEMENT_DEFS) {
    if (achievementUnlocked(def.id)) continue;
    if (def.trigger?.type === "bossKill" && !def.trigger.solo && bossKillCount(def.trigger.zoneId) > 0) unlockAchievement(def);
  }
}

function checkLevelAchievements(level, characterId = state.activeCharacterId) {
  if (!achievementsEnabled()) return false;
  const reachedLevel = Math.max(1, Math.trunc(Number(level) || 1));
  let unlocked = false;
  for (const def of ACHIEVEMENT_DEFS) {
    if (achievementUnlocked(def.id) || def.trigger?.type !== "level") continue;
    const targetLevel = Math.max(1, Math.trunc(Number(def.trigger.level) || 1));
    if (reachedLevel < targetLevel) continue;
    unlocked = unlockAchievement(def, { characterId }) || unlocked;
  }
  return unlocked;
}

function checkBossKillAchievements(zoneId, participantClassIds = []) {
  if (!achievementsEnabled()) return false;
  const participants = [...new Set(
    participantClassIds
      .map((classId) => normalizeCharacterId(classId))
      .filter(Boolean),
  )];
  if (!participants.length) return false;
  let unlocked = false;
  for (const def of ACHIEVEMENT_DEFS) {
    if (achievementUnlocked(def.id)) continue;
    if (def.trigger?.type !== "bossKill" || def.trigger.zoneId !== zoneId) continue;
    if (def.trigger.solo && participants.length !== 1) continue;
    const characterId = def.trigger.solo ? participants[0] : state.activeCharacterId;
    unlocked = unlockAchievement(def, { characterId }) || unlocked;
  }
  return unlocked;
}

function deductItemQuantityFromInventoryState(inventory, itemId, quantity) {
  let remaining = Math.max(0, Math.trunc(Number(quantity) || 0));
  if (!inventory || remaining <= 0) return remaining;
  const entries = [...(inventory.items ?? [])].filter((entry) => entry.itemId === itemId);
  for (const entry of entries) {
    if (remaining <= 0) break;
    const stack = Math.max(1, Math.trunc(Number(entry.quantity) || 1));
    const taken = Math.min(remaining, stack);
    entry.quantity = stack - taken;
    remaining -= taken;
    if (entry.quantity <= 0) {
      inventory.items = inventory.items.filter((candidate) => candidate.id !== entry.id);
    }
  }
  return remaining;
}

function deductItemQuantityFromStorage(itemId, quantity) {
  let remaining = Math.max(0, Math.trunc(Number(quantity) || 0));
  if (remaining <= 0) return remaining;
  const entries = [...storageEntries()].filter((entry) => entry.itemId === itemId);
  for (const entry of entries) {
    if (remaining <= 0) break;
    const stack = Math.max(1, Math.trunc(Number(entry.quantity) || 1));
    const taken = Math.min(remaining, stack);
    entry.quantity = stack - taken;
    remaining -= taken;
    if (entry.quantity <= 0) {
      state.account.storage.items = state.account.storage.items.filter((candidate) => candidate.id !== entry.id);
    }
  }
  return remaining;
}

function createStorageEntry(itemId, quantity) {
  ensureStorageSlots();
  const slot = nextFreeStorageSlot();
  const maxSlots = state.account.storage.maxSlots;
  return {
    id: allocateStorageEntryId(),
    itemId,
    quantity,
    slot: Number.isInteger(slot) && slot < maxSlots ? slot : null,
  };
}

function addItemQuantityToStorage(itemId, quantity = 1) {
  ensureStorageSlots();
  const item = itemDefinition(itemId);
  if (!item) return 0;
  let remaining = Math.max(1, Math.floor(Number(quantity) || 1));
  const maxStack = maxItemStack(item);
  let added = 0;

  while (remaining > 0) {
    if (isStackableItem(item)) {
      const existing = storageEntries().find((entry) => entry.itemId === itemId && entry.quantity < maxStack);
      if (existing) {
        const add = Math.min(remaining, maxStack - existing.quantity);
        existing.quantity += add;
        remaining -= add;
        added += add;
        continue;
      }
      if (nextFreeStorageSlot() >= state.account.storage.maxSlots) break;
      const entry = createStorageEntry(itemId, Math.min(remaining, maxStack));
      state.account.storage.items.push(entry);
      added += entry.quantity;
      remaining -= entry.quantity;
      continue;
    }

    if (nextFreeStorageSlot() >= state.account.storage.maxSlots) break;
    const entry = createStorageEntry(itemId, 1);
    state.account.storage.items.push(entry);
    added += 1;
    remaining -= 1;
  }

  ensureStorageSlots();
  return added;
}

function accountRebirthPoints() {
  return Math.max(0, Math.trunc(Number(state.account.rebirthPoints) || 0));
}

function payRebirthPoints(quantity) {
  const cost = Math.max(1, Math.trunc(Number(quantity) || 1));
  if (accountRebirthPoints() < cost) return false;
  state.account.rebirthPoints = accountRebirthPoints() - cost;
  trackRebirthPointsSpent(cost);
  return true;
}

function resetCharacterProgressForRebirth(classId) {
  return createDefaultCharacterState(classId);
}

function awakeningSoulQuantityInStorage() {
  return storageEntries()
    .filter((entry) => entry.itemId === AWAKENING_SOUL_ITEM_ID)
    .reduce((total, entry) => total + Math.max(1, Math.trunc(Number(entry.quantity) || 1)), 0);
}

function resetAccountStorageForRebirth() {
  captureActiveCharacterState();
  state.account.storage = createDefaultStorageState();
}

function resetNonRebirthAccountUpgrades() {
  state.account.upgrades = sanitizeAccountUpgradeState(state.account.upgrades);
  const tiers = { ...(state.account.upgrades.tiers ?? {}) };
  for (const upgradeId of Object.keys(tiers)) {
    const upgrade = accountUpgradeById(upgradeId);
    if (!upgrade || accountUpgradeSection(upgrade) !== "rebirth") delete tiers[upgradeId];
  }
  state.account.upgrades = { tiers };
}

function performAccountRebirth() {
  if (!REBIRTH_ENABLED) {
    pushBattleLog("Rebirth is not available yet.");
    battlePanelSignature = "";
    renderBattlePanel();
    return false;
  }
  if (!canPerformRebirth()) {
    pushBattleLog("Need at least 1 Awakening Soul to rebirth.");
    battlePanelSignature = "";
    renderBattlePanel();
    return false;
  }
  captureActiveCharacterState();
  const soulsConverted = accountAwakenedSoulCount();
  const permanentCodex = cloneAccountCodexState(state.account.codex);
  const permanentAchievements = cloneAccountAchievementState(state.account.achievements);
  resetAccountStorageForRebirth();
  resetNonRebirthAccountUpgrades();
  state.account.codex = permanentCodex;
  state.account.achievements = permanentAchievements;
  ensureAccountStats();
  let pointsGained = 0;
  if (soulsConverted > 0) {
    pointsGained = Math.max(0, Math.trunc(soulsConverted * rebirthPointMultiplier()));
    state.account.rebirthPoints = accountRebirthPoints() + pointsGained;
    trackRebirthPointsGained(pointsGained);
  }
  state.account.stats.rebirthCount += 1;
  for (const classId of CHARACTER_IDS) {
    state.characters[classId] = resetCharacterProgressForRebirth(classId);
  }
  state.game.mode = "town";
  state.game.activeZoneId = null;
  state.showEnemies = false;
  state.continuousWalk = false;
  state.paused = false;
  state.bossEmpowerSelected = false;
  applyCharacterState(state.activeCharacterId, state.characters[state.activeCharacterId]);
  // Token-bought pages are permanent and must survive rebirth.
  applyOwnedUnlocks();
  normalizeAutoCastSpellsForClass(state.battle.combatClass);
  resetBattleForCurrentMode(false);
  pushBattleLog(`Rebirth complete. All characters reset to level 1 with starter gear.${pointsGained > 0 ? ` ${soulsConverted} Awakening Soul${soulsConverted === 1 ? "" : "s"} converted into ${pointsGained} Rebirth Point${pointsGained === 1 ? "" : "s"}.` : ""}`);
  playSfx("ui.gold", { volume: 0.55, throttleMs: 80 });
  state.pendingRebirthConfirm = false;
  sceneSignature = "";
  gamePanelSignature = "";
  battlePanelSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  renderBattlePanel();
  renderMapControls();
  render();
  saveGameState(true);
  return true;
}

function confirmPerformRebirth() {
  if (!canPerformRebirth()) {
    pushBattleLog("Need at least 1 Awakening Soul to rebirth.");
    battlePanelSignature = "";
    renderBattlePanel();
    return false;
  }
  state.pendingRebirthConfirm = true;
  sceneSignature = "";
  renderSceneOverlay();
  return true;
}

function cancelRebirthConfirm() {
  state.pendingRebirthConfirm = false;
  sceneSignature = "";
  renderSceneOverlay();
}

function confirmPendingRebirth() {
  if (!state.pendingRebirthConfirm || !canPerformRebirth()) {
    cancelRebirthConfirm();
    return false;
  }
  state.pendingRebirthConfirm = false;
  return performAccountRebirth();
}

function rebirthConfirmHtml() {
  if (!state.pendingRebirthConfirm) return "";
  if (!canPerformRebirth()) {
    state.pendingRebirthConfirm = false;
    return "";
  }
  const souls = accountAwakenedSoulCount();
  const pointsFromSouls = Math.max(0, Math.trunc(souls * rebirthPointMultiplier()));
  const heldPoints = accountRebirthPoints();
  const keptPointsLine = heldPoints > 0
    ? `<li>Your ${heldPoints} current Rebirth Point${heldPoints === 1 ? "" : "s"}</li>`
    : "";
  const soulConvertLine = souls > 0
    ? `<li>${souls} Awakening Soul${souls === 1 ? "" : "s"} converting into ${pointsFromSouls} Rebirth Point${pointsFromSouls === 1 ? "" : "s"}</li>`
    : "";
  return `
    <div class="rebirth-confirm inventory-destroy-confirm" role="dialog" aria-modal="true" aria-labelledby="rebirthConfirmTitle">
      <div class="rebirth-confirm-window inventory-destroy-confirm-window">
        <button type="button" class="inventory-destroy-close" data-cancel-rebirth-confirm aria-label="Cancel rebirth">X</button>
        <div class="inventory-destroy-title" id="rebirthConfirmTitle">Confirm Rebirth</div>
        <p class="rebirth-confirm-lead">Rebirth will reset almost all account progress. This cannot be undone.</p>
        <div class="rebirth-confirm-columns">
          <div class="rebirth-confirm-section">
            <strong>You will lose</strong>
            <ul>
              <li>Every character's level, skills, inventory, and equipment</li>
              <li>Account storage and all normal (non-rebirth) upgrades</li>
            </ul>
          </div>
          <div class="rebirth-confirm-section rebirth-confirm-section-keep">
            <strong>You will keep</strong>
            <ul>
              <li>Your permanent item Codex and achievements</li>
              <li>Rebirth upgrades already purchased</li>
              ${keptPointsLine}
              ${soulConvertLine}
            </ul>
          </div>
        </div>
        <div class="inventory-destroy-actions rebirth-confirm-actions">
          <button type="button" class="danger" data-confirm-rebirth>Rebirth</button>
          <button type="button" data-cancel-rebirth-confirm>Cancel</button>
        </div>
      </div>
    </div>
  `;
}

function sanitizeHotbarState(savedHotbar = {}, inventory = state.inventory) {
  return sanitizeHotbarStateCore(
    savedHotbar,
    (inventory.items ?? []).map((entry) => entry.id),
    Object.values(inventory.equipment ?? {}).filter(Boolean),
    HOTBAR_SLOT_COUNT,
  );
}

function sanitizeMagicState(savedMagic = {}) {
  return sanitizeMagicStateCore(savedMagic, (spellId) => Boolean(magicSpellById(spellId)));
}

function sanitizeCharacterBattleState(savedBattle = {}) {
  return sanitizeCharacterBattleStateCore(savedBattle);
}

function applyCharacterState(classId, character = createDefaultCharacterState(classId)) {
  const safeClassId = normalizeCharacterId(classId);
  state.activeCharacterId = safeClassId;
  state.battle.combatClass = safeClassId;
  state.game.mode = character.game.mode;
  state.game.activeZoneId = character.game.activeZoneId;
  state.game.kills = character.game.kills;
  state.game.zoneKills = character.game.zoneKills;
  state.game.distance = character.game.distance;
  state.game.playtimeMs = character.game.playtimeMs;
  sessionStartedAt = performance.now();
  state.game.lastReward = character.game.lastReward;
  state.game.recentLoot = [...character.game.recentLoot];
  state.game.lootToasts = [];
  state.game.dropPity = { ...character.game.dropPity };
  state.game.bossRespawns = { ...accountBossRespawns() };
  state.game.bossKills = { ...accountBossKills() };
  state.game.selectedTownNpcId = null;
  state.game.hoveredTownNpcId = null;
  state.game.miningNextRollAt = Math.max(0, Math.trunc(Number(character.game.miningNextRollAt) || 0));
  state.game.miningSpotId = miningSpotById(character.game.miningSpotId)?.id ?? null;
  state.game.groupDungeonRun = sanitizeGroupDungeonOfflineRun?.(character.game.groupDungeonRun, character.game.activeZoneId, safeClassId) ?? null;
  state.game.progress = { ...character.game.progress };
  state.inventory = cloneInventoryState(character.inventory);
  state.hotbar = cloneHotbarState(character.hotbar);
  state.magic = cloneMagicState(character.magic);
  removeRetiredTestingDefaultMagic(safeClassId, state.magic, {
    retiredSpellIds: RETIRED_TEST_DEFAULT_WIZARD_SPELLS,
  });
  normalizeAutoCastSpellsForClass(safeClassId);
  state.paused = character.battle?.paused === true;
  state.battle.statBuffs = sanitizeStatBuffs(character.battle?.statBuffs);
  state.battle.petStatBuffs = sanitizeStatBuffs(character.battle?.petStatBuffs);
  pendingSavedPlayerResources = {
    hp: finiteNumberOrNull(character.battle?.playerHp),
    mp: finiteNumberOrNull(character.battle?.playerMp),
    potHealthAmount: Math.max(0, Math.trunc(Number(character.battle?.potHealthAmount) || 0)),
    potManaAmount: Math.max(0, Math.trunc(Number(character.battle?.potManaAmount) || 0)),
    healAmount: Math.max(0, Math.trunc(Number(character.battle?.healAmount) || 0)),
    vampAmount: Math.max(0, Math.trunc(Number(character.battle?.vampAmount) || 0)),
  };
  syncInventoryCapacity();
  ensureInventorySlots();
  state.game.progress.gold = state.inventory.gold;
  applyEquippedVisualIndexes();
  syncTownPartyIdleMembers();
}

function captureActiveCharacterState() {
  const classId = normalizeCharacterId(state.activeCharacterId);
  state.characters[classId] = serializeCurrentCharacterState();
}

// Keep every saved character's zone/town state aligned (boss party assist chars each
// have their own character slot and reload via applyCharacterState on tab switch).
function persistCharacterGameLocation({ mode, zoneId = null, classIds = null, running = false } = {}) {
  const ids = (classIds ?? CHARACTER_IDS).map(normalizeCharacterId).filter((classId) => state.characters?.[classId]);
  for (const classId of ids) {
    const character = state.characters[classId];
    character.game.mode = mode;
    character.game.activeZoneId = zoneId;
    if (mode === "town") {
      character.game.zoneKills = 0;
      character.game.distance = 0;
      character.game.miningNextRollAt = 0;
      character.game.miningSpotId = null;
      state.game.groupDungeonRun = null;
      character.game.groupDungeonRun = null;
    } else if (mode === "mining") {
      character.game.miningSpotId = state.game.miningSpotId ?? null;
      state.game.groupDungeonRun = null;
      character.game.groupDungeonRun = null;
    } else if (mode === "zone" && groupDungeonZone?.(PROTOTYPE_ZONES.find((zone) => zone.id === zoneId))) {
      const entryZone = PROTOTYPE_ZONES.find((entry) => entry.id === zoneId);
      const groupRun = groupDungeonOfflineRunSnapshot?.() ?? {
        kind: "groupDungeon",
        zoneId,
        leaderClassId: state.activeCharacterId,
        classIds: ids,
        waveNumber: 1,
        killedThisWave: 0,
        targetThisWave: groupDungeonWaveSpawnCount(1, entryZone),
        endless: false,
      };
      state.game.groupDungeonRun = groupRun;
      character.game.groupDungeonRun = groupRun;
    } else {
      state.game.groupDungeonRun = null;
      character.game.groupDungeonRun = null;
    }
    character.battle = {
      ...character.battle,
      running: Boolean(running),
      paused: false,
    };
    if (mode === "town") {
      character.battle.statBuffs = [];
      character.battle.petStatBuffs = [];
    }
    state.characters[classId] = character;
  }
}

function bossPartyMemberClassIds(party = state.battle.bossParty) {
  if (!party?.members?.length) return [state.activeCharacterId];
  return party.members.map((member) => member.classId);
}

function bossPartyOnField(party = state.battle.bossParty) {
  return Boolean(party?.members?.length && (party.active || party.finished));
}

function freezeBossPartyMembersForAftermath(party, now = performance.now()) {
  if (!party?.members?.length) return;
  for (const member of party.members) {
    if (!member.alive || member.hp <= 0) continue;
    member.targetWorldX = null;
    member.meleeAdvanceFromX = null;
    member.meleeAdvanceStartedAt = null;
    member.visualAction = "stance";
    member.visualOneShot = false;
    member.visualFrame = 0;
    member.visualLastTick = now;
    member.nextActionAt = Number.POSITIVE_INFINITY;
    member.returnToStandAt = now + COMBAT_STANCE_HOLD_MS;
    if (member.classId === bossPartyControlledClassId()) setPlayerAction("stance", now);
  }
}

function updateBossPartyMemberRestState(member, now) {
  if (!member?.alive || member.hp <= 0 || !member.returnToStandAt) return;
  if (now < member.returnToStandAt) return;
  member.returnToStandAt = 0;
  member.visualAction = "standing";
  member.visualFrame = 0;
  member.visualOneShot = false;
  member.visualLastTick = now;
  if (member.classId === bossPartyControlledClassId()) setPlayerAction("standing", now);
}

function returnAllCharactersToTown() {
  if (bossPartyOnField()) {
    syncBossPartyControlledMemberFromState(bossPartyLeaderClassId());
    syncBossPartyMembersToCharacters(state.battle.bossParty, { applyControlled: true });
  } else {
    captureActiveCharacterState();
  }
  clearGroupDungeonRunState();
  state.battle.bossParty = null;
  state.game.mode = "town";
  state.game.activeZoneId = null;
  lastStageShellSize = { w: 0, h: 0, mode: "", scale: 0 };
  state.game.zoneKills = 0;
  state.game.distance = 0;
  state.game.miningNextRollAt = 0;
  state.game.miningSpotId = null;
  state.game.selectedTownNpcId = null;
  persistCharacterGameLocation({ mode: "town", zoneId: null, classIds: CHARACTER_IDS, running: false });
}

function serializeCurrentCharacterState() {
  return {
    classId: state.activeCharacterId,
    game: {
      mode: state.game.mode,
      activeZoneId: state.game.activeZoneId,
      kills: state.game.kills,
      zoneKills: state.game.zoneKills,
      distance: Math.floor(Number(state.game.distance) || 0),
      playtimeMs: Math.floor(totalPlaytimeMs()),
      lastReward: state.game.lastReward,
      recentLoot: state.game.recentLoot.slice(0, 6),
      dropPity: { ...state.game.dropPity },
      bossRespawns: { ...state.game.bossRespawns },
      bossKills: { ...state.game.bossKills },
      progress: {
        level: state.game.progress.level,
        experience: state.game.progress.experience,
        gold: state.inventory.gold,
      },
      starterGearVersion: STARTER_GEAR_VERSION,
      miningNextRollAt: Math.max(0, Math.trunc(Number(state.game.miningNextRollAt) || 0)),
      miningSpotId: state.game.miningSpotId ?? null,
      groupDungeonRun: state.game.groupDungeonRun ?? null,
    },
    inventory: cloneInventoryStateIncludingWeaponRefineStaged(state.inventory),
    hotbar: cloneHotbarState(state.hotbar),
    magic: magicStateForPersistence(state.magic),
    battle: {
      running: state.battle.running,
      paused: state.paused,
      playerHp: state.battle.player?.hp ?? pendingSavedPlayerResources?.hp ?? null,
      playerMp: state.battle.player?.mp ?? pendingSavedPlayerResources?.mp ?? null,
      potHealthAmount: state.battle.potHealthAmount ?? pendingSavedPlayerResources?.potHealthAmount ?? 0,
      potManaAmount: state.battle.potManaAmount ?? pendingSavedPlayerResources?.potManaAmount ?? 0,
      healAmount: state.battle.healAmount ?? pendingSavedPlayerResources?.healAmount ?? 0,
      vampAmount: state.battle.vampAmount ?? pendingSavedPlayerResources?.vampAmount ?? 0,
      statBuffs: pruneStatBuffs(state.battle.statBuffs ?? []),
      petStatBuffs: pruneStatBuffs(state.battle.petStatBuffs ?? []),
    },
  };
}

function serializeCharactersState() {
  return Object.fromEntries(CHARACTER_IDS.map((classId) => {
    const character = state.characters[classId] ?? createDefaultCharacterState(classId);
    return [classId, {
      classId,
      game: {
        ...character.game,
        progress: { ...character.game.progress },
        starterGearVersion: Math.max(STARTER_GEAR_VERSION, Math.trunc(Number(character.game.starterGearVersion) || 0)),
        dropPity: { ...character.game.dropPity },
        bossRespawns: { ...character.game.bossRespawns },
        bossKills: { ...character.game.bossKills },
        recentLoot: [...character.game.recentLoot],
      },
      inventory: cloneInventoryState(character.inventory),
      hotbar: cloneHotbarState(character.hotbar),
      magic: magicStateForPersistence(character.magic),
      battle: { ...character.battle },
    }];
  }));
}

function cloneInventoryState(inventory) {
  const cloned = {
    gold: Math.max(0, Math.trunc(Number(inventory?.gold) || 0)),
    pagesUnlocked: Math.max(1, Math.min(inventoryPageCount(), Math.trunc(Number(inventory?.pagesUnlocked) || 1))),
    goldPageUnlocked: inventoryGoldPageUnlocked(inventory),
    tokenPageUnlocked: Boolean(inventory?.tokenPageUnlocked),
    maxSlots: INVENTORY_BASE_SLOTS,
    nextInstanceId: Math.max(1, Math.trunc(Number(inventory?.nextInstanceId) || 1)),
    items: (inventory?.items ?? []).map((entry) => ({
      id: entry.id,
      itemId: entry.itemId,
      quantity: Math.max(1, Math.trunc(Number(entry.quantity) || 1)),
      slot: Number.isInteger(entry.slot) ? entry.slot : null,
      ...normalizeInventoryEntryFields(entry),
    })),
    equipment: Object.fromEntries(EQUIPMENT_SLOTS.map((slot) => [slot.id, inventory?.equipment?.[slot.id] ?? null])),
  };
  syncInventoryCapacity(cloned);
  return cloned;
}

function cloneInventoryStateIncludingWeaponRefineStaged(inventory) {
  const cloned = cloneInventoryState(inventory);
  for (const staged of Object.values(state.weaponRefine?.stagedEntries ?? {})) {
    if (!staged?.entry || cloned.items.some((entry) => entry.id === staged.entry.id)) continue;
    cloned.items.push({
      id: staged.entry.id,
      itemId: staged.entry.itemId,
      quantity: Math.max(1, Math.trunc(Number(staged.entry.quantity) || 1)),
      slot: Number.isInteger(staged.returnSlot) ? staged.returnSlot : (
        Number.isInteger(staged.entry.slot) ? staged.entry.slot : null
      ),
      ...normalizeInventoryEntryFields(staged.entry),
    });
  }
  for (const staged of Object.values(state.craftingCube?.stagedEntries ?? {})) {
    if (!staged?.entry || cloned.items.some((entry) => entry.id === staged.entry.id)) continue;
    cloned.items.push({
      id: staged.entry.id,
      itemId: staged.entry.itemId,
      quantity: Math.max(1, Math.trunc(Number(staged.entry.quantity) || 1)),
      slot: Number.isInteger(staged.returnSlot) ? staged.returnSlot : (
        Number.isInteger(staged.entry.slot) ? staged.entry.slot : null
      ),
      ...normalizeInventoryEntryFields(staged.entry),
    });
  }
  syncInventoryCapacity(cloned);
  return cloned;
}

function cloneStorageState(storage) {
  const cloned = {
    pagesUnlocked: Math.max(1, Math.min(storagePageCount(), Math.trunc(Number(storage?.pagesUnlocked) || 1))),
    page2Purchased: Boolean(storage?.page2Purchased),
    tokenPageUnlocked: Boolean(storage?.tokenPageUnlocked),
    maxSlots: STORAGE_BASE_SLOTS,
    nextInstanceId: Math.max(1, Math.trunc(Number(storage?.nextInstanceId) || 1)),
    items: (storage?.items ?? []).map((entry) => ({
      id: entry.id,
      itemId: entry.itemId,
      quantity: Math.max(1, Math.trunc(Number(entry.quantity) || 1)),
      slot: Number.isInteger(entry.slot) ? entry.slot : null,
      ...normalizeInventoryEntryFields(entry),
    })),
  };
  // Knock loose any item on a page the account does not own (derive usable
  // pages from the two independent unlock flags).
  const usablePages = Math.min(
    storagePageCount(),
    1 + (cloned.page2Purchased ? 1 : 0) + (cloned.tokenPageUnlocked ? 1 : 0),
  );
  const usableSlots = usablePages * STORAGE_PAGE_SIZE;
  for (const entry of cloned.items) {
    if (Number.isInteger(entry.slot) && entry.slot >= usableSlots) {
      entry.slot = null;
    }
  }
  syncStorageCapacity(cloned);
  ensureStorageSlots(cloned);
  return cloned;
}

function cloneAccountUpgradeState(upgrades) {
  return sanitizeAccountUpgradeState(upgrades);
}

function cloneHotbarState(hotbar) {
  return {
    slots: Array.from({ length: HOTBAR_SLOT_COUNT }, (_, slot) => hotbar?.slots?.[slot] ?? null),
  };
}

function cloneMagicState(magic) {
  return {
    learned: Object.fromEntries(
      Object.entries(magic?.learned ?? {}).map(([spellId, learned]) => [
        spellId,
        {
          spellId: learned.spellId ?? spellId,
          level: Math.max(0, Math.min(3, Math.trunc(Number(learned.level) || 0))),
          experience: Math.max(0, Math.trunc(Number(learned.experience) || 0)),
          key: learned.key ?? null,
          autoCast: Boolean(learned.autoCast),
          castReadyAt: Math.max(0, Number(learned.castReadyAt) || 0),
          learnedAt: Number(learned.learnedAt) || 0,
        },
      ]),
    ),
  };
}

function magicStateForPersistence(magic) {
  const cloned = cloneMagicState(magic);
  for (const learned of Object.values(cloned.learned ?? {})) {
    learned.castReadyAt = 0;
  }
  return cloned;
}

function restoreSettingsState(snapshot) {
  Object.assign(state.settings, sanitizeSettingsState(snapshot.settings ?? {}));
  const savedTrackIndex = BACKGROUND_MUSIC_TRACKS.findIndex((track) => track.id === snapshot.settings?.musicTrackId);
  musicTrackIndex = savedTrackIndex >= 0 ? savedTrackIndex : 0;
}

function restorePendingSavedPlayerResources() {
  if (!pendingSavedPlayerResources || !state.battle.player) return;
  if (pendingSavedPlayerResources.hp != null) {
    state.battle.player.hp = Math.max(0, Math.min(state.battle.player.maxHp, Math.trunc(pendingSavedPlayerResources.hp)));
  }
  if (pendingSavedPlayerResources.mp != null) {
    state.battle.player.mp = Math.max(0, Math.min(state.battle.player.maxMp, Math.trunc(pendingSavedPlayerResources.mp)));
  }
  state.battle.potHealthAmount = Math.max(0, Math.trunc(Number(pendingSavedPlayerResources.potHealthAmount) || 0));
  state.battle.potManaAmount = Math.max(0, Math.trunc(Number(pendingSavedPlayerResources.potManaAmount) || 0));
  state.battle.potTickAt = state.battle.potHealthAmount > 0 || state.battle.potManaAmount > 0
    ? performance.now() + CRYSTAL_POT_DELAY_MS
    : 0;
  state.battle.healAmount = Math.max(0, Math.trunc(Number(pendingSavedPlayerResources.healAmount) || 0));
  state.battle.healTickAt = state.battle.healAmount > 0
    ? performance.now() + CRYSTAL_HEAL_DELAY_MS
    : 0;
  state.battle.vampAmount = Math.max(0, Math.trunc(Number(pendingSavedPlayerResources.vampAmount) || 0));
  state.battle.vampTickAt = state.battle.vampAmount > 0
    ? performance.now() + CRYSTAL_VAMP_DELAY_MS
    : 0;
  pendingSavedPlayerResources = null;
}

function createPendingOfflineProgress(snapshot) {
  return resolvePendingOfflineProgress(snapshot, Date.now(), {
    zoneIds: PROTOTYPE_ZONES.map((zone) => zone.id),
    miningZoneId: MINING_ZONE_ID,
    minMs: OFFLINE_PROGRESS_MIN_MS,
    capMs: OFFLINE_PROGRESS_CAP_MS,
    sanitizeGroupDungeonRun: (run, activeZoneId, classId) =>
      sanitizeGroupDungeonOfflineRun?.(run, activeZoneId, classId) ?? null,
  });
}

function applyPendingOfflineProgress() {
  const pending = pendingOfflineProgress;
  pendingOfflineProgress = null;
  if (!pending) return;
  if (pending.kind === "mining") applyOfflineMiningProgress(pending);
  else applyOfflineProgress(pending);
}

function applyOfflineProgress(pending) {
  const zone = activeZone();
  if (!pending || !zone || state.game.mode !== "zone" || !state.battle.running || !state.battle.player) return;
  if (state.paused) return;
  if (state.battle.player.hp <= 0) return;

  const groupDungeonMode = Boolean(pending.groupDungeonRun && groupDungeonZone(zone));
  if (groupDungeonMode) {
    // Offline simulation is not supported in group dungeons. The live save already
    // preserved the party's progress on the way out, so skip the (non-functional)
    // simulation and just tell the player instead of presenting an empty report.
    presentGroupDungeonOfflineNotice(pending);
    refreshOfflineProgressUi();
    return;
  }

  const bossPartyMode = bossPartyOfflineSimulationActive(zone);
  let report;
  suppressSimulationRender = true;
  try {
    report = bossPartyMode
      ? simulateBossPartyCatchUp(pending.elapsedMs, performance.now())
      : simulateOfflineProgress(zone, pending);
  } finally {
    suppressSimulationRender = false;
  }

  if (!report || report.elapsedMs < OFFLINE_PROGRESS_MIN_MS) return;
  rebaseOfflineTransientTimers(report.simulatedEndedAt, performance.now());
  if (bossPartyMode) finalizeOfflineBossPartyState(report);
  else finalizeOfflineBattleState(zone, report);
  presentOfflineReport(report);
  refreshOfflineProgressUi();
}

function applyOfflineMiningProgress(pending) {
  if (!pending || state.game.mode !== "mining" || state.paused) return;

  let report;
  suppressSimulationRender = true;
  try {
    report = simulateOfflineMining(pending);
  } finally {
    suppressSimulationRender = false;
  }

  if (!report || report.elapsedMs < OFFLINE_PROGRESS_MIN_MS) return;
  finalizeOfflineMiningState(report);
  presentOfflineMiningReport(report);
  refreshOfflineProgressUi();
}

function refreshOfflineProgressUi() {
  gamePanelSignature = "";
  battlePanelSignature = "";
  sceneSignature = "";
  playerHudSignature = "";
  hotbarSignature = "";
  saveGameState(true);
}

function simulateOfflineMining(pending) {
  const limitMs = Math.max(0, Math.trunc(Number(pending.elapsedMs) || 0));
  return simulateOfflineMiningSwings(limitMs, {
    swingCycleMs: effectiveMiningSwingCycleMs(),
    hitChance: MINING_HIT_CHANCE,
    capped: pending.capped,
    rollOre: () => ({
      itemId: rollMiningOreItemId(),
      purity: rollMiningOrePurity(),
    }),
    formatOreLabel: (ore) => offlineMiningOreLabel(ore.itemId, ore.purity),
    tryAddOre: (ore) => {
      syncInventoryCapacity();
      ensureInventorySlots();
      recordCodexDrop(ore.itemId, codexDropSource({ kind: "mining" }));
      if (inventoryUsedSlots() >= state.inventory.maxSlots) return false;
      state.inventory.items.push(createOreInventoryEntry(ore.itemId, ore.purity));
      syncBossPartyControlledInventoryFromState();
      return true;
    },
  });
}

function offlineMiningOreLabel(itemId, purity) {
  const item = itemDefinition(itemId);
  if (!item) return itemId;
  const purityLabel = purity > 0 ? ` P${purity}` : "";
  return `${item.name}${purityLabel}`;
}

function finalizeOfflineMiningState(report) {
  const now = performance.now();
  ensureMiningSpotId(false);
  state.showEnemies = true;
  state.battle.running = false;
  state.battle.returnToStandAt = 0;
  state.battle.enemy = null;
  state.battle.phase = "idle";
  state.battle.cameraX = state.battle.playerX - playerScreenX();
  setPlayerAction("mine", now, true);
  const spot = activeMiningSpot();
  if (spot?.label) {
    pushBattleLog(`Resumed mining at ${spot.label}.`);
  }
}

function presentOfflineMiningReport(report) {
  const duration = formatDuration(report.elapsedMs);
  const dropsText = reportCountText(report.drops, 5);
  const ignoredText = reportCountText(report.ignoredDrops, 3);
  const lines = [
    `Offline mining ${duration}: ${report.swings} swings, ${report.hits} ore finds`,
  ];
  if (dropsText) lines.push(`Found ${dropsText}`);
  if (ignoredText) lines.push(`No room for ${ignoredText}`);
  if (report.capped) lines.push("Offline cap reached: 8h");

  state.game.offlineReport = {
    kind: "mining",
    duration,
    swings: report.swings,
    hits: report.hits,
    drops: [...report.drops.entries()],
    ignoredDrops: [...report.ignoredDrops.entries()],
    capped: report.capped,
  };
  state.game.recentLoot = [...lines, ...state.game.recentLoot].slice(0, 6);
  for (const line of [...lines].reverse()) pushBattleLog(line);
  addLootNotice(`Offline: ${report.hits} ore`, "item");
  renderOfflineReport();
}

function simulateOfflineTrainingRoomProgress(zone, report, startedAt, limitMs) {
  const template = trainingRoomEnemyTemplate(zone);
  const enemy = {
    ...template,
    hp: template.maxHp,
    mp: template.maxMp,
    poisons: [],
    debuffs: { slowUntil: 0, frozenUntil: 0 },
  };
  state.battle.enemy = enemy;
  state.battle.enemyId = enemy.id;
  state.battle.phase = "engaged";
  state.battle.enemyAggro = true;
  state.battle.playerX = 0;
  state.battle.enemyX = playerAttackRange();
  dismissBattleCompanions();

  let elapsedMs = 0;
  let nextCastAt = Math.max(0, (state.battle.trainingRoomNextCastAt ?? 0) - startedAt);
  offlineUpdateRecovery(startedAt, report);

  while (elapsedMs < limitMs && (state.battle.player?.hp ?? 0) > 0) {
    if (elapsedMs < nextCastAt) {
      const jump = Math.min(nextCastAt - elapsedMs, limitMs - elapsedMs);
      elapsedMs += jump;
      offlineUpdateRecovery(startedAt + elapsedMs, report);
      if (elapsedMs >= limitMs) break;
    }

    const now = startedAt + elapsedMs;
    const cast = tryTrainingRoomAutocastCycle(now);
    if (cast) {
      const gap = trainingRoomCastGapMs(cast.spell, cast.learned);
      nextCastAt = elapsedMs + gap;
      state.battle.trainingRoomNextCastAt = startedAt + nextCastAt;
      state.battle.nextPlayerAttackAt = state.battle.trainingRoomNextCastAt;
      state.battle.lastPlayerAttackCooldownMs = gap;
    } else {
      nextCastAt = elapsedMs + CRYSTAL_SPELL_GLOBAL_LOCK_MS;
      state.battle.trainingRoomNextCastAt = startedAt + nextCastAt;
    }
    offlineUpdateRecovery(now, report);
  }

  report.elapsedMs = Math.min(elapsedMs, limitMs);
  report.simulatedEndedAt = startedAt + report.elapsedMs;
  report.finalEnemy = enemy;
  state.battle.level = state.game.progress.level;
  state.battle.experience = state.game.progress.experience;
  state.battle.gold = state.inventory.gold;
  clearTransientCombatBuffs();
  return report;
}

function simulateOfflineProgress(zone, pending) {
  const report = createOfflineZoneReport(pending);
  const startedAt = performance.now();
  report.simulatedStartedAt = startedAt;
  const limitMs = Math.max(0, Math.trunc(Number(pending.elapsedMs) || 0));

  if (isTrainingRoomZone(zone)) {
    return simulateOfflineTrainingRoomProgress(zone, report, startedAt, limitMs);
  }

  state.battle.phase = "engaged";
  state.battle.enemyAggro = true;
  state.battle.playerX = 0;
  state.battle.enemyX = playerAttackRange();

  while (report.elapsedMs < limitMs && (state.battle.player?.hp ?? 0) > 0) {
    const template = randomZoneEnemyTemplate(zone);
    const result = simulateOfflineFight(template, startedAt + report.elapsedMs, limitMs - report.elapsedMs, report);
    const step = processOfflineZoneFightCycle(report, result, limitMs, LANE.respawnDelayMs);
    if (step.status === "player_died" || step.status === "fight_incomplete") break;

    dismissTaoistPet();
    awardOfflineEnemyRewards(zone, template, report);
    state.game.distance += enemySpawnDistance();
    offlineUpdateRecovery(startedAt + report.elapsedMs, report);
  }

  finalizeOfflineZoneReport(report, limitMs, startedAt);
  state.battle.level = state.game.progress.level;
  state.battle.experience = state.game.progress.experience;
  state.battle.gold = state.inventory.gold;
  return report;
}

function rebaseOfflineTransientTimers(simulatedNow, actualNow = performance.now()) {
  if (!Number.isFinite(simulatedNow) || simulatedNow <= 0) return;

  for (const [spellId, learned] of Object.entries(state.magic.learned ?? {})) {
    const spell = magicSpellById(spellId);
    if (!spell || !learned) continue;
    learned.castReadyAt = rebaseTransientTimestamp(
      learned.castReadyAt,
      simulatedNow,
      actualNow,
      wizardCastCooldownMs(spell, learned),
    );
  }

  state.battle.wizardSpellLockUntil = rebaseTransientTimestamp(
    state.battle.wizardSpellLockUntil,
    simulatedNow,
    actualNow,
    CRYSTAL_SPELL_GLOBAL_LOCK_MS,
  );

  state.battle.trainingRoomNextCastAt = rebaseTransientTimestamp(
    state.battle.trainingRoomNextCastAt,
    simulatedNow,
    actualNow,
    CRYSTAL_SPELL_GLOBAL_LOCK_MS,
  );

  state.battle.furyUntil = rebaseTransientTimestamp(state.battle.furyUntil, simulatedNow, actualNow, 120000);
  state.battle.potTickAt = rebaseTransientTimestamp(state.battle.potTickAt, simulatedNow, actualNow, CRYSTAL_POT_DELAY_MS);
  state.battle.healTickAt = rebaseTransientTimestamp(state.battle.healTickAt, simulatedNow, actualNow, CRYSTAL_HEAL_DELAY_MS);
  state.battle.vampTickAt = rebaseTransientTimestamp(state.battle.vampTickAt, simulatedNow, actualNow, CRYSTAL_VAMP_DELAY_MS);
  if (state.battle.pendingHeal) {
    state.battle.pendingHeal.at = rebaseTransientTimestamp(
      state.battle.pendingHeal.at,
      simulatedNow,
      actualNow,
      CRYSTAL_HEAL_APPLY_DELAY_MS,
    );
  }
  if (state.battle.pendingPoison) {
    state.battle.pendingPoison.at = rebaseTransientTimestamp(
      state.battle.pendingPoison.at,
      simulatedNow,
      actualNow,
      CRYSTAL_POISON_APPLY_DELAY_MS,
    );
  }
  if (state.battle.pendingEnemyStrike) {
    const strikeSpan = Math.max(
      EVIL_CENTIPEDE_ATTACK_IMPACT_MS,
      Number(state.battle.pendingEnemyStrike.moveDurationMs) || BONE_LORD_ATTACK_IMPACT_MS,
    );
    state.battle.pendingEnemyStrike.at = rebaseTransientTimestamp(
      state.battle.pendingEnemyStrike.at,
      simulatedNow,
      actualNow,
      strikeSpan,
    );
    if (state.battle.pendingEnemyStrike.startedAt != null) {
      state.battle.pendingEnemyStrike.startedAt = rebaseTransientTimestamp(
        state.battle.pendingEnemyStrike.startedAt,
        simulatedNow,
        actualNow,
        strikeSpan,
      );
    }
  }
  if (state.battle.pendingTaoPet) {
    state.battle.pendingTaoPet.at = rebaseTransientTimestamp(
      state.battle.pendingTaoPet.at,
      simulatedNow,
      actualNow,
      taoistSummonPetDelayMs(state.battle.pendingTaoPet.spellId),
    );
  }
  if (state.battle.pendingWizardMirror) {
    state.battle.pendingWizardMirror.at = rebaseTransientTimestamp(
      state.battle.pendingWizardMirror.at,
      simulatedNow,
      actualNow,
      CRYSTAL_MIRRORING_SUMMON_DELAY_MS,
    );
  }
  if (state.battle.wizardMirror?.active) {
    state.battle.wizardMirror.expiresAt = rebaseTransientTimestamp(
      state.battle.wizardMirror.expiresAt,
      simulatedNow,
      actualNow,
      wizardMirrorDurationMs(state.battle.wizardMirror.spellLevel),
    );
    state.battle.wizardMirror.nextActionAt = rebaseTransientTimestamp(
      state.battle.wizardMirror.nextActionAt,
      simulatedNow,
      actualNow,
      5000,
    );
    state.battle.wizardMirror.nextUpkeepAt = rebaseTransientTimestamp(
      state.battle.wizardMirror.nextUpkeepAt,
      simulatedNow,
      actualNow,
      WIZARD_MIRROR_UPKEEP_INTERVAL_MS,
    );
  }
  if (state.battle.pendingPetAttack) {
    state.battle.pendingPetAttack.at = rebaseTransientTimestamp(
      state.battle.pendingPetAttack.at,
      simulatedNow,
      actualNow,
      taoistPetAttackImpactMs(state.battle.taoPet ?? state.battle.bossParty?.pet),
    );
  }
  if (state.battle.pendingDefenceBuff) {
    state.battle.pendingDefenceBuff.at = rebaseTransientTimestamp(
      state.battle.pendingDefenceBuff.at,
      simulatedNow,
      actualNow,
      CRYSTAL_HEAL_APPLY_DELAY_MS,
    );
  }
  if (state.battle.pendingWizardBuff) {
    state.battle.pendingWizardBuff.at = rebaseTransientTimestamp(
      state.battle.pendingWizardBuff.at,
      simulatedNow,
      actualNow,
      500,
    );
  }
  if (state.battle.pendingMassHeal) {
    state.battle.pendingMassHeal.at = rebaseTransientTimestamp(
      state.battle.pendingMassHeal.at,
      simulatedNow,
      actualNow,
      CRYSTAL_HEAL_APPLY_DELAY_MS,
    );
  }
  if (state.battle.pendingPetEnhancer) {
    state.battle.pendingPetEnhancer.at = rebaseTransientTimestamp(
      state.battle.pendingPetEnhancer.at,
      simulatedNow,
      actualNow,
      CRYSTAL_HEAL_APPLY_DELAY_MS,
    );
  }
  if (state.battle.pendingUltimateEnhancer) {
    state.battle.pendingUltimateEnhancer.at = rebaseTransientTimestamp(
      state.battle.pendingUltimateEnhancer.at,
      simulatedNow,
      actualNow,
      CRYSTAL_HEAL_APPLY_DELAY_MS,
    );
  }
  if (state.battle.taoPet?.active) {
    state.battle.taoPet.nextAttackAt = rebaseTransientTimestamp(
      state.battle.taoPet.nextAttackAt,
      simulatedNow,
      actualNow,
      state.battle.taoPet.attackMs,
    );
    state.battle.taoPet.healTickAt = rebaseTransientTimestamp(
      state.battle.taoPet.healTickAt,
      simulatedNow,
      actualNow,
      CRYSTAL_HEAL_DELAY_MS,
    );
  }
  state.battle.autoPotionReadyAt = {
    hp: rebaseTransientTimestamp(state.battle.autoPotionReadyAt?.hp, simulatedNow, actualNow, AUTO_POTION_COOLDOWN_MS),
    mp: rebaseTransientTimestamp(state.battle.autoPotionReadyAt?.mp, simulatedNow, actualNow, AUTO_POTION_COOLDOWN_MS),
  };
  state.battle.statBuffs = (state.battle.statBuffs ?? []).map((buff) => ({
    ...buff,
    expiresAt: rebaseTransientTimestamp(
      buff.expiresAt,
      simulatedNow,
      actualNow,
      maxStatBuffRemainingMs(buff),
    ),
  })).filter((buff) => buff.expiresAt > actualNow);
  state.battle.petStatBuffs = (state.battle.petStatBuffs ?? []).map((buff) => ({
    ...buff,
    expiresAt: rebaseTransientTimestamp(
      buff.expiresAt,
      simulatedNow,
      actualNow,
      maxStatBuffRemainingMs(buff),
    ),
  })).filter((buff) => buff.expiresAt > actualNow);
}

function maxStatBuffRemainingMs(buff) {
  if (buff?.kind === "magicShield" || buff?.stat === "damageReduction") return 30 * 60 * 1000;
  if (buff?.stat === "ac" || buff?.stat === "amc") return 30 * 60 * 1000;
  if (buff?.kind === "ultimateEnhancer") return 30 * 60 * 1000;
  return BUFF_POTION_DURATION_MS;
}

function simulateOfflineFight(template, startedAt, remainingMs, report) {
  const enemy = createOfflineFightEnemy(template);
  return simulateOfflineFightLoop({
    remainingMs,
    startedAt,
    travelMs: offlineTravelTimeMs(),
    enemy,
    initialNextEnemyAttackMs: enemy.attackMs,
    getPlayerHp: () => state.battle.player?.hp ?? 0,
    getPetAttackDelayMs: (simNow) => offlinePetAttackDelayMs(
      state.battle.taoPet?.active ? state.battle.taoPet : null,
      simNow,
    ),
    isEnemyFrozen: (target, now) => enemyFrozenActive(target, now),
    onTravelComplete: (simNow) => {
      state.battle.enemy = enemy;
      state.battle.enemyId = enemy.id;
      state.battle.phase = "engaged";
      state.battle.enemyAggro = true;
      state.battle.playerX = 0;
      state.battle.enemyX = playerAttackRange();
      dismissTaoistPet();
      offlineUpdateRecovery(simNow, report);
    },
    onRecovery: (now) => offlineUpdateRecovery(now, report),
    onPlayerAttack: (target, now) => offlinePlayerAttack(target, now),
    onPetAttack: (now) => {
      if (state.battle.taoPet?.active && (state.battle.taoPet.nextAttackAt ?? 0) <= now) {
        updateTaoistPetAttack(now, { offline: true });
      }
    },
    onEnemyAttack: (target, now) => offlineEnemyAttack(target, now, report),
    consumePlayerCooldownMs: (now) => consumeLastPlayerAttackCooldown(now),
    getNextEnemyAttackMs: (target, now) => effectiveEnemyAttackMs(target, now),
  });
}

function offlineTravelTimeMs() {
  const distance = Math.max(0, enemySpawnDistance() - playerAttackRange());
  return computeOfflineTravelTimeMs(distance, {
    walkCap: TRAVEL_WALK_DISTANCE,
    playerSpeed: LANE.playerSpeed,
    runSpeed: LANE.runSpeed,
  });
}

function offlinePetAttackDelayMs(pet, simNow) {
  return computeOfflinePetAttackDelayMsCore(pet, simNow, {
    pendingPetAttack: Boolean(state.battle.pendingPetAttack),
    shinsuShowPending: pet?.spellId === "SummonShinsu" && !pet?.shinsuVisible && pet?.action === "show",
    outOfRange: taoistPetEnemyDistance() > taoistPetAttackRangePx(pet),
  });
}

function offlineUpdateRecovery(now, report) {
  updatePendingHeal(now);
  updatePendingDefenceBuff(now, { offline: true });
  updatePendingWizardBuff(now, { offline: true });
  updatePendingMassHeal(now, { offline: true });
  updatePendingUltimateEnhancer(now, { offline: true });
  updatePendingPetEnhancer(now, { offline: true });
  updatePendingPoison(now, { offline: true });
  updatePendingPetAttack(now, { offline: true });
  updatePendingTaoPet(now);
  updatePendingWizardMirror(now);
  updateWizardMirror(now, { offline: true });
  updateHealingRegen(now);
  updateVampirismRegen(now);
  updateEnemyPoisons(now, { offline: true });
  updatePotionRegen(now);
  if (state.battle.combatClass === "Warrior") {
    maybeAutoWarriorCharge(now, { offline: true });
  }
  offlineAutoUsePotions(now, report);
  updatePendingHeal(now);
  updatePendingDefenceBuff(now, { offline: true });
  updatePendingWizardBuff(now, { offline: true });
  updatePendingMassHeal(now, { offline: true });
  updatePendingUltimateEnhancer(now, { offline: true });
  updatePendingPetEnhancer(now, { offline: true });
  updatePendingPoison(now, { offline: true });
  updatePendingTwinDrakeHits(now);
  updateAttachedSpellFx(now);
  updatePendingPetAttack(now, { offline: true });
  updatePendingTaoPet(now);
  updatePendingWizardMirror(now);
  updateWizardMirror(now, { offline: true });
  updateHealingRegen(now);
  updateVampirismRegen(now);
  updateEnemyPoisons(now, { offline: true });
  updatePotionRegen(now);
}

function offlineAutoUsePotions(now, report) {
  const resources = ["hp", "mp"].sort((a, b) => resourceRatio(a) - resourceRatio(b));
  for (const kind of resources) {
    if (!shouldAutoUsePotion(kind, now)) continue;
    const candidate = autoPotionCandidates(kind)[0];
    if (!candidate) continue;
    const hpRestore = potionRestoreAmount(candidate.item, "hp");
    const mpRestore = potionRestoreAmount(candidate.item, "mp");
    if (!removeInventoryEntry(candidate.entry.id, 1)) continue;
    queuePotionRestore(hpRestore, mpRestore, now);
    state.battle.autoPotionReadyAt[kind] = now + AUTO_POTION_COOLDOWN_MS;
    incrementReportCount(report.potionsUsed, candidate.item.name);
  }
}

function applyOfflineEnemyDamage(enemy, damage, now, kind = "physical") {
  if (damage <= 0) return;
  applyCombatDamageEvent(enemyDamageEvent(damage, { kind }), now, { enemy });
}

function offlinePlayerAttack(enemy, now) {
  state.battle.enemy = enemy;
  state.battle.enemyId = enemy.id;
  state.battle.enemyX = state.battle.playerX + playerAttackRange();

  if (state.battle.combatClass === "Wizard") {
    offlineWizardAttack(enemy, now);
    return true;
  }
  if (state.battle.combatClass === "Taoist") {
    offlineTaoistAttack(enemy, now);
    return true;
  }
  return offlineWarriorAttack(enemy, now);
}

function offlineWarriorAttack(enemy, now) {
  const battle = state.battle;
  const { skill, learned, cost, charged } = usableWarriorAttackSkill(now);

  if (skill.buff) {
    castWarriorBuff(skill, learned, cost, now);
    battle.lastPlayerAttackCooldownMs = CRYSTAL_PLAYER_ACTION_LOCK_MS;
    return true;
  }

  if (isBladeAvalancheSkill(skill)) {
    if (learned) commitWarriorSpellUse(skill, learned, cost, now);
    battle.lastPlayerAttackCooldownMs = playerWeaponAttackCooldownMs(now, skill);
    if (learned && rollHit(battle.player.accuracy, enemy.agility)) {
      const depthIndex = bladeAvalancheDepthIndexFromDistance(enemyDistance());
      if (depthIndex != null) {
        const damage = rollBladeAvalancheDamage(
          skill,
          learned,
          battle.player,
          enemy,
          state.inventory,
          bladeAvalancheDepthDamageScale(depthIndex),
        );
        const scaled = scalePhysicalDamageForStun(damage, enemyStunned(enemy, now));
        if (scaled > 0) {
          applyOfflineEnemyDamage(enemy, scaled, now, "magic");
          if (learned) levelWarriorMagic(skill, learned, now);
        }
      }
    }
    levelPassiveWeaponMagic(now);
    rollSlayingChargeAfterAttack(now);
    maybeAutoWarriorCharge(now, { offline: true });
    return true;
  }

  if (learned) commitWarriorSpellUse(skill, learned, cost, now);
  battle.lastPlayerAttackCooldownMs = playerWeaponAttackCooldownMs(now, skill);
  let damage = 0;
  if (learned) {
    if (!rollHit(battle.player.accuracy, enemy.agility)) {
      rollSlayingChargeAfterAttack(now);
      maybeAutoWarriorCharge(now, { offline: true });
      return true;
    }
    damage = rollWarriorMagicDamage(skill, learned, battle.player, enemy);
  } else {
    const stats = effectiveCombatStats(battle.player);
    const attack = resolvePhysicalAttack(
      battle.player.accuracy,
      enemy.agility,
      stats.dc,
      enemyPhysicalDefence(enemy),
      stats.luck,
    );
    if (!attack.hit) {
      rollSlayingChargeAfterAttack(now);
      maybeAutoWarriorCharge(now, { offline: true });
      return true;
    }
    damage = applyCritToOutgoingDamage(attack.damage, battle.player);
  }
  const scaled = scalePhysicalDamageForStun(damage, enemyStunned(enemy, now));
  if (scaled <= 0) {
    rollSlayingChargeAfterAttack(now);
    maybeAutoWarriorCharge(now, { offline: true });
    return true;
  }
  applyOfflineEnemyDamage(enemy, scaled, now, learned ? "magic" : "physical");
  if (learned) levelWarriorMagic(skill, learned, now);
  levelPassiveWeaponMagic(now);
  rollSlayingChargeAfterAttack(now);
  if (skill.id === "TwinDrakeBlade" && charged && enemy.hp > 0) {
    queueTwinDrakeSecondHit({ classId: battle.combatClass }, learned, damage, now);
  }
      maybeAutoWarriorCharge(now, { offline: true });
  return true;
}

function offlineMagicAttack(enemy, now, statKey, multiplier = 1) {
  const player = state.battle.player;
  const { hit, damage } = resolveMagicAttack(
    enemy,
    player[statKey] ?? player.dc,
    enemyMagicalDefence(enemy),
    player.luck,
    multiplier,
  );
  if (hit) applyOfflineEnemyDamage(enemy, damage, now, "magic");
}

function offlineWizardAttack(enemy, now) {
  const battle = state.battle;
  const queued = queuedCombatSpell("Wizard");
  if (queued?.spell?.id === "Mirroring") {
    const mirrorCast = usableWizardMirroring(now, { requireAuto: false, ignorePhase: true });
    if (mirrorCast) {
      castWizardMirroring(mirrorCast, now, { offline: true });
      battle.lastPlayerAttackCooldownMs = wizardCastCooldownMs(mirrorCast.spell, mirrorCast.learned);
      return;
    }
  } else if (!queued) {
    const mirrorCast = usableWizardMirroring(now);
    if (mirrorCast) {
      castWizardMirroring(mirrorCast, now, { offline: true });
      battle.lastPlayerAttackCooldownMs = wizardCastCooldownMs(mirrorCast.spell, mirrorCast.learned);
      return;
    }
  }
  const attackSpell = usableWizardAttackSpell(now);
  const phase = resolveOfflineWizardTurnPhase({
    defenceAuto: Boolean(usableWizardDefenceBuff(now)),
    defenceQueued: queued?.spell?.id === OFFLINE_WIZARD_DEFENCE_SPELL_ID
      && Boolean(usableWizardDefenceBuff(now, { requireAuto: false })),
    hasAttackSpell: Boolean(attackSpell),
    weaponFallback: attackSpell
      ? resolveSpellCastWeaponFallback({
        cooldownWaiting: attackSpell.cooldownWaiting,
        playerMp: battle.player?.mp ?? 0,
        spellCost: attackSpell.cost,
      }) === "weapon"
      : false,
  });

  if (phase === "defenceAuto") {
    castWizardDefenceBuff(usableWizardDefenceBuff(now), now, { offline: true });
    return;
  }
  if (phase === "defenceQueued") {
    castWizardDefenceBuff(usableWizardDefenceBuff(now, { requireAuto: false }), now, { offline: true });
    return;
  }
  if (phase === "weapon") {
    offlineWizardWeaponAttack(enemy, now);
    return;
  }
  if (phase !== "cast" || !attackSpell) return;

  const { spell, learned, cost } = attackSpell;
  battle.lastPlayerAttackCooldownMs = wizardSpellActionLockMs(spell, learned);
  commitWizardSpellUse(spell, learned, cost, now);
  if (spell.id === "TurnUndead") {
    const result = rollTurnUndeadResult(spell, learned, battle.player, enemy);
    if (result.success) {
      applyOfflineEnemyDamage(enemy, Math.max(1, Math.trunc(Number(enemy.hp) || 1)), now, "magic");
      if (learned) levelMagicSkill(spell, learned, now);
    }
    return;
  }
  if (!rollMagicHit(enemy)) return;
  const damage = rollWizardMagicDamage(spell, learned, battle.player, enemy);
  if (damage <= 0) return;
  applyOfflineEnemyDamage(enemy, damage, now, "magic");
  if (spell.id === "FrostCrunch") applyFrostCrunchEffects(enemy, learned, battle.player, now);
  if (spell.id === "Vampirism" && learned) queueVampirismRestore(vampirismRestoreAmount(damage, learned), now);
  if (learned) levelMagicSkill(spell, learned, now);
}

function offlineWizardWeaponAttack(enemy, now) {
  const battle = state.battle;
  battle.lastPlayerAttackCooldownMs = playerWeaponAttackCooldownMs(now, BASIC_ATTACK_SKILL);
  const { hit, damage } = resolvePhysicalAttack(
    battle.player.accuracy,
    enemy.agility,
    battle.player.dc,
    enemyPhysicalDefence(enemy),
    battle.player.luck,
  );
  if (hit) applyOfflineEnemyDamage(enemy, applyCritToOutgoingDamage(damage, battle.player), now);
}

function offlineTaoistAttack(enemy, now) {
  const battle = state.battle;
  const queuedRequest = queuedCombatSpell("Taoist");
  const queued = usableQueuedTaoistSpell(now);
  if (queued) {
    switch (offlineTaoistQueuedSpellKind(queued.spell.id)) {
      case "soulFireBall":
        return offlineTaoistSoulFireBall(enemy, now, queued);
      case "healing":
        return castTaoistHealing(queued, now, { offline: true });
      case "poisoning":
        return castTaoistPoisoning(queued, now, { offline: true });
      case "poisonCloud":
        return castTaoistPoisonCloud(queued, now, { offline: true });
      case "plague":
        return castTaoistPlague(queued, now, { offline: true });
      case "curse":
        return castTaoistCurse(queued, now, { offline: true });
      case "summon": {
        castTaoistSummonPet(queued, now, { offline: true });
        updatePendingTaoPet(now + offlineTaoistSummonPetDelayMs(queued.spell.id, {
          skeletonMs: CRYSTAL_SUMMON_SKELETON_DELAY_MS,
          shinsuMs: CRYSTAL_SUMMON_SHINSU_DELAY_MS,
          holyDevaMs: CRYSTAL_SUMMON_HOLY_DEVA_DELAY_MS,
        }));
        battle.lastPlayerAttackCooldownMs = spellDelayMs(queued.spell, queued.learned);
        return;
      }
      case "defenceBuff":
        return castTaoistDefenceBuff(queued, now, { offline: true });
      case "energyShield":
        return castTaoistEnergyShield(queued, now, { offline: true });
      case "massHeal":
        return castTaoistMassHealing(queued, now, { offline: true });
      case "healingCircle":
        return castTaoistHealingCircle(queued, now, { offline: true });
      case "ultimateEnhancer":
        return castTaoistUltimateEnhancer(queued, now, { offline: true });
      case "petEnhancer":
        return castTaoistPetEnhancer(queued, now, { offline: true });
      default:
        break;
    }
  }
  if (queuedRequest) return offlineTaoistWeaponAttack(enemy, now);

  const autoSummonId = nextOfflineTaoistAutoSummonId({
    SummonSkeleton: Boolean(usableTaoistSummonSkeleton(now)),
    SummonShinsu: Boolean(usableTaoistSummonShinsu(now)),
    SummonHolyDeva: Boolean(usableTaoistSummonHolyDeva(now)),
  });
  if (autoSummonId) {
    const summon = usableTaoistSummonSpell(autoSummonId, now);
    if (summon) {
      castTaoistSummonPet(summon, now, { offline: true });
      updatePendingTaoPet(now + offlineTaoistSummonPetDelayMs(autoSummonId, {
        skeletonMs: CRYSTAL_SUMMON_SKELETON_DELAY_MS,
        shinsuMs: CRYSTAL_SUMMON_SHINSU_DELAY_MS,
        holyDevaMs: CRYSTAL_SUMMON_HOLY_DEVA_DELAY_MS,
      }));
      battle.lastPlayerAttackCooldownMs = spellDelayMs(summon.spell, summon.learned);
      return;
    }
  }

  if (taoistPetCanTank()) {
    if (!taoistPetSupportAttackOffline(now)) battle.lastPlayerAttackCooldownMs = TAOIST_COMBAT_POLL_MS;
    return;
  }
  if (enemy.hp <= 0) return;
  taoistPlayerTankAttackOffline(enemy, now);
}

function taoistOfflineSupportAvailability(now) {
  return {
    Healing: Boolean(usableTaoistHealing(now)),
    MassHealing: Boolean(usableTaoistMassHealing(now)),
    HealingCircle: Boolean(usableTaoistHealingCircle(now)),
    SoulShield: Boolean(usableTaoistDefenceBuff("SoulShield", now)),
    BlessedArmour: Boolean(usableTaoistDefenceBuff("BlessedArmour", now)),
    EnergyShield: Boolean(usableTaoistEnergyShield(now)),
    UltimateEnhancer: Boolean(usableTaoistUltimateEnhancer(now)),
    PetEnhancer: Boolean(usableTaoistPetEnhancer(now)),
    Poisoning: Boolean(usableTaoistPoisoning(now)),
    PoisonCloud: Boolean(usableTaoistPoisonCloud(now)),
    Plague: Boolean(usableTaoistPlague(now)),
    Curse: Boolean(usableTaoistCurse(now)),
    SoulFireBall: Boolean(usableTaoistSoulFireBall(now)),
  };
}

function taoistOfflineCastSupportSpell(spellId, enemy, now, soulFireBallOptions = {}) {
  switch (spellId) {
    case "Healing":
      return castTaoistHealing(usableTaoistHealing(now), now, { offline: true });
    case "MassHealing":
      return castTaoistMassHealing(usableTaoistMassHealing(now), now, { offline: true });
    case "HealingCircle":
      return castTaoistHealingCircle(usableTaoistHealingCircle(now), now, { offline: true });
    case "SoulShield":
    case "BlessedArmour":
    case "EnergyShield":
      return castTaoistEnergyShield(usableTaoistEnergyShield(now), now, { offline: true });
    case "UltimateEnhancer":
      return castTaoistUltimateEnhancer(usableTaoistUltimateEnhancer(now), now, { offline: true });
    case "PetEnhancer":
      return castTaoistPetEnhancer(usableTaoistPetEnhancer(now), now, { offline: true });
    case "Poisoning":
      return castTaoistPoisoning(usableTaoistPoisoning(now), now, { offline: true });
    case "PoisonCloud":
      return castTaoistPoisonCloud(usableTaoistPoisonCloud(now), now, { offline: true });
    case "Plague":
      return castTaoistPlague(usableTaoistPlague(now), now, { offline: true });
    case "Curse":
      return castTaoistCurse(usableTaoistCurse(now), now, { offline: true });
    case "SoulFireBall":
      return offlineTaoistSoulFireBall(enemy, now, usableTaoistSoulFireBall(now), soulFireBallOptions);
    default:
      return false;
  }
}

function taoistPetSupportAttackOffline(now) {
  const spellId = nextOfflineTaoistSupportSpellId(
    taoistOfflineSupportAvailability(now),
    OFFLINE_TAOIST_PET_SUPPORT_SPELL_ORDER,
  );
  if (!spellId) return false;
  return taoistOfflineCastSupportSpell(spellId, state.battle.enemy, now);
}

function taoistPlayerTankAttackOffline(enemy, now) {
  const soulFireBall = usableTaoistSoulFireBall(now);
  if (soulFireBall) offlineTaoistSoulFireBall(enemy, now, soulFireBall, { secondary: true });
  if (enemy.hp <= 0) return;

  const spellId = nextOfflineTaoistSupportSpellId(
    taoistOfflineSupportAvailability(now),
    OFFLINE_TAOIST_SUPPORT_SPELL_ORDER,
  );
  if (spellId) {
    taoistOfflineCastSupportSpell(spellId, enemy, now);
    return;
  }
  offlineTaoistWeaponAttack(enemy, now);
}

function offlineTaoistSoulFireBall(enemy, now, soulFireBall, options = {}) {
  const battle = state.battle;
  const { spell, learned, cost, entry } = soulFireBall;
  if (!consumeOneInventoryUnit(entry.id)) return false;
  if (!options.secondary) battle.lastPlayerAttackCooldownMs = spellDelayMs(spell, learned);
  commitTaoistSpellUse(spell, learned, cost, now);
  if (!rollMagicHit(enemy)) return true;
  const damage = rollTaoistMagicDamage(spell, learned, battle.player, enemy);
  if (damage <= 0) return true;
  applyOfflineEnemyDamage(enemy, damage, now, "magic");
  if (learned) levelMagicSkill(spell, learned, now);
  return true;
}

function offlineTaoistWeaponAttack(enemy, now) {
  const battle = state.battle;
  battle.lastPlayerAttackCooldownMs = playerWeaponAttackCooldownMs(now, BASIC_ATTACK_SKILL);
  const { hit, damage } = resolvePhysicalAttack(
    battle.player.accuracy,
    enemy.agility,
    battle.player.dc,
    enemyPhysicalDefence(enemy),
    battle.player.luck,
  );
  if (hit) applyOfflineEnemyDamage(enemy, applyCritToOutgoingDamage(damage, battle.player), now);
  levelPassiveWeaponMagic(now);
}

function offlineEnemyAttack(enemy, now, report) {
  if (isTrainingDummyEnemy(enemy)) return;
  state.battle.enemy = enemy;
  const player = state.battle.player;
  if (!player || player.hp <= 0) return;
  if (taoistPetCanTank()) {
    const pet = state.battle.taoPet;
    const { hit, damage } = resolveIncomingEnemyAttack(enemy, defenceTargetForIncomingAttack(pet));
    if (!hit) return;
    applyCombatDamageEvent(petDamageEvent(damage), now, {
      target: {
        kind: "pet",
        applyDamage: (amount) => {
          pet.hp = Math.max(0, pet.hp - reduceTaoistPetIncomingDamage(pet, amount));
          if (pet.hp <= 0) markTaoistPetDead(now, { sound: false });
        },
      },
    });
    return;
  }
  const { hit, damage } = resolveIncomingEnemyAttack(enemy, defenceTargetForIncomingAttack(player));
  if (!hit) return;
  applyCombatDamageEvent(playerDamageEvent(damage), now, {
    target: {
      kind: "player",
      applyDamage: (amount) => {
        player.hp = Math.max(0, player.hp - amount);
        report.damageTaken += amount;
        if (player.hp <= 0) {
          state.battle.running = false;
          state.battle.phase = "idle";
        }
      },
    },
  });
}

function awardOfflineEnemyRewards(zone, enemy, report) {
  const reward = zone?.rewards ?? { gold: [1, 2] };
  const xp = adjustedKillExperience(enemy?.experience ?? 0, state.game.progress.level, enemy?.level ?? 0);
  const gold = adjustedKillGold(
    randomInt(reward.gold[0], reward.gold[1]),
    totalGoldBonusPercent(),
  );
  const drops = isRedThunderZumaEnemy(enemy)
    ? rollRedThunderZumaDrops()
    : rollZoneDrops(zone, enemy);
  const leveledTo = applyExperienceReward(xp);
  if (leveledTo.length) {
    applyEquippedStatsToBattlePlayer();
    restoreBattlePlayerResources();
  }

  state.inventory.gold += gold;
  state.game.progress.gold = state.inventory.gold;
  state.game.kills += 1;
  state.game.zoneKills += 1;
  state.game.lastReward = { xp, gold, drops: drops.added };
  state.battle.experience = state.game.progress.experience;
  state.battle.gold = state.game.progress.gold;
  state.battle.level = state.game.progress.level;

  recordOfflineKillRewards(report, {
    xp,
    gold,
    levels: leveledTo,
    addedDropLabels: drops.added.map((drop) => dropResultLabel(drop)),
    ignoredDropLabels: drops.ignored.map((item) => item.name),
  });
}

function finalizeOfflineBattleState(zone, report) {
  const now = performance.now();
  const player = state.battle.player;
  if (!player) return;

  state.showEnemies = true;
  state.battle.running = player.hp > 0;
  state.battle.returnToStandAt = 0;
  state.battle.pendingImpact = null;
  state.battle.pendingEnemyStrike = null;
  state.battle.activeSkill = "None";
  state.battle.activeSkillAtlas = null;
  state.battle.activeWizardSpell = null;
  state.battle.activeWizardSpellAtlas = null;
  state.battle.activeTaoSpell = null;
  state.battle.activeTaoSpellAtlas = null;
  state.battle.pendingHeal = null;
  state.battle.pendingPoison = null;

  if (player.hp <= 0 || report.diedAtMs) {
    dismissBattleCompanions();
    player.hp = 0;
    state.battle.phase = "idle";
    state.battle.nextPlayerAttackAt = 0;
    state.battle.nextEnemyAttackAt = 0;
    setPlayerAction("die", now);
    return;
  }

  const enemy = report.finalEnemy?.hp > 0
    ? report.finalEnemy
    : { ...randomZoneEnemyTemplate(zone), hp: undefined, mp: undefined };
  if (!(report.finalEnemy?.hp > 0)) dismissBattleCompanions();
  enemy.hp = enemy.hp ?? enemy.maxHp;
  enemy.mp = enemy.mp ?? enemy.maxMp;
  enemy.poisons = Array.isArray(enemy.poisons) ? enemy.poisons : [];
  state.battle.enemy = enemy;
  state.battle.enemyId = enemy.id;
  state.battle.enemyAggro = Boolean(report.finalEnemy?.hp > 0);
  state.battle.phase = report.finalEnemy?.hp > 0 ? "engaged" : "advance";
  state.battle.playerX = 0;
  state.battle.enemyX = report.finalEnemy?.hp > 0 ? playerAttackRange() : enemySpawnDistance();
  if (report.finalEnemy?.hp > 0 && state.battle.taoPet?.active) {
    placeTaoistCombatPet(state.battle.taoPet);
    if (!taoistPetIsFollower(state.battle.taoPet) && !enemyUsesFixedArenaSpawn()) {
      state.battle.enemyX = Math.max(LANE.aggroRange, state.battle.enemyX);
    }
  }
  state.battle.cameraX = state.battle.playerX - playerScreenX();
  state.battle.travelStartedAt = now;
  state.battle.travelStartedX = state.battle.playerX;
  state.battle.nextPlayerAttackAt = report.finalEnemy?.hp > 0 ? now + playerAttackDelayMs(now) : 0;
  state.battle.nextEnemyAttackAt = report.finalEnemy?.hp > 0 ? now + Math.max(1, Number(enemy.attackMs) || 2500) : 0;
  state.enemy.index = enemy.monsterIndex;
  state.enemy.action = "standing";
  state.enemy.frame = 0;
  state.enemy.oneShot = false;
  state.enemy.lastTick = now;
  setPlayerAction(report.finalEnemy?.hp > 0 ? "stance" : "walking", now);
}

function presentOfflineReport(report) {
  const duration = formatDuration(report.elapsedMs);
  const dropsText = reportCountText(report.drops, 3);
  const ignoredText = reportCountText(report.ignoredDrops, 2);
  const potionText = reportCountText(report.potionsUsed, 2);
  const isBossParty = report.kind === "bossParty";
  const lines = isBossParty
    ? [
      `Offline party ${duration}: ${report.kills} kills`,
      `+${report.xp} XP, +${report.gold} gold`,
    ]
    : [
      `Offline ${duration}: ${report.kills} kills`,
      `+${report.xp} XP, +${report.gold} gold`,
    ];
  if (report.wavesCleared > 0) lines.push(`Waves cleared: ${report.wavesCleared}`);
  if (report.levels.length) lines.push(`Level ${report.levels.at(-1)}`);
  if (dropsText) lines.push(`Found ${dropsText}`);
  if (ignoredText) lines.push(`No room for ${ignoredText}`);
  if (potionText) lines.push(`Used ${potionText}`);
  if (report.diedAtMs) lines.push(`Defeated after ${formatDuration(report.diedAtMs)}`);
  if (report.capped) lines.push("Offline cap reached: 8h");

  state.game.offlineReport = {
    kind: isBossParty ? "bossParty" : "zone",
    duration,
    kills: report.kills,
    xp: report.xp,
    gold: report.gold,
    level: report.levels.at(-1) ?? null,
    drops: [...report.drops.entries()],
    ignoredDrops: [...report.ignoredDrops.entries()],
    potionsUsed: [...report.potionsUsed.entries()],
    defeatedAfter: report.diedAtMs ? formatDuration(report.diedAtMs) : "",
    capped: report.capped,
  };
  state.game.recentLoot = [...lines, ...state.game.recentLoot].slice(0, 6);
  for (const line of [...lines].reverse()) pushBattleLog(line);
  addLootNotice(report.diedAtMs ? "Offline: defeated" : `Offline: ${report.kills} kills`, report.diedAtMs ? "full" : "item");
  renderOfflineReport();
}

function presentGroupDungeonOfflineNotice(pending) {
  const awayMs = Math.max(0, Math.trunc(Number(pending?.rawElapsedMs ?? pending?.elapsedMs) || 0));
  const duration = formatDuration(awayMs);
  const message = "Offline simulation does not work in group dungeons, but your progress was saved.";
  state.game.offlineReport = {
    kind: "groupDungeon",
    duration,
    message,
  };
  pushBattleLog(message);
  addLootNotice("Group dungeon: progress saved", "item");
  renderOfflineReport();
}

function renderOfflineReport() {
  const report = state.game.offlineReport;
  if (!els.offlineReport) return;
  if (!report) {
    els.offlineReport.hidden = true;
    els.offlineReport.innerHTML = "";
    return;
  }

  if (report.kind === "groupDungeon") {
    els.offlineReport.hidden = false;
    els.offlineReport.innerHTML = `
      <div class="offline-report-window" role="dialog" aria-modal="true" aria-labelledby="offlineReportTitle">
        <header>
          <div>
            <p class="eyebrow">Offline Progress</p>
            <h2 id="offlineReportTitle">While You Were Away</h2>
          </div>
          <button type="button" data-close-offline-report aria-label="Close offline report">X</button>
        </header>
        <p class="offline-report-message">${escapeHtml(report.message)}</p>
        ${report.duration ? `<dl><dt>Away</dt><dd>${escapeHtml(String(report.duration))}</dd></dl>` : ""}
        <button type="button" class="primary" data-close-offline-report>Continue</button>
      </div>
    `;
    return;
  }

  const rows = [["Away", report.duration]];
  if (report.kind === "mining") {
    rows.push(["Swings", report.swings ?? 0]);
    rows.push(["Ore finds", report.hits ?? 0]);
    if (report.drops?.length) rows.push(["Found", reportEntriesText(report.drops, 6)]);
    if (report.ignoredDrops?.length) rows.push(["No Room", reportEntriesText(report.ignoredDrops, 4)]);
    rows.push(["Result", report.capped ? "8 hour cap reached" : "Still mining"]);
  } else {
    rows.push(["Kills", report.kills ?? 0]);
    rows.push(["XP", `+${report.xp ?? 0}`]);
    rows.push(["Gold", `+${report.gold ?? 0}`]);
    if (report.level) rows.push(["Level", report.level]);
    if (report.potionsUsed?.length) rows.push(["Potions", reportEntriesText(report.potionsUsed, 4)]);
    if (report.drops?.length) rows.push(["Found", reportEntriesText(report.drops, 5)]);
    if (report.ignoredDrops?.length) rows.push(["No Room", reportEntriesText(report.ignoredDrops, 4)]);
    if (report.defeatedAfter) rows.push(["Result", `Defeated after ${report.defeatedAfter}`]);
    else rows.push(["Result", report.capped ? "8 hour cap reached" : "Still hunting"]);
  }

  els.offlineReport.hidden = false;
  els.offlineReport.innerHTML = `
    <div class="offline-report-window" role="dialog" aria-modal="true" aria-labelledby="offlineReportTitle">
      <header>
        <div>
          <p class="eyebrow">Offline Progress</p>
          <h2 id="offlineReportTitle">While You Were Away</h2>
        </div>
        <button type="button" data-close-offline-report aria-label="Close offline report">X</button>
      </header>
      <dl>
        ${rows.map(([label, value]) => `<dt>${escapeHtml(String(label))}</dt><dd>${escapeHtml(String(value))}</dd>`).join("")}
      </dl>
      <button type="button" class="primary" data-close-offline-report>Continue</button>
    </div>
  `;
}

function closeOfflineReport() {
  state.game.offlineReport = null;
  renderOfflineReport();
}

function ensureMusicAudio() {
  if (musicAudio) return musicAudio;
  musicAudio = new Audio();
  musicAudio.preload = "auto";
  musicAudio.volume = normalizedVolume(state.settings.musicVolume);
  musicAudio.addEventListener("ended", () => handleMusicEnded());
  musicAudio.addEventListener("error", () => {
    musicStatusText = `Could not play ${currentMusicTrack()?.id ?? "music"}.`;
    sceneSignature = "";
    renderSceneOverlay();
  });
  return musicAudio;
}

function currentMusicTrack() {
  return BACKGROUND_MUSIC_TRACKS[musicTrackIndex] ?? BACKGROUND_MUSIC_TRACKS[0] ?? null;
}

function syncBackgroundMusic() {
  const audio = ensureMusicAudio();
  audio.volume = normalizedVolume(state.settings.musicVolume);
  if (!state.settings.musicEnabled) {
    audio.pause();
    musicStatusText = "";
    return;
  }
  if (!audio.src) setMusicTrack(musicTrackIndex, false);
  playCurrentMusic();
}

function playCurrentMusic() {
  const audio = ensureMusicAudio();
  const track = currentMusicTrack();
  if (!track) return;
  if (!audio.src || !audio.src.endsWith(track.src.replace("./", ""))) {
    audio.src = track.src;
  }
  audio.volume = normalizedVolume(state.settings.musicVolume);
  const playPromise = audio.play();
  if (playPromise?.catch) {
    playPromise
      .then(() => {
        musicStatusText = "";
        sceneSignature = "";
        renderSceneOverlay();
      })
      .catch(() => {
        musicStatusText = "Click Music On or Next once to start audio.";
        sceneSignature = "";
        renderSceneOverlay();
      });
  }
}

function setMusicTrack(index, autoplay = true, mode = state.settings.musicMode) {
  const count = BACKGROUND_MUSIC_TRACKS.length;
  if (!count) return;
  musicTrackIndex = ((Math.trunc(Number(index) || 0) % count) + count) % count;
  state.settings.musicMode = normalizedMusicMode(mode);
  const audio = ensureMusicAudio();
  const track = currentMusicTrack();
  audio.src = track.src;
  audio.currentTime = 0;
  sceneSignature = "";
  if (autoplay && state.settings.musicEnabled) playCurrentMusic();
  renderSceneOverlay();
}

function handleMusicEnded() {
  if (!state.settings.musicEnabled) return;
  if (normalizedMusicMode(state.settings.musicMode) === MUSIC_MODE_TRACK) {
    setMusicTrack(musicTrackIndex, true, MUSIC_MODE_TRACK);
    return;
  }
  playNextMusicTrack();
}

function playNextMusicTrack() {
  setMusicTrack(musicTrackIndex + 1, state.settings.musicEnabled, MUSIC_MODE_PLAYLIST);
}

function setMusicEnabled(enabled) {
  state.settings.musicEnabled = Boolean(enabled);
  if (state.settings.musicEnabled && !ensureMusicAudio().src) setMusicTrack(musicTrackIndex, false);
  syncBackgroundMusic();
  saveGameState(true);
  sceneSignature = "";
  renderSceneOverlay();
}

function setMusicVolume(value) {
  state.settings.musicVolume = normalizedVolume(value);
  if (musicAudio) musicAudio.volume = state.settings.musicVolume;
  saveGameState(true);
  sceneSignature = "";
  renderSceneOverlay();
}

function sfxEntry(key) {
  return state.sfxManifest?.byKey?.[key] ?? null;
}

function ensureSfxPool(key) {
  const entry = sfxEntry(key);
  if (!entry?.src) return null;
  let pool = sfxPools.get(key);
  if (!pool) {
    pool = Array.from({ length: SFX_POOL_SIZE }, () => {
      const audio = new Audio(entry.src);
      audio.preload = "auto";
      return audio;
    });
    sfxPools.set(key, pool);
    sfxPoolIndexes.set(key, 0);
  }
  return pool;
}

function playSfx(key, options = {}) {
  if (!state.settings.sfxEnabled) return false;
  const pool = ensureSfxPool(key);
  if (!pool?.length) return false;

  const now = performance.now();
  const throttleMs = Math.max(0, Number(options.throttleMs) || 0);
  if (!options.force && throttleMs > 0 && now - (sfxLastPlayedAt.get(key) ?? -Infinity) < throttleMs) return false;
  sfxLastPlayedAt.set(key, now);

  const startIndex = sfxPoolIndexes.get(key) ?? 0;
  const audio = pool.find((candidate) => candidate.paused || candidate.ended) ?? pool[startIndex];
  sfxPoolIndexes.set(key, (startIndex + 1) % pool.length);
  try {
    audio.currentTime = 0;
  } catch {
    // Some browsers can briefly reject currentTime before metadata is ready.
  }
  audio.volume = normalizedVolume(state.settings.sfxVolume) * normalizedVolume(options.volume ?? 1);
  const playPromise = audio.play();
  if (playPromise?.catch) playPromise.catch(() => {});
  return true;
}

function setSfxEnabled(enabled) {
  state.settings.sfxEnabled = Boolean(enabled);
  saveGameState(true);
  sceneSignature = "";
  renderSceneOverlay();
}

function setSfxVolume(value) {
  state.settings.sfxVolume = normalizedVolume(value);
  saveGameState(true);
  sceneSignature = "";
  renderSceneOverlay();
}

function loadPrototypeStatsPlayerId() {
  try {
    const existing = localStorage.getItem(STATS_PLAYER_ID_KEY);
    if (existing) return existing;
    const generated = globalThis.crypto?.randomUUID?.() ?? `anon-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
    localStorage.setItem(STATS_PLAYER_ID_KEY, generated);
    return generated;
  } catch {
    return `anon-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
  }
}

function prototypeStatsPlayerLabel(playerId = state.prototypeStats.playerId) {
  const accountId = String(playerId ?? "").split(":")[0];
  if (!accountId) return "Player ????????";
  return `Player ${accountId.slice(0, 8)}`;
}

// The name other players see: the chosen alias if set, else the derived label.
function prototypeStatsDisplayName(playerId = state.prototypeStats.playerId) {
  const alias = String(state.prototypeStats.alias ?? "").trim();
  if (alias) return alias;
  return prototypeStatsPlayerLabel(playerId);
}

const PLAYER_ALIAS_MIN_LENGTH = 3;
const PLAYER_ALIAS_MAX_LENGTH = 16;
const PLAYER_ALIAS_PATTERN = /^[A-Za-z0-9 ._'-]+$/;

function normalizePlayerAliasInput(value) {
  return String(value ?? "").trim().replace(/\s+/g, " ").slice(0, PLAYER_ALIAS_MAX_LENGTH);
}

function playerAliasValidationError(alias) {
  if (alias.length < PLAYER_ALIAS_MIN_LENGTH) return "Name must be at least 3 characters.";
  if (alias.length > PLAYER_ALIAS_MAX_LENGTH) return "Name must be 16 characters or fewer.";
  if (!PLAYER_ALIAS_PATTERN.test(alias)) return "Use only letters, numbers, spaces or . _ ' -";
  if (/^player\b/i.test(alias)) return "Name cannot start with \"Player\".";
  return "";
}

function setPlayerAliasStatus(status, error = "") {
  state.prototypeStats.aliasStatus = status;
  state.prototypeStats.aliasError = error;
  if (state.openScenes.options) {
    sceneSignature = "";
    renderSceneOverlay();
  }
}

async function fetchPlayerAlias() {
  const stats = state.prototypeStats;
  if (stats.aliasLoaded) return;
  const base = leaderboardApiBase();
  const playerId = String(stats.playerId ?? "").split(":")[0];
  if (!base || !playerId) return;
  try {
    const response = await fetch(`${base}/player/alias?playerId=${encodeURIComponent(playerId)}`, {
      method: "GET",
      headers: { Accept: "application/json" },
    });
    if (!response.ok) return;
    const data = await response.json();
    stats.alias = typeof data?.alias === "string" ? data.alias : "";
    stats.aliasInput = stats.alias;
    stats.aliasLoaded = true;
    if (state.openScenes.options) {
      sceneSignature = "";
      renderSceneOverlay();
    }
  } catch {
    // Non-fatal: alias is a cosmetic overlay on the derived label.
  }
}

async function submitPlayerAlias() {
  const stats = state.prototypeStats;
  if (stats.aliasSaving) return;
  const base = leaderboardApiBase();
  const playerId = String(stats.playerId ?? "").split(":")[0];
  const recoveryCode = state.cloudSave?.recoveryCode ?? "";
  if (!base || !playerId) {
    setPlayerAliasStatus("error", "Social features are not available right now.");
    return;
  }
  if (!recoveryCode) {
    setPlayerAliasStatus("error", "A recovery code is required to claim a name.");
    return;
  }
  const alias = normalizePlayerAliasInput(stats.aliasInput);
  const validationError = playerAliasValidationError(alias);
  if (validationError) {
    setPlayerAliasStatus("error", validationError);
    return;
  }

  stats.aliasSaving = true;
  setPlayerAliasStatus("saving");
  try {
    const response = await fetch(`${base}/player/alias`, {
      method: "POST",
      headers: { "content-type": "application/json", Accept: "application/json" },
      body: JSON.stringify({ playerId, recoveryCode, alias }),
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok) {
      stats.aliasSaving = false;
      setPlayerAliasStatus("error", String(data?.error ?? "Could not save that name."));
      return;
    }
    stats.alias = typeof data?.alias === "string" ? data.alias : alias;
    stats.aliasInput = stats.alias;
    stats.aliasLoaded = true;
    stats.aliasSaving = false;
    setPlayerAliasStatus("saved");
  } catch {
    stats.aliasSaving = false;
    setPlayerAliasStatus("error", "Network error. Please try again.");
  }
}

function prototypeStatsNoticeRequired() {
  if (!state.settings.prototypeStatsEnabled) return false;
  return Math.max(0, Math.trunc(Number(state.settings.prototypeStatsNoticeVersion) || 0)) < STATS_NOTICE_VERSION;
}

function prototypeResetNoticeRequired(now = Date.now()) {
  // The itch/demo build is frozen, so progress can't be reset by future
  // updates there. Suppress the reset warning on any demo host (same gating
  // as the live-site banner); it still shows on the live site.
  if (demoLiveSiteBannerConfig()) return false;
  const seenVersion = Math.max(0, Math.trunc(Number(state.settings.prototypeResetNoticeVersion) || 0));
  const lastSeenAt = Math.max(0, Math.trunc(Number(state.settings.prototypeResetNoticeLastSeenAt) || 0));
  return seenVersion < PROTOTYPE_RESET_NOTICE_VERSION
    || now - lastSeenAt >= PROTOTYPE_RESET_NOTICE_INTERVAL_MS;
}

function cloudBackupNoticeRequired(now = Date.now()) {
  const seenVersion = Math.max(0, Math.trunc(Number(state.settings.cloudBackupNoticeVersion) || 0));
  const lastSeenAt = Math.max(0, Math.trunc(Number(state.settings.cloudBackupNoticeLastSeenAt) || 0));
  return seenVersion < CLOUD_BACKUP_NOTICE_VERSION
    || now - lastSeenAt >= CLOUD_BACKUP_NOTICE_INTERVAL_MS;
}

function normalizeDemoLiveSiteUrl(value) {
  const text = typeof value === "string" ? value.trim() : "";
  if (!text) return DEFAULT_DEMO_LIVE_SITE_URL;
  try {
    const url = new URL(text);
    if (url.protocol !== "https:" && url.protocol !== "http:") return "";
    return url.href.replace(/\/$/, "");
  } catch {
    return "";
  }
}

function isLiveSiteHost(hostname = location.hostname) {
  return LIVE_SITE_HOSTS.has(String(hostname ?? "").toLowerCase());
}

function fullscreenSupported() {
  const rootEl = document.documentElement;
  if (document.fullscreenEnabled && rootEl.requestFullscreen) return true;
  return Boolean(document.webkitFullscreenEnabled && rootEl.webkitRequestFullscreen);
}

function isAppFullscreen() {
  return Boolean(document.fullscreenElement ?? document.webkitFullscreenElement);
}

function syncFullscreenToggle() {
  const button = els.fullscreenToggle;
  if (!button) return;
  const supported = fullscreenSupported();
  button.hidden = !supported;
  if (!supported) return;
  const active = isAppFullscreen();
  button.setAttribute("aria-pressed", active ? "true" : "false");
  button.setAttribute("aria-label", active ? "Exit fullscreen" : "Enter fullscreen");
  button.title = active ? "Exit fullscreen" : "Fullscreen";
}

async function toggleAppFullscreen() {
  if (!fullscreenSupported()) return;
  try {
    if (isAppFullscreen()) {
      if (document.exitFullscreen) await document.exitFullscreen();
      else document.webkitExitFullscreen?.();
    } else {
      const rootEl = document.documentElement;
      if (rootEl.requestFullscreen) await rootEl.requestFullscreen();
      else rootEl.webkitRequestFullscreen?.();
    }
  } catch {
    // Browser may reject fullscreen outside a direct user gesture.
  }
  syncFullscreenToggle();
}

function demoLiveSiteLinkUrl(url) {
  try {
    const target = new URL(url);
    target.searchParams.set("from", "demo");
    return target.href;
  } catch {
    return url;
  }
}

function isDemoEmbedHost(hostname = location.hostname) {
  const host = String(hostname ?? "").toLowerCase();
  if (!host) return false;
  if (isLiveSiteHost(host)) return false;
  if (host === "localhost" || host === "127.0.0.1") return true;
  return host.endsWith(".itch.io")
    || host.endsWith(".itch.zone")
    || host.includes(".itch.")
    || host.endsWith(".itch.games");
}

function demoLiveSiteBannerConfig() {
  const banner = state.demoLiveSiteBanner ?? {};
  const query = new URLSearchParams(location.search);
  const url = normalizeDemoLiveSiteUrl(banner.url || DEFAULT_DEMO_LIVE_SITE_URL);
  if (!url) return null;
  if (query.get("demoBanner") === "0") return null;
  if (query.get("demoBanner") === "1") return { url };
  if (banner.enabled === false || isLiveSiteHost()) return null;
  if (banner.enabled === true || isDemoEmbedHost()) return { url };
  return null;
}

function demoLiveSiteBannerRequired(now = Date.now()) {
  if (!demoLiveSiteBannerConfig()) return false;
  const lastSeenAt = Math.max(0, Math.trunc(Number(state.settings.demoLiveSiteBannerLastSeenAt) || 0));
  return now - lastSeenAt >= DEMO_LIVE_SITE_BANNER_INTERVAL_MS;
}

function prototypeStatsCanSubmit() {
  return Boolean(
    state.settings.prototypeStatsEnabled
      && state.prototypeStats.configured
      && state.prototypeStats.endpoint
      && !prototypeStatsNoticeRequired(),
  );
}

function loadOrCreateCloudRecoveryCode() {
  try {
    const existing = normalizeRecoveryCode(localStorage.getItem(CLOUD_RECOVERY_CODE_STORAGE_KEY));
    if (existing) return existing;
    const generated = createRecoveryCode();
    localStorage.setItem(CLOUD_RECOVERY_CODE_STORAGE_KEY, generated);
    return generated;
  } catch (err) {
    console.warn("Unable to persist cloud recovery code", err);
    return createRecoveryCode();
  }
}

function loadCloudSavedAt() {
  try {
    return Math.max(0, Math.trunc(Number(localStorage.getItem(CLOUD_LAST_SAVED_AT_STORAGE_KEY)) || 0));
  } catch {
    return 0;
  }
}

function storeCloudSavedAt(timestamp) {
  const savedAt = Math.max(0, Math.trunc(Number(timestamp) || 0));
  state.cloudSave.lastSavedAt = savedAt;
  try {
    if (savedAt > 0) localStorage.setItem(CLOUD_LAST_SAVED_AT_STORAGE_KEY, String(savedAt));
    else localStorage.removeItem(CLOUD_LAST_SAVED_AT_STORAGE_KEY);
  } catch {
    // The in-memory timestamp still gives useful status for this session.
  }
}

function storeCloudRecoveryCode(code) {
  const normalized = normalizeRecoveryCode(code);
  if (!normalized) return false;
  state.cloudSave.recoveryCode = normalized;
  try {
    localStorage.setItem(CLOUD_RECOVERY_CODE_STORAGE_KEY, normalized);
  } catch {
    // The code remains usable for this session and visible for manual copying.
  }
  return true;
}

function rotateCloudRecoveryCode() {
  storeCloudRecoveryCode(createRecoveryCode());
  storeCloudSavedAt(0);
  state.cloudSave.lastAttemptAt = performance.now();
  state.cloudSave.restoreCodeInput = "";
  state.cloudSave.pendingRestore = null;
  state.cloudSave.statusText = "A new recovery code was created for this fresh save.";
}

function setCloudSaveStatus(message) {
  state.cloudSave.statusText = String(message ?? "");
  sceneSignature = "";
  if (state.openScenes.options) renderSceneOverlay();
}

function formatCloudSaveTime(timestamp) {
  const value = Math.max(0, Math.trunc(Number(timestamp) || 0));
  if (!value) return "Not backed up yet";
  return new Date(value).toLocaleString();
}

function parseCloudServerTime(value) {
  const text = String(value ?? "").trim();
  if (!text) return 0;
  const normalized = /^\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}$/.test(text)
    ? `${text.replace(" ", "T")}Z`
    : text;
  const timestamp = Date.parse(normalized);
  return Number.isFinite(timestamp) ? timestamp : 0;
}

async function uploadCloudSave(reason = "manual") {
  if (!saveReady || !state.cloudSave.configured || !state.cloudSave.endpoint) {
    setCloudSaveStatus("Cloud saves are not available right now. Your local save is unaffected.");
    return false;
  }
  if (state.cloudSave.saving) return false;

  state.cloudSave.saving = true;
  state.cloudSave.lastAttemptAt = performance.now();
  setCloudSaveStatus(reason === "manual" ? "Saving to the cloud..." : "Automatic cloud save in progress...");
  try {
    const snapshot = createSaveSnapshot();
    const response = await fetch(state.cloudSave.endpoint, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ recoveryCode: state.cloudSave.recoveryCode, save: snapshot }),
    });
    const body = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(body.error || `HTTP ${response.status}`);
    storeCloudSavedAt(parseCloudServerTime(body.savedAt) || Date.now());
    setCloudSaveStatus("Cloud save updated.");
    return true;
  } catch (err) {
    console.warn("Unable to upload cloud save", err);
    setCloudSaveStatus(`Cloud save failed: ${err.message || "please try again"}. Your local save is safe.`);
    return false;
  } finally {
    state.cloudSave.saving = false;
    sceneSignature = "";
    if (state.openScenes.options) renderSceneOverlay();
  }
}

function maybeUploadCloudSave(now) {
  if (!saveReady || !state.cloudSave.configured || state.cloudSave.saving || state.cloudSave.restoring) return;
  if (now - state.cloudSave.lastAttemptAt < CLOUD_SAVE_INTERVAL_MS) return;
  void uploadCloudSave("interval");
}

async function findCloudSaveForRestore(code) {
  const normalized = normalizeRecoveryCode(code);
  state.cloudSave.restoreCodeInput = normalized || String(code ?? "").trim().toUpperCase();
  if (!normalized) {
    setCloudSaveStatus("Enter a complete recovery code in the format MIR-XXXX-XXXX-XXXX-XXXX.");
    return false;
  }
  if (!state.cloudSave.configured || !cloudRestoreEndpoint(state.cloudSave.endpoint)) {
    setCloudSaveStatus("Cloud saves are not available right now.");
    return false;
  }
  if (state.cloudSave.restoring) return false;

  state.cloudSave.restoring = true;
  setCloudSaveStatus("Looking for that cloud save...");
  try {
    const response = await fetch(cloudRestoreEndpoint(state.cloudSave.endpoint), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ recoveryCode: normalized }),
    });
    const body = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(body.error || `HTTP ${response.status}`);
    const parsed = parseSaveSnapshotText(JSON.stringify(body.save));
    if (!parsed.ok) throw new Error(parsed.error);
    state.cloudSave.pendingRestore = {
      recoveryCode: normalized,
      savedAt: parseCloudServerTime(body.savedAt),
      snapshot: parsed.snapshot,
    };
    setCloudSaveStatus("Backup found. Confirm below to replace this browser's progress.");
    return true;
  } catch (err) {
    console.warn("Unable to restore cloud save", err);
    state.cloudSave.pendingRestore = null;
    setCloudSaveStatus(err.message || "Cloud save lookup failed.");
    return false;
  } finally {
    state.cloudSave.restoring = false;
    sceneSignature = "";
    if (state.openScenes.options) renderSceneOverlay();
  }
}

async function confirmCloudSaveRestore() {
  const pending = state.cloudSave.pendingRestore;
  if (!pending) return false;
  const restored = await replaceCurrentGameWithSnapshot(pending.snapshot, "Cloud save restored.");
  if (!restored) return false;
  storeCloudRecoveryCode(pending.recoveryCode);
  storeCloudSavedAt(pending.savedAt || Date.now());
  state.cloudSave.pendingRestore = null;
  state.cloudSave.restoreCodeInput = "";
  state.cloudSave.lastAttemptAt = performance.now();
  state.cloudSave.statusText = "Cloud save restored. Automatic backups will continue with this recovery code.";
  return true;
}

function cancelCloudSaveRestore() {
  state.cloudSave.pendingRestore = null;
  setCloudSaveStatus("Cloud restore cancelled.");
}

async function copyTextToClipboard(text, fallbackInput = null) {
  const value = String(text ?? "");
  if (!value) return false;
  try {
    if (navigator.clipboard?.writeText) {
      await navigator.clipboard.writeText(value);
      return true;
    }
  } catch {
    // Async Clipboard API is often blocked inside cross-origin iframes
    // (e.g. the itch.io embed); fall through to the legacy execCommand path.
  }
  try {
    if (fallbackInput && typeof fallbackInput.select === "function") {
      fallbackInput.focus();
      fallbackInput.select();
      fallbackInput.setSelectionRange?.(0, value.length);
      if (document.execCommand("copy")) return true;
    }
    const scratch = document.createElement("textarea");
    scratch.value = value;
    scratch.setAttribute("readonly", "");
    scratch.style.position = "fixed";
    scratch.style.top = "-1000px";
    scratch.style.opacity = "0";
    document.body.appendChild(scratch);
    scratch.focus();
    scratch.select();
    scratch.setSelectionRange(0, value.length);
    const copied = document.execCommand("copy");
    document.body.removeChild(scratch);
    if (copied) return true;
  } catch {
    // ignore and report failure below
  }
  return false;
}

async function copyCloudRecoveryCode() {
  const input = root.querySelector("[data-cloud-recovery-code]");
  const copied = await copyTextToClipboard(state.cloudSave.recoveryCode, input);
  if (copied) {
    setCloudSaveStatus("Recovery code copied.");
  } else {
    input?.focus();
    input?.select();
    setCloudSaveStatus("Recovery code selected. Press Ctrl+C to copy it.");
  }
}

async function loadPrototypeStatsConfig() {
  const config = await loadJson(STATS_CONFIG_URL).catch(() => ({}));
  const endpoint = typeof config.endpoint === "string" ? config.endpoint.trim() : "";
  const panelUrl = typeof config.panel === "string" ? config.panel.trim() : "";
  const bannerConfig = config.demoLiveSiteBanner && typeof config.demoLiveSiteBanner === "object"
    ? config.demoLiveSiteBanner
    : {};
  state.prototypeStats.endpoint = endpoint;
  state.prototypeStats.panelUrl = panelUrl;
  state.prototypeStats.configured = Boolean(endpoint) && config.enabled !== false;
  state.cloudSave.endpoint = cloudSaveEndpointFromConfig(config, endpoint);
  state.cloudSave.configured = Boolean(state.cloudSave.endpoint);
  state.demoLiveSiteBanner.enabled = bannerConfig.enabled === true
    ? true
    : bannerConfig.enabled === false
      ? false
      : null;
  state.demoLiveSiteBanner.url = normalizeDemoLiveSiteUrl(
    typeof bannerConfig.url === "string" ? bannerConfig.url : DEFAULT_DEMO_LIVE_SITE_URL,
  ) || DEFAULT_DEMO_LIVE_SITE_URL;
  state.prototypeStats.statusText = state.prototypeStats.configured
    ? (panelUrl ? "Anonymous progress stats ready. Leaderboard panel available." : "Anonymous progress stats ready.")
    : "Stats endpoint not configured yet.";
}

function setPrototypeStatsEnabled(enabled) {
  state.settings.prototypeStatsEnabled = Boolean(enabled);
  saveGameState(true);
  sceneSignature = "";
  renderSceneOverlay();
  renderPrototypeStatsNotice();
  if (state.settings.prototypeStatsEnabled) void submitPrototypeStats("enabled");
}

function maybeSubmitPrototypeStats(now) {
  if (!prototypeStatsCanSubmit()) return;
  if (state.prototypeStats.submitting) return;
  if (now - state.prototypeStats.lastSubmittedAt < STATS_SUBMIT_INTERVAL_MS) return;
  void submitPrototypeStats("interval", now);
}

function flushPrototypeStats(reason = "session-end") {
  if (!prototypeStatsCanSubmit()) return false;
  const snapshot = prototypeStatsSnapshot();
  const payloadHash = JSON.stringify(snapshot);
  if (payloadHash === state.prototypeStats.lastPayloadHash) return false;
  const payload = JSON.stringify({
    ...snapshot,
    reason,
    submittedAt: new Date().toISOString(),
  });
  if (!navigator.sendBeacon) {
    void submitPrototypeStats(reason);
    return true;
  }
  const sent = navigator.sendBeacon(state.prototypeStats.endpoint, new Blob([payload], { type: "application/json" }));
  if (sent) {
    state.prototypeStats.lastPayloadHash = payloadHash;
    state.prototypeStats.lastSubmittedAt = performance.now();
  }
  return sent;
}

const TELEMETRY_HEARTBEAT_INTERVAL_MS = 45 * 1000;
const TELEMETRY_MAX_TICK_MS = 5 * 60 * 1000;
const telemetry = {
  started: false,
  sessionId: "",
  lastTickAt: 0,
  lastSendAt: 0,
  deltas: { foregroundMs: 0, backgroundMs: 0, combatMs: 0, idleMs: 0, totalMs: 0 },
};

function telemetryResetDeltas() {
  telemetry.deltas = { foregroundMs: 0, backgroundMs: 0, combatMs: 0, idleMs: 0, totalMs: 0 };
}

function telemetryEndpoint() {
  const base = leaderboardApiBase();
  return base ? `${base}/telemetry` : "";
}

function telemetryEnabled() {
  // Reuse the same anonymous opt-in as prototype stats.
  return prototypeStatsCanSubmit() && Boolean(telemetryEndpoint());
}

function ensureTelemetrySession() {
  if (telemetry.sessionId) return;
  try {
    telemetry.sessionId = crypto.randomUUID();
  } catch {
    telemetry.sessionId = `s-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
  }
  telemetry.lastTickAt = Date.now();
}

function telemetryIsActiveGameplay() {
  const mode = state.game?.mode;
  if (mode === "mining") return true;
  if (mode === "zone") return Boolean(state.battle?.running);
  return false;
}

function accumulateTelemetry(now = Date.now()) {
  if (!telemetryEnabled()) {
    telemetry.lastTickAt = now;
    telemetryResetDeltas();
    return;
  }
  ensureTelemetrySession();
  if (!telemetry.lastTickAt) {
    telemetry.lastTickAt = now;
    return;
  }
  const elapsed = Math.min(TELEMETRY_MAX_TICK_MS, Math.max(0, now - telemetry.lastTickAt));
  telemetry.lastTickAt = now;
  if (!elapsed) return;
  const foreground = typeof document === "undefined" || document.visibilityState === "visible";
  if (foreground) telemetry.deltas.foregroundMs += elapsed;
  else telemetry.deltas.backgroundMs += elapsed;
  if (telemetryIsActiveGameplay()) telemetry.deltas.combatMs += elapsed;
  else telemetry.deltas.idleMs += elapsed;
  telemetry.deltas.totalMs += elapsed;
}

function sendTelemetry(useBeacon = false, now = Date.now()) {
  if (!telemetryEnabled()) return;
  ensureTelemetrySession();
  accumulateTelemetry(now);
  if (telemetry.deltas.totalMs <= 0) return;
  const endpoint = telemetryEndpoint();
  const payload = JSON.stringify({
    playerId: state.prototypeStats.playerId,
    sessionId: telemetry.sessionId,
    ...telemetry.deltas,
    submittedAt: new Date().toISOString(),
  });
  telemetryResetDeltas();
  telemetry.lastSendAt = now;
  try {
    if (useBeacon && navigator.sendBeacon) {
      navigator.sendBeacon(endpoint, new Blob([payload], { type: "application/json" }));
      return;
    }
    void fetch(endpoint, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: payload,
      keepalive: true,
    }).catch(() => {});
  } catch {
    // Telemetry is best-effort; never disrupt play.
  }
}

function maybeSendTelemetry(now = Date.now()) {
  if (!telemetryEnabled()) return;
  accumulateTelemetry(now);
  if (now - telemetry.lastSendAt >= TELEMETRY_HEARTBEAT_INTERVAL_MS) sendTelemetry(false, now);
}

function startTelemetryHeartbeat() {
  if (telemetry.started) return;
  telemetry.started = true;
  telemetry.lastTickAt = Date.now();
  setInterval(() => accumulateTelemetry(), 1000);
  setInterval(() => maybeSendTelemetry(), TELEMETRY_HEARTBEAT_INTERVAL_MS);
}

function prototypeStatsInt(value, fallback = 0) {
  const number = Math.trunc(Number(value));
  return Number.isFinite(number) ? Math.max(0, number) : fallback;
}

function prototypeStatsCharacterSummaries() {
  captureActiveCharacterState();
  return CHARACTER_SELECT_CLASSES
    .filter((entry) => !entry.disabled)
    .map((entry) => prototypeStatsCharacterSummary(entry.id, state.characters[entry.id]))
    .filter(Boolean);
}

function prototypeStatsCharacterEquipment(character) {
  const equipment = {};
  const slotMap = character?.inventory?.equipment;
  const items = character?.inventory?.items;
  if (!slotMap || !Array.isArray(items)) return equipment;
  for (const slot of EQUIPMENT_SLOTS) {
    const entryId = slotMap[slot.id];
    if (!entryId) continue;
    const entry = items.find((candidate) => candidate.id === entryId);
    if (!entry?.itemId) continue;
    equipment[slot.id] = {
      instanceId: entry.id,
      itemId: entry.itemId,
      smithLevel: Math.max(0, prototypeStatsInt(entry.smithLevel)),
      weaponRefineLevel: Math.max(0, prototypeStatsInt(entry.weaponRefineLevel)),
      gemCount: Math.max(0, prototypeStatsInt(entry.gemCount)),
      empowered: Boolean(entry.empowered),
      empowerTier: Math.max(0, prototypeStatsInt(entry.empowerTier)),
      bonusStats: sanitizeItemBonusStats(entry.bonusStats),
      smithBonusStats: sanitizeSmithBonusStats(entry.smithBonusStats),
      empowerBonusStats: sanitizeItemBonusStats(entry.empowerBonusStats),
      empowerSpellBonuses: sanitizeEmpowerSpellBonuses(entry.empowerSpellBonuses),
    };
  }
  return equipment;
}

function prototypeStatsCharacterSkills(character) {
  const skills = {};
  const learned = character?.magic?.learned;
  if (!learned || typeof learned !== "object") return skills;
  for (const [spellId, info] of Object.entries(learned)) {
    if (!spellId) continue;
    skills[spellId] = Math.max(0, prototypeStatsInt(info?.level));
  }
  return skills;
}

function prototypeStatsCharacterSummary(classId, character) {
  const game = character?.game;
  const progress = game?.progress;
  if (!game || !progress) return null;
  const stats = characterSnapshotTotalStats(classId, character, { includeBuffs: false });
  return {
    characterClass: normalizeCharacterId(classId),
    level: Math.max(1, prototypeStatsInt(progress.level, 1)),
    experience: prototypeStatsInt(progress.experience),
    kills: prototypeStatsInt(game.kills),
    zoneKills: prototypeStatsInt(game.zoneKills),
    gold: prototypeStatsInt(progress.gold ?? character.inventory?.gold),
    activeZoneId: game.activeZoneId ?? null,
    playtimeMs: prototypeStatsInt(game.playtimeMs),
    equipment: prototypeStatsCharacterEquipment(character),
    skills: prototypeStatsCharacterSkills(character),
    stats: {
      hp: prototypeStatsInt(stats.hp),
      maxHp: prototypeStatsInt(stats.maxHp),
      mp: prototypeStatsInt(stats.mp),
      maxMp: prototypeStatsInt(stats.maxMp),
      dc: [prototypeStatsInt(stats.dc?.[0]), prototypeStatsInt(stats.dc?.[1])],
      mc: [prototypeStatsInt(stats.mc?.[0]), prototypeStatsInt(stats.mc?.[1])],
      sc: [prototypeStatsInt(stats.sc?.[0]), prototypeStatsInt(stats.sc?.[1])],
      ac: [prototypeStatsInt(stats.ac?.[0]), prototypeStatsInt(stats.ac?.[1])],
      amc: [prototypeStatsInt(stats.amc?.[0]), prototypeStatsInt(stats.amc?.[1])],
      accuracy: prototypeStatsInt(stats.accuracy),
      agility: prototypeStatsInt(stats.agility),
      luck: prototypeStatsInt(stats.luck),
    },
  };
}

function prototypeStatsSnapshot() {
  const account = accountStatsSnapshot();
  const characters = prototypeStatsCharacterSummaries();
  const totalKills = characters.reduce((sum, character) => sum + character.kills, 0);
  const totalPlaytimeMs = characters.reduce((sum, character) => sum + character.playtimeMs, 0);
  return {
    game: "lom-idle-v2",
    saveVersion: SAVE_VERSION,
    integrityRulesVersion: ITEM_INTEGRITY_RULES_VERSION,
    playerId: state.prototypeStats.playerId,
    activeCharacterId: state.activeCharacterId,
    account,
    characters,
    highestLevel: account.highestCharacterLevel,
    experience: characters.reduce((best, character) => Math.max(best, character.experience), 0),
    kills: totalKills,
    zoneKills: characters.reduce((best, character) => Math.max(best, character.zoneKills), 0),
    bossKills: account.bossKills,
    gold: account.totalGold,
    activeZoneId: state.game.activeZoneId ?? null,
    playtimeMs: totalPlaytimeMs,
    characterCount: characters.length,
  };
}

async function submitPrototypeStats(reason = "manual", now = performance.now()) {
  if (!prototypeStatsCanSubmit()) return false;
  const snapshot = prototypeStatsSnapshot();
  const payloadHash = JSON.stringify(snapshot);
  if (reason !== "enabled" && payloadHash === state.prototypeStats.lastPayloadHash) return false;

  state.prototypeStats.submitting = true;
  state.prototypeStats.lastSubmittedAt = now;
  try {
    const response = await fetch(state.prototypeStats.endpoint, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        ...snapshot,
        reason,
        submittedAt: new Date().toISOString(),
      }),
      keepalive: true,
    });
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    state.prototypeStats.lastPayloadHash = payloadHash;
    state.prototypeStats.statusText = `Anonymous stats submitted: ${snapshot.account.rebirthCount} rebirths, top level ${snapshot.account.highestCharacterLevel}.`;
    sceneSignature = "";
    renderSceneOverlay();
    return true;
  } catch (err) {
    state.prototypeStats.statusText = "Stats upload failed. Progress is still saved locally.";
    console.warn("Unable to submit prototype stats", err);
    sceneSignature = "";
    renderSceneOverlay();
    return false;
  } finally {
    state.prototypeStats.submitting = false;
  }
}

function renderPrototypeStatsNotice() {
  if (!els.prototypeStatsNotice) return;
  if (state.demoImport?.active) {
    els.prototypeStatsNotice.classList.remove("prototype-reset-notice-overlay");
    els.prototypeStatsNotice.hidden = true;
    els.prototypeStatsNotice.innerHTML = "";
    return;
  }
  if (!prototypeStatsNoticeRequired()) {
    if (cloudBackupNoticeRequired()) {
      renderCloudBackupNotice();
      return;
    }
    if (prototypeResetNoticeRequired()) {
      renderPrototypeResetNotice();
      return;
    }

    els.prototypeStatsNotice.classList.remove("prototype-reset-notice-overlay");
    els.prototypeStatsNotice.hidden = true;
    els.prototypeStatsNotice.innerHTML = "";
    return;
  }

  els.prototypeStatsNotice.classList.remove("prototype-reset-notice-overlay");
  els.prototypeStatsNotice.hidden = false;
  els.prototypeStatsNotice.innerHTML = `
    <div class="prototype-stats-notice-window" role="dialog" aria-modal="true" aria-labelledby="prototypeStatsNoticeTitle">
      <h2 id="prototypeStatsNoticeTitle">Anonymous Prototype Stats</h2>
      <p>
        This prototype can submit anonymous per-character gameplay progress such as level, XP, kills, gold, current zone, and playtime so I can tune balance and test leaderboards.
      </p>
      <p>
        No name, email, account, or personal details are sent. You can turn this off now, or later in Options.
      </p>
      <div class="prototype-stats-notice-actions">
        <button type="button" data-disable-prototype-stats>Turn Off</button>
        <button type="button" class="primary" data-accept-prototype-stats>Continue</button>
      </div>
    </div>
  `;
}

