async function selectBattleEnemy(enemyId) {
  resetBattle(enemyId);
  state.enemy.index = state.battle.enemy.monsterIndex;
  state.enemy.action = "standing";
  state.enemy.frame = 0;
  state.enemy.oneShot = false;
  await reloadEnemyAtlas();
  renderEnemyControls();
  render();
}

function startBattle() {
  if (isRoomOnlyZone()) {
    if (!state.battle.player) resetBattleForRoomOnly();
    state.battle.running = false;
    state.battle.phase = "idle";
    ensureMapStampArenaLock();
    return;
  }
  if (!state.battle.player || !state.battle.enemy) resetBattle();
  const zone = activeZone();
  const bossDef = bossRoomDef(zone?.id);
  if (bossDef && bossRespawnRemainingMs(zone.id) > 0) {
    state.battle.running = false;
    state.battle.phase = "victory";
    state.battle.nextEnemySpawnAt = 0;
    pushBattleLog(`${bossDef.bossName} is still respawning.`);
    return;
  }
  stopOneStepTest();
  state.continuousWalk = false;
  state.battle.running = true;
  resetCombatEquipmentLock();
  const now = performance.now();
  state.battle.phase = "advance";
  state.battle.lastMotionAt = now;
  state.battle.travelStartedAt = now;
  state.battle.travelStartedX = state.battle.playerX;
  state.battle.returnToStandAt = 0;
  state.battle.enemyAggro = false;
  state.battle.nextPlayerAttackAt = 0;
  state.battle.nextEnemyAttackAt = 0;
  state.battle.pendingImpact = null;
  state.battle.pendingEnemyStrike = null;
  state.battle.pendingHeal = null;
  state.battle.pendingPoison = null;
  dismissBattleCompanions();
  if ((bossDef || groupDungeonZone(zone)) && beginBossPartyFight(zone.id, now)) return;
  if (applyFixedArenaEnemySpawn(now)) {
    initMapLightningSchedule(now);
    initMapHellFireSchedule(now);
    pushBattleLog(`${state.battle.enemy?.name ?? "The boss"} waits beneath the floor...`);
    return;
  }
  initMapLightningSchedule(now);
  initMapHellFireSchedule(now);
  pushBattleLog("Adventure started.");
  setPlayerAction("walking", now);
}

function stopBattle() {
  if (state.battle.bossParty?.finished) return;
  if (state.battle.bossParty?.active) {
    syncBossPartyControlledMemberFromState(bossPartyLeaderClassId());
    syncBossPartyMembersToCharacters(state.battle.bossParty, { applyControlled: false });
    persistCharacterGameLocation({
      mode: state.game.mode,
      zoneId: state.game.activeZoneId,
      classIds: bossPartyMemberClassIds(),
      running: false,
    });
  } else {
    captureActiveCharacterState();
  }
  state.continuousWalk = false;
  state.battle.running = false;
  state.battle.phase = "idle";
  state.battle.pendingImpact = null;
  state.battle.pendingEnemyStrike = null;
  state.battle.pendingHeal = null;
  state.battle.pendingPoison = null;
  dismissBattleCompanions();
  state.battle.bossParty = null;
  resetCombatEquipmentLock();
  clearGroupDungeonRunState();
  state.battle.groundSpellEffects = [];
  pushBattleLog("Adventure paused.");
}

function startContinuousMovement(action) {
  if (!state.battle.player || !state.battle.enemy) resetBattle();
  const now = performance.now();
  const startX = state.battle.playerX;
  const startCameraX = state.battle.cameraX ?? startX - playerScreenX();
  const startTileCameraX = startCameraX * LANE.tileScrollRatio;
  stopOneStepTest();
  state.continuousWalk = true;
  state.continuousMoveAction = action;
  state.continuousWalkStartedAt = now;
  state.continuousWalkStartX = startX;
  state.continuousWalkStartCameraX = startCameraX;
  state.continuousWalkStartScrollX = movementTestScrollCameraX(startTileCameraX);
  state.showEnemies = false;
  state.battle.running = true;
  state.battle.phase = "advance";
  state.battle.playerX = startX;
  state.battle.cameraX = startCameraX;
  state.battle.lastMotionAt = now;
  state.battle.travelStartedAt = now;
  state.battle.travelStartedX = startX;
  state.battle.enemyAggro = false;
  state.battle.nextPlayerAttackAt = 0;
  state.battle.nextEnemyAttackAt = 0;
  state.battle.pendingImpact = null;
  state.battle.pendingEnemyStrike = null;
  state.battle.pendingHeal = null;
  state.battle.pendingPoison = null;
  dismissBattleCompanions();
  setPlayerAction(action, now);
  const cycleDistance = movementCycleDistance(action);
  pushBattleLog(`Deterministic ${PLAYER_ACTIONS[action].label.toLowerCase()} test started: one cycle equals ${cycleDistance}px.`);
  renderMapControls();
  battlePanelSignature = "";
  render();
}

function stopContinuousWalk() {
  if (!state.continuousWalk) return;
  state.continuousWalk = false;
  state.battle.running = false;
  state.battle.phase = "idle";
  state.battle.pendingImpact = null;
  state.battle.pendingEnemyStrike = null;
  state.battle.pendingHeal = null;
  state.battle.pendingPoison = null;
  dismissBattleCompanions();
  state.battle.groundSpellEffects = [];
  setPlayerAction("standing", performance.now());
  pushBattleLog(`Deterministic ${PLAYER_ACTIONS[state.continuousMoveAction].label.toLowerCase()} test stopped.`);
  renderMapControls();
  battlePanelSignature = "";
  render();
}

function startOneStepTest() {
  if (!state.battle.player || !state.battle.enemy) resetBattle();
  const now = performance.now();
  const test = state.stepTest;
  const startX = state.battle.playerX;
  const startCameraX = state.battle.cameraX ?? startX - playerScreenX();
  const startTileCameraX = startCameraX * LANE.tileScrollRatio;
  const startScrollX = movementTestScrollCameraX(startTileCameraX);

  state.showEnemies = false;
  state.continuousWalk = false;
  state.battle.running = false;
  state.battle.phase = "stepTest";
  state.battle.playerX = startX;
  state.battle.enemyX = enemySpawnDistance();
  state.battle.cameraX = startCameraX;
  state.battle.lastMotionAt = now;
  state.battle.travelStartedAt = now;
  state.battle.travelStartedX = state.battle.playerX;
  state.battle.enemyAggro = false;
  state.battle.nextPlayerAttackAt = 0;
  state.battle.nextEnemyAttackAt = 0;
  state.battle.pendingImpact = null;
  state.battle.pendingEnemyStrike = null;
  state.battle.pendingHeal = null;
  state.battle.pendingPoison = null;
  state.battle.activeSkill = "None";
  state.battle.activeSkillAtlas = null;
  state.battle.activeWizardSpell = null;
  state.battle.activeWizardSpellAtlas = null;
  state.battle.activeTaoSpell = null;
  state.battle.activeTaoSpellAtlas = null;
  state.enemy.action = "standing";
  state.enemy.frame = 0;
  state.enemy.oneShot = false;

  test.active = true;
  test.complete = false;
  test.startAt = now;
  test.startX = state.battle.playerX;
  test.startCameraX = startCameraX;
  test.startScrollX = startScrollX;
  test.durationMs = WALK_CYCLE_MS;
  test.distancePx = LANE_TILE_PX;

  state.spell = "None";
  state.spellAtlas = null;
  state.action = "walking";
  state.frame = 0;
  state.playerOneShot = false;
  state.lastTick = now;
  pushBattleLog(`One-step test: ${LANE_TILE_PX}px tile over ${WALK_CYCLE_MS}ms from the current backdrop position.`);
  renderMapControls();
  updateActionButtons();
  battlePanelSignature = "";
  render();
}

function stopOneStepTest() {
  if (!state.stepTest.active && !state.stepTest.complete) return;
  state.stepTest.active = false;
  state.stepTest.complete = false;
  if (state.battle.phase === "stepTest") state.battle.phase = "idle";
}

const BATTLE_LOG_MAX_LINES = 12;
const ACTIVITY_LOG_ROUTINE_ATTACK_SPELLS = [
  "FireBall",
  "Great FireBall",
  "GreatFireBall",
  "ThunderBolt",
  "Ice Storm",
  "IceStorm",
  "Flame Field",
  "FlameField",
  "FireWall",
  "Firewall",
  "Soul Fire Ball",
  "SoulFireBall",
  "Blizzard",
  "Meteor Strike",
  "MeteorStrike",
  "Flame Disruptor",
  "FlameDisruptor",
];

function pushBattleLog(text) {
  const line = String(text ?? "").trim();
  if (!line || !shouldShowActivityLogLine(line)) return;
  if (state.battle.log[0] === line) return;
  state.battle.log.unshift(line);
  state.battle.log = state.battle.log.slice(0, BATTLE_LOG_MAX_LINES);
}

function shouldShowActivityLogLine(line) {
  if (line.startsWith(COMBAT_LOG_SUMMARY_PREFIX)) return false;
  if (/burns on the ground/i.test(line)) return false;
  if (isRoutineDamageActivityLine(line)) return false;
  if (isRoutineAttackCastActivityLine(line)) return false;
  return true;
}

function isRoutineDamageActivityLine(line) {
  if (/\bmiss(?:es|ed)?\b/i.test(line)) return true;
  if (/\b(?:hit|hits|strikes|burns)\b.+\bfor\s+\d+/i.test(line)) return true;
  if (/\bfor\s+\d+\s+damage\b/i.test(line)) return true;
  if (/Lightning strikes .+ for \d+/i.test(line)) return true;
  if (/Twin Drake Blade hits .+ again for \d+/i.test(line)) return true;
  if (/\bswings\b.+\bbut misses\b/i.test(line)) return true;
  return false;
}

function isRoutineAttackCastActivityLine(line) {
  if (!/\bcasts?\b/i.test(line)) return false;
  if (/\b(?:Poison|Healing|MassHealing|Mass Healing|SoulShield|BlessedArmour|UltimateEnhancer|PetEnhancer|MagicShield|MagicBooster|Mirroring|Summon|Skeleton|Shinsu|Holy Deva|Fury|Protection Field|ProtectionField|Immortal Skin|ImmortalSkin)\b/i.test(line)) {
    return false;
  }
  return ACTIVITY_LOG_ROUTINE_ATTACK_SPELLS.some((spell) => line.includes(spell));
}

function pushRecentLoot(text) {
  state.game.recentLoot.unshift(String(text));
  state.game.recentLoot = state.game.recentLoot.slice(0, 6);
}

function combatPlayableZones() {
  return PROTOTYPE_ZONES.filter((zone) => !zone.miningOnly && !zone.trainingRoom && !zone.roomOnly);
}

function isRoomOnlyZone(zone = activeZone()) {
  return Boolean(zone?.roomOnly);
}

function isTrainingRoomZone(zone = activeZone()) {
  return Boolean(zone?.trainingRoom);
}

function trainingRoomEnemyTemplate(zone = activeZone()) {
  const enemyId = zone?.enemyIds?.[0];
  return ENEMY_TEMPLATES.find((enemy) => enemy.id === enemyId) ?? ENEMY_TEMPLATES[0];
}

function isTrainingDummyEnemy(enemy = state.battle?.enemy) {
  return Boolean(enemy?.trainingDummy);
}

function reduceEnemyHp(enemy, damage) {
  if (!enemy || damage <= 0) return;
  if (isTrainingDummyEnemy(enemy)) return;
  enemy.hp = Math.max(0, enemy.hp - damage);
  maybeTriggerEnemyEnrage(enemy);
}

function trainingRoomCastGapMs(_spell, _learned) {
  // Academy cycles practice casts — not each spell's combat cooldown (Fury is ~10 min).
  // Pace by attack speed so Fury's AS boost actually speeds training here too.
  return Math.max(
    CRYSTAL_PLAYER_ACTION_LOCK_MS,
    Math.min(CRYSTAL_SPELL_GLOBAL_LOCK_MS, attackDelayMs(effectivePlayerAttackSpeed(), playerCombatLevel())),
  );
}

function isTrainingRoomCombat() {
  const battle = state.battle;
  return isTrainingRoomZone()
    && battle.running
    && !battle.bossParty?.active
    && Boolean(battle.enemy);
}

function trainingRoomAutocastEntries() {
  const classId = state.battle.combatClass;
  // Training room cycles every spell the player toggled Auto on — not combat's autocast slot cap.
  return combatAutoCastSpells(classId)
    .map((spell) => ({ spell, learned: learnedMagic(spell.id) }))
    .filter(({ spell, learned }) => learned?.autoCast && !spell.passive)
    .sort((a, b) => autoCastPriorityForClass(classId, a.spell) - autoCastPriorityForClass(classId, b.spell));
}

function trainingRoomSpendMp(spell, learned, cost) {
  const battle = state.battle;
  battle.player.mp = Math.max(0, battle.player.mp - cost);
  if (learned) learned.castReadyAt = 0;
  battle.wizardSpellLockUntil = 0;
  if (spell?.id) clearQueuedCombatSpell(spell.id);
}

function trainingRoomPlayCastVisual(spell, now) {
  const battle = state.battle;
  battle.pendingImpact = null;
  battle.pendingDefenceBuff = null;
  battle.pendingWizardBuff = null;
  battle.pendingMassHeal = null;
  battle.pendingHeal = null;
  battle.pendingPoison = null;
  battle.pendingUltimateEnhancer = null;
  battle.pendingPetEnhancer = null;
  battle.pendingPetAttack = null;
  battle.pendingTaoPet = null;
  battle.activeWizardSpell = null;
  battle.activeWizardSpellAtlas = null;
  battle.activeTaoSpell = null;
  battle.activeTaoSpellAtlas = null;
  battle.activeSkill = "None";
  battle.activeSkillAtlas = null;

  const bodyAction = spell.bodyAction ?? "spell";
  if (battle.combatClass === "Warrior") {
    battle.activeSkill = spell.id;
    battle.activeSkillAtlas = state.warriorSkillAtlases[spell.id] ?? null;
    battle.activeSkillStartedAt = now;
    setPlayerAction(bodyAction, now, true);
    if (spell.id === "BladeAvalanche") queueBladeAvalancheLaneFx(now, battle.playerX);
    return;
  }
  if (battle.combatClass === "Wizard") {
    battle.activeWizardSpell = spell.id;
    battle.activeWizardSpellAtlas = state.wizardSpellAtlases[spell.id] ?? null;
    battle.activeWizardSpellStartedAt = now;
    setPlayerAction(bodyAction, now, true);
    return;
  }
  battle.activeTaoSpell = spell.id;
  battle.activeTaoSpellAtlas = state.taoistSpellAtlases[spell.id] ?? null;
  battle.activeTaoSpellStartedAt = now;
  setPlayerAction(bodyAction, now, true);
}

function trainingRoomCastWarrior(spell, learned, cost, now) {
  const battle = state.battle;
  // Toggle attack skills (Half Moon, Thrusting) are not charge casts — train via the
  // generic swing path below. Do not bail out on spell.toggle here.

  if (spell.id === "TwinDrakeBlade") {
    if (warriorTwinDrakeReady()) {
      trainingRoomSpendMp(spell, learned, cost);
      clearTwinDrakeChargeState(battle);
      levelWarriorMagic(spell, learned, now);
      trainingRoomPlayCastVisual(spell, now);
      playWarriorSpellSwingSfx(spell, { volume: 0.5 });
      setEnemyAction("struck", true, now);
      playMonsterSfx("flinch");
      return true;
    }
    if (!isWarriorChargeSkill(spell)) return false;
    trainingRoomSpendMp(spell, learned, cost);
    applyTwinDrakeChargeState(battle, now);
    levelWarriorMagic(spell, learned, now);
    trainingRoomPlayCastVisual(spell, now);
    pushBattleLog(`${spell.label} readied for the next attack.`);
    return true;
  }

  if (spell.id === "FlamingSword") {
    if (warriorFlamingSwordReady()) {
      trainingRoomSpendMp(spell, learned, 0);
      clearFlamingSwordChargeState(battle);
      levelWarriorMagic(spell, learned, now);
      trainingRoomPlayCastVisual(spell, now);
      playWarriorSpellSwingSfx(spell, { volume: 0.5 });
      setEnemyAction("struck", true, now);
      playMonsterSfx("flinch");
      return true;
    }
    if (!isWarriorChargeSkill(spell)) return false;
    trainingRoomSpendMp(spell, learned, cost);
    applyFlamingSwordChargeState(battle, now);
    learned.castReadyAt = now + spellDelayMs(spell, learned);
    trainingRoomPlayCastVisual(spell, now);
    pushBattleLog(`${spell.label} readied for the next attack.`);
    return true;
  }

  if (isWarriorChargeSkill(spell)) {
    trainingRoomSpendMp(spell, learned, cost);
    levelWarriorMagic(spell, learned, now);
    trainingRoomPlayCastVisual(spell, now);
    pushBattleLog(`${spell.label} readied for the next attack.`);
    return true;
  }

  if (spell.buff) {
    if (spell.id === "Fury" || spell.id === "Rage" || spell.id === "ProtectionField" || spell.id === "ImmortalSkin") {
      if (spell.id === "Fury" && hasActiveFuryBuff(battle.player, now)) return false;
      if (spell.id === "Rage" && hasActiveRageBuff(battle.player, now)) return false;
      if (spell.id === "ProtectionField" && hasActiveProtectionFieldBuff(battle.player, now)) return false;
      if (spell.id === "ImmortalSkin" && hasActiveImmortalSkinBuff(battle.player, now)) return false;
      trainingRoomSpendMp(spell, learned, cost);
      applyWarriorCombatBuffToEntity(battle.player, spell, learned, now);
      trainingRoomPlayCastVisual(spell, now);
      playWarriorSpellSwingSfx(spell, { volume: 0.5 });
      return true;
    }
    return false;
  }

  trainingRoomSpendMp(spell, learned, cost);
  levelWarriorMagic(spell, learned, now);
  trainingRoomPlayCastVisual(spell, now);
  playWarriorSpellSwingSfx(spell, { volume: 0.5 });
  setEnemyAction("struck", true, now);
  playMonsterSfx("flinch");
  return true;
}

function trainingRoomCastWizard(spell, learned, cost, now) {
  const battle = state.battle;

  if (spell.id === "MagicShield") {
    trainingRoomSpendMp(spell, learned, cost);
    const applied = applyDefenceBuffEffect(spell, learned, battle.player, now);
    startMagicShieldLoopFx({ expiresAt: now + applied.durationMs, now });
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    return true;
  }

  if (spell.id === "MagicBooster") {
    trainingRoomSpendMp(spell, learned, cost);
    applyMagicBoosterEffect(spell, learned, battle.player, now);
    levelMagicSkill(spell, learned, now);
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    return true;
  }

  if (spell.id === "Mirroring") {
    if (battle.wizardMirror?.active) dismissWizardMirror();
    trainingRoomSpendMp(spell, learned, cost);
    levelMagicSkill(spell, learned, now);
    battle.wizardMirror = createWizardMirror(learned.level, now);
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    return true;
  }

  trainingRoomSpendMp(spell, learned, cost);
  levelMagicSkill(spell, learned, now);
  trainingRoomPlayCastVisual(spell, now);
  playSpellSfx(spell.id, "cast");

  if (spell.impactMode === "ground") {
    const value = rollWizardMagicValue(spell, learned, battle.player);
    createWizardGroundSpellEffect(spell, { value, worldX: battle.enemyX }, now);
  } else {
    setEnemyAction("struck", true, now);
    playMonsterSfx("flinch");
  }
  return true;
}

function trainingRoomCastTaoist(spell, learned, cost, now) {
  const battle = state.battle;

  if (spell.id === "Healing") {
    trainingRoomSpendMp(spell, learned, cost);
    levelMagicSkill(spell, learned, now);
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    return true;
  }

  if (spell.id === "SoulShield" || spell.id === "BlessedArmour") {
    const entry = amuletCandidate(0);
    const item = entry ? itemDefinition(entry.itemId) : null;
    if (!entry || !isTaoistAmuletItem(item) || !consumeOneInventoryUnit(entry.id)) return false;
    trainingRoomSpendMp(spell, learned, cost);
    applyDefenceBuffEffect(spell, learned, battle.player, now);
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    return true;
  }

  if (spell.id === "EnergyShield") {
    trainingRoomSpendMp(spell, learned, cost);
    applyEnergyShieldEffect(spell, learned, battle.player, battle.player, now);
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    return true;
  }

  if (spell.id === "MassHealing") {
    trainingRoomSpendMp(spell, learned, cost);
    levelMagicSkill(spell, learned, now);
    const applied = applyTaoistMassHealEffect(spell, learned, battle.player, now, { levelSkill: false });
    if (applied) showTaoistMassHealTexts(spell, applied, now);
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    return true;
  }

  if (spell.id === "HealingCircle") {
    trainingRoomSpendMp(spell, learned, cost);
    levelMagicSkill(spell, learned, now);
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    const skillLevel = Math.max(0, Math.min(3, Math.trunc(Number(learned?.level) || 0)));
    const centerTile = healingCircleCenterTile();
    createWizardGroundSpellEffect(spell, {
      value: skillLevel,
      worldX: centerTile.worldX,
      centerTile,
    }, now);
    return true;
  }

  if (spell.id === "UltimateEnhancer") {
    const targets = ultimateEnhancerTargets(now);
    if (!targets.length) return false;
    const entry = amuletCandidate(0);
    const item = entry ? itemDefinition(entry.itemId) : null;
    if (!entry || !isTaoistAmuletItem(item) || !consumeOneInventoryUnit(entry.id)) return false;
    trainingRoomSpendMp(spell, learned, cost);
    applyUltimateEnhancerToTargets(spell, learned, battle.player, targets, now);
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    return true;
  }

  if (spell.id === "PetEnhancer") {
    const pet = activeTaoistPet(now);
    if (!pet) return false;
    trainingRoomSpendMp(spell, learned, cost);
    const applied = applyPetEnhancerToPet(spell, learned, battle.player, pet, now);
    if (!applied) return false;
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    queuePetEnhancerImpactFx(spell, now, { soundPlayed: true });
    return true;
  }

  if (spell.id === "SummonSkeleton" || spell.id === "SummonShinsu" || spell.id === "SummonHolyDeva") {
    const amuletCost = taoistSummonAmuletCost(spell.id);
    const entry = amuletCandidate(0);
    const item = entry ? itemDefinition(entry.itemId) : null;
    if (!entry || !isTaoistAmuletItem(item) || amuletInventoryCount() < amuletCost) return false;
    if (!consumeAmuletInventoryUnits(amuletCost)) return false;
    if (battle.taoPet?.active) dismissTaoistPet();
    trainingRoomSpendMp(spell, learned, cost);
    levelMagicSkill(spell, learned, now);
    battle.taoPet = createTaoistSummonPet(spell.id, learned.level, now);
    state.taoPetAtlas = taoPetAtlasFor(battle.taoPet);
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    return true;
  }

  if (spell.id === "Poisoning") {
    const entry = poisonCandidateForEnemy(battle.enemy, now);
    const item = entry ? itemDefinition(entry.itemId) : null;
    if (!entry || !isPoisonItem(item) || !consumeOneInventoryUnit(entry.id)) return false;
    trainingRoomSpendMp(spell, learned, cost);
    levelMagicSkill(spell, learned, now);
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    return true;
  }

  if (spell.id === "PoisonCloud") {
    if (amuletInventoryCount() < POISON_CLOUD_AMULET_COST || poisonInventoryCount("green") < POISON_CLOUD_GREEN_POISON_COST) return false;
    if (!consumeAmuletInventoryUnits(POISON_CLOUD_AMULET_COST) || !consumeGreenPoisonUnits(POISON_CLOUD_GREEN_POISON_COST)) return false;
    trainingRoomSpendMp(spell, learned, cost);
    levelMagicSkill(spell, learned, now);
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    return true;
  }

  if (spell.id === "Plague") {
    if (amuletInventoryCount() < PLAGUE_AMULET_COST) return false;
    const poisonCandidate = plaguePoisonCandidateForCast();
    if (!consumePlagueCastSupplies(poisonCandidate)) return false;
    trainingRoomSpendMp(spell, learned, cost);
    levelMagicSkill(spell, learned, now);
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    setEnemyAction("struck", true, now);
    playMonsterSfx("flinch");
    return true;
  }

  if (spell.id === "Curse") {
    if (amuletInventoryCount() < CURSE_AMULET_COST) return false;
    if (!consumeAmuletInventoryUnits(CURSE_AMULET_COST)) return false;
    trainingRoomSpendMp(spell, learned, cost);
    if (rollCurseCastProceeds(learned?.level)) {
      const durationMs = curseDurationMs(spell, learned, state.battle.player);
      applyCurseToEnemy(state.battle.enemy, durationMs, curseOffenceReductionPercent(learned?.level), now);
      levelMagicSkill(spell, learned, now);
    }
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    return true;
  }

  if (spell.id === "SoulFireBall") {
    const entry = amuletCandidate(0);
    const item = entry ? itemDefinition(entry.itemId) : null;
    if (!entry || !isTaoistAmuletItem(item) || !consumeOneInventoryUnit(entry.id)) return false;
    trainingRoomSpendMp(spell, learned, cost);
    levelMagicSkill(spell, learned, now);
    trainingRoomPlayCastVisual(spell, now);
    playSpellSfx(spell.id, "cast");
    setEnemyAction("struck", true, now);
    playMonsterSfx("flinch");
    return true;
  }

  return false;
}

function trainingRoomTryCast(spell, learned, now) {
  if (!spell || !learned) return false;
  const cost = effectiveSpellMpCost(spell, learned);
  if ((state.battle.player?.mp ?? 0) < cost) return false;

  const classId = state.battle.combatClass;
  if (classId === "Warrior") return trainingRoomCastWarrior(spell, learned, cost, now);
  if (classId === "Wizard") return trainingRoomCastWizard(spell, learned, cost, now);
  if (classId === "Taoist") return trainingRoomCastTaoist(spell, learned, cost, now);
  return false;
}

function tryTrainingRoomAutocastCycle(now) {
  const entries = trainingRoomAutocastEntries();
  if (!entries.length) return false;

  const battle = state.battle;
  const startIndex = battle.trainingRoomSpellIndex ?? 0;
  for (let offset = 0; offset < entries.length; offset += 1) {
    const entry = entries[(startIndex + offset) % entries.length];
    if (trainingRoomTryCast(entry.spell, entry.learned, now)) {
      battle.trainingRoomSpellIndex = (startIndex + offset + 1) % entries.length;
      sceneSignature = "";
      battlePanelSignature = "";
      combatSkillBarSignature = "";
      return entry;
    }
  }
  return null;
}

function updateTrainingRoomBattle(now) {
  const battle = state.battle;
  if (!battle.running || !battle.player || battle.player.hp <= 0 || !battle.enemy) return;

  updateWarriorChargeExpiry(now);
  updateDefenceBuffFx(now);
  updateMassHealFx(now);
  updateAttachedSpellFx(now);
  updatePendingWizardMirror(now);
  updateWizardMirror(now);
  updateGroundSpellEffects(now);
  updateLaneMotion(now);

  if (battle.phase !== "engaged") return;

  if (now < (battle.trainingRoomNextCastAt ?? 0)) return;

  const cast = tryTrainingRoomAutocastCycle(now);
  if (cast) {
    const gap = trainingRoomCastGapMs(cast.spell, cast.learned);
    battle.trainingRoomNextCastAt = now + gap;
    battle.nextPlayerAttackAt = battle.trainingRoomNextCastAt;
    battle.lastPlayerAttackCooldownMs = gap;
    return;
  }

  battle.trainingRoomNextCastAt = now + CRYSTAL_SPELL_GLOBAL_LOCK_MS;
}

function rollMiningOreItemId() {
  return rollMiningOreItemIdCore(MINING_ORE_DROPS, MINING_TOTAL_SLOTS);
}

function rollMiningOrePurity() {
  return rollMiningOrePurityCore(undefined, 10, rebirthMiningMinPurity());
}

function tryAddMiningOre(itemId, purity) {
  syncInventoryCapacity();
  ensureInventorySlots();
  recordCodexDrop(itemId, codexDropSource({ kind: "mining" }));
  if (inventoryUsedSlots() >= state.inventory.maxSlots) {
    const item = itemDefinition(itemId);
    addLootNotice(`Inventory full: ${item?.name ?? itemId}`, "full");
    return false;
  }
  state.inventory.items.push(createOreInventoryEntry(itemId, purity));
  syncBossPartyControlledInventoryFromState();
  gamePanelSignature = "";
  sceneSignature = "";
  hotbarSignature = "";
  return true;
}

function updateMining(now) {
  if (state.game.mode !== "mining" || state.paused) return false;
  updateBattleRestState(now);
  return false;
}

function rollMiningOreOnSwing() {
  if (state.game.mode !== "mining") return;
  playMiningHitSfx();
  if (Math.random() >= MINING_HIT_CHANCE) {
    pushBattleLog("Swing... nothing.");
    return;
  }
  const itemId = rollMiningOreItemId();
  const purity = rollMiningOrePurity();
  const item = itemDefinition(itemId);
  if (!tryAddMiningOre(itemId, purity)) {
    pushBattleLog("Inventory full.");
    return;
  }
  const label = item ? `${item.name} (Purity ${purity})` : itemId;
  pushBattleLog(`Mined ${label}.`);
  pushRecentLoot(label);
  addLootNotice(`Mined ${item?.name ?? itemId}`, "item");
}

function miningSpotById(spotId) {
  const id = String(spotId ?? "").trim();
  return MINING_SPOTS.find((spot) => spot.id === id) ?? null;
}

function pickRandomMiningSpot() {
  const spot = MINING_SPOTS[Math.floor(Math.random() * MINING_SPOTS.length)];
  state.game.miningSpotId = spot.id;
  return spot;
}

function activeMiningSpot() {
  if (state.game.mode !== "mining") return null;
  return miningSpotById(state.game.miningSpotId) ?? pickRandomMiningSpot();
}

function ensureMiningSpotId(forcePick = false) {
  if (state.game.mode !== "mining") return null;
  if (!forcePick && miningSpotById(state.game.miningSpotId)) {
    return miningSpotById(state.game.miningSpotId);
  }
  return pickRandomMiningSpot();
}

function enterMiningFromRefiner() {
  if (bossPartyOnField()) return;
  captureActiveCharacterState();
  closeScene(false);
  stopOneStepTest();
  state.continuousWalk = false;
  state.zoneBuilderPreviewZoneId = null;
  state.showEnemies = true;
  state.game.mode = "mining";
  state.game.activeZoneId = MINING_ZONE_ID;
  state.game.zoneKills = 0;
  state.game.distance = 0;
  state.game.selectedTownNpcId = null;
  const spot = pickRandomMiningSpot();
  resetBattle();
  ensureMapStampArenaLock();
  state.battle.cameraX = state.battle.playerX - playerScreenX();
  state.battle.enemy = null;
  state.battle.running = false;
  state.battle.phase = "idle";
  state.battle.returnToStandAt = 0;
  restorePendingSavedPlayerResources();
  state.battle.log = [`Mining at ${spot?.label ?? activeZone()?.label ?? "the mines"}.`];
  applyEquippedVisualIndexes();
  queueVisualAtlasReload(["weapon"]);
  setPlayerAction("mine", performance.now(), true);
  playSfx("ui.teleport", { volume: 0.55, throttleMs: 300 });
  persistCharacterGameLocation({ mode: "mining", zoneId: MINING_ZONE_ID, classIds: CHARACTER_IDS, running: false });
  renderMapControls();
  gamePanelSignature = "";
  battlePanelSignature = "";
  render();
}

function seedStarterInventory() {
  if (state.inventory.items.length) return;
  addInventoryItem("wooden-sword");
  addInventoryItem("base-dress");
  addInventoryItem("hp-drug-small", 5);
  addInventoryItem("mp-drug-small", 5);
}

function inventoryPageCount() {
  return Math.max(1, Math.ceil(INVENTORY_MAX_SLOTS / INVENTORY_PAGE_SIZE));
}

function syncInventoryCapacity(inventory = state.inventory) {
  if (!inventory) return;
  // Usable pages are derived purely from the two independent unlock flags, so a
  // paid page can never be lost or accidentally re-locked.
  const gold = inventoryGoldPageUnlocked(inventory) ? 1 : 0;
  const token = inventory.tokenPageUnlocked ? 1 : 0;
  const pages = Math.max(1, Math.min(inventoryPageCount(), 1 + gold + token));
  inventory.pagesUnlocked = pages;
  inventory.maxSlots = Math.min(INVENTORY_MAX_SLOTS, pages * INVENTORY_PAGE_SIZE);
  if (inventory === state.inventory && state.inventoryPage >= pages) {
    state.inventoryPage = pages - 1;
  }
}

// The 100k-gold page and the 250-token page are tracked as independent flags
// (mirroring storage's page2Purchased). Legacy saves that only stored a page
// count are migrated in sanitizeInventoryState.
function inventoryGoldPageUnlocked(inventory = state.inventory) {
  if (!inventory) return false;
  if (typeof inventory.goldPageUnlocked === "boolean") return inventory.goldPageUnlocked;
  return (Math.trunc(Number(inventory.pagesUnlocked) || 1) - (inventory.tokenPageUnlocked ? 1 : 0)) >= 2;
}

// Ordered tab descriptors: base page, then unlocked extras, then locked
// purchase tabs. Extras are listed gold-first so a still-locked token page is
// always the LAST tab; once the token page is bought it becomes an unlocked
// extra and packs to the front.
function inventoryPageDescriptors() {
  syncInventoryCapacity();
  const token = Boolean(state.inventory.tokenPageUnlocked);
  const gold = inventoryGoldPageUnlocked();
  const extras = [
    { type: "gold", unlocked: gold },
    { type: "token", unlocked: token },
  ];
  const tabs = [{ type: "base", unlocked: true }];
  for (const extra of extras) if (extra.unlocked) tabs.push({ type: extra.type, unlocked: true });
  for (const extra of extras) if (!extra.unlocked) tabs.push({ type: extra.type, unlocked: false });
  return tabs.slice(0, inventoryPageCount()).map((tab, index) => ({ ...tab, index }));
}

function inventoryPageIndexForType(type) {
  const found = inventoryPageDescriptors().find((tab) => tab.unlocked && tab.type === type);
  return found ? found.index : Math.max(0, state.inventory.pagesUnlocked - 1);
}

function syncBossPartyInventoryCapacityFromState(classId = state.activeCharacterId) {
  syncBossPartyControlledInventoryFromState(classId);
}

function syncBossPartyControlledInventoryFromState(classId = bossPartyLeaderClassId()) {
  const party = state.battle.bossParty;
  if (!party?.members?.length) return;
  const leaderClassId = bossPartyLeaderClassId(party);
  const member = party.members.find((candidate) => candidate.classId === classId);
  if (!member || classId !== leaderClassId) return;
  if (normalizeCharacterId(state.activeCharacterId) !== leaderClassId) return;
  member.inventory = cloneInventoryState(state.inventory);
  member.hotbar = cloneHotbarState(state.hotbar);
  ensureBossPartyInventorySlots(member);
}

function syncBossPartyControlledInventoryToState(classId = bossPartyLeaderClassId()) {
  const party = state.battle.bossParty;
  if (!party?.members?.length) return;
  const leaderClassId = bossPartyLeaderClassId(party);
  const member = party.members.find((candidate) => candidate.classId === classId);
  if (!member || classId !== leaderClassId) return;
  state.inventory = cloneInventoryState(member.inventory);
  state.hotbar = cloneHotbarState(member.hotbar);
  state.magic = cloneMagicState(member.magic);
  state.game.progress.gold = member.inventory.gold;
  state.battle.gold = member.inventory.gold;
}

function mergeBossPartyMemberSpellCooldowns(member, magicState) {
  if (!member?.magic?.learned || !magicState?.learned) return;
  for (const [spellId, memberLearned] of Object.entries(member.magic.learned)) {
    const liveLearned = magicState.learned[spellId];
    if (!liveLearned) continue;
    const memberReady = Number(memberLearned.castReadyAt) || 0;
    const liveReady = Number(liveLearned.castReadyAt) || 0;
    if (memberReady > liveReady) liveLearned.castReadyAt = memberReady;
  }
}

function syncBossPartyControlledMemberFromState(classId = bossPartyLeaderClassId()) {
  syncBossPartyControlledInventoryFromState(classId);
  const party = state.battle.bossParty;
  if (!party?.members?.length) return;
  const leaderClassId = bossPartyLeaderClassId(party);
  const member = party.members.find((candidate) => candidate.classId === classId);
  if (!member || classId !== leaderClassId) return;
  if (normalizeCharacterId(state.activeCharacterId) !== leaderClassId) return;
  mergeBossPartyMemberSpellCooldowns(member, state.magic);
  member.magic = cloneMagicState(state.magic);
  syncBossPartyControlledRecoveryFromState(member);
}

function syncBossPartyControlledMemberToState(classId = bossPartyLeaderClassId()) {
  syncBossPartyControlledInventoryToState(classId);
  syncBossPartyControlledRecoveryToState(
    state.battle.bossParty?.members.find((candidate) => candidate.classId === classId) ?? null,
  );
}

function syncBossPartyControlledRecoveryFromState(member = bossPartyLeaderMember()) {
  if (!member || member.classId !== bossPartyLeaderClassId()) return;
  member.potHealthAmount = Math.max(0, Math.trunc(Number(state.battle.potHealthAmount) || 0));
  member.potManaAmount = Math.max(0, Math.trunc(Number(state.battle.potManaAmount) || 0));
  member.potTickAt = state.battle.potTickAt ?? 0;
  member.healAmount = Math.max(0, Math.trunc(Number(state.battle.healAmount) || 0));
  member.healTickAt = state.battle.healTickAt ?? 0;
  member.vampAmount = Math.max(0, Math.trunc(Number(state.battle.vampAmount) || 0));
  member.vampTickAt = state.battle.vampTickAt ?? 0;
  member.autoPotionReadyAt = {
    hp: state.battle.autoPotionReadyAt?.hp ?? 0,
    mp: state.battle.autoPotionReadyAt?.mp ?? 0,
  };
}

function syncBossPartyControlledRecoveryToState(member = bossPartyLeaderMember()) {
  if (!member || member.classId !== bossPartyLeaderClassId()) return;
  state.battle.potHealthAmount = Math.max(0, Math.trunc(Number(member.potHealthAmount) || 0));
  state.battle.potManaAmount = Math.max(0, Math.trunc(Number(member.potManaAmount) || 0));
  state.battle.potTickAt = member.potTickAt ?? 0;
  state.battle.healAmount = Math.max(0, Math.trunc(Number(member.healAmount) || 0));
  state.battle.healTickAt = member.healTickAt ?? 0;
  state.battle.vampAmount = Math.max(0, Math.trunc(Number(member.vampAmount) || 0));
  state.battle.vampTickAt = member.vampTickAt ?? 0;
  state.battle.autoPotionReadyAt = {
    hp: member.autoPotionReadyAt?.hp ?? 0,
    mp: member.autoPotionReadyAt?.mp ?? 0,
  };
}

function inventoryPageUnlocked(page) {
  syncInventoryCapacity();
  return page >= 0 && page < state.inventory.pagesUnlocked;
}

// Buys the 100,000-gold inventory page (whichever locked "gold" tab is showing).
function unlockInventoryGoldPage() {
  syncInventoryCapacity();
  if (inventoryGoldPageUnlocked() || state.inventory.pagesUnlocked >= inventoryPageCount()) return false;
  const cost = INVENTORY_PAGE_2_UNLOCK_COST;
  if (state.inventory.gold < cost) {
    pushBattleLog(`Need ${cost.toLocaleString()} gold to unlock another inventory page.`);
    battlePanelSignature = "";
    renderBattlePanel();
    return false;
  }
  state.inventory.gold -= cost;
  state.game.progress.gold = state.inventory.gold;
  state.battle.gold = state.inventory.gold;
  state.inventory.goldPageUnlocked = true;
  syncInventoryCapacity();
  ensureInventorySlots();
  syncBossPartyInventoryCapacityFromState();
  state.inventoryPage = inventoryPageIndexForType("gold");
  pushBattleLog("Unlocked another inventory page.");
  playSfx("ui.gold", { volume: 0.55, throttleMs: 80 });
  sceneSignature = "";
  gamePanelSignature = "";
  battlePanelSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  renderBattlePanel();
  return true;
}

// Buys the 250-token inventory page for the active character (server-authoritative).
function confirmInventoryTokenPageUnlock() {
  state.pendingInventoryTokenUnlock = false;
  const classId = normalizeCharacterId(state.activeCharacterId);
  purchasePageUnlock(inventoryPageUnlockKey(classId), () => {
    state.inventory.tokenPageUnlocked = true;
    const stored = state.characters?.[classId]?.inventory;
    if (stored) stored.tokenPageUnlocked = true;
    syncInventoryCapacity();
    ensureInventorySlots();
    syncBossPartyInventoryCapacityFromState();
    state.inventoryPage = inventoryPageIndexForType("token");
    pushBattleLog("Unlocked a new inventory page with tokens.");
    playSfx("ui.gold", { volume: 0.55, throttleMs: 80 });
    gamePanelSignature = "";
    battlePanelSignature = "";
    renderGamePanel();
    renderBattlePanel();
    saveGameState(true);
  });
}

function storagePageCount() {
  return Math.max(1, Math.ceil(STORAGE_MAX_SLOTS / STORAGE_PAGE_SIZE));
}

function syncStorageCapacity(storage = state.account.storage) {
  if (!storage) return;
  // Storage pages are fully derived from the two independent unlock flags:
  // the 1,000,000-gold page (page2Purchased) and the 250-token page.
  const pages = Math.max(1, Math.min(
    storagePageCount(),
    1 + (storage.page2Purchased ? 1 : 0) + (storage.tokenPageUnlocked ? 1 : 0),
  ));
  storage.pagesUnlocked = pages;
  storage.maxSlots = Math.min(STORAGE_MAX_SLOTS, pages * STORAGE_PAGE_SIZE);
  if (storage === state.account.storage && state.storagePage >= pages) {
    state.storagePage = pages - 1;
  }
}

function storagePageUnlocked(page) {
  syncStorageCapacity();
  return page >= 0 && page < state.account.storage.pagesUnlocked;
}

// Ordered storage tab descriptors, mirroring inventory: base page, unlocked
// extras, then locked purchase tabs. Gold-first so a still-locked token page is
// always the LAST tab; a bought token page packs to the front.
function storagePageDescriptors() {
  syncStorageCapacity();
  const token = Boolean(state.account.storage.tokenPageUnlocked);
  const gold = Boolean(state.account.storage.page2Purchased);
  const extras = [
    { type: "gold", unlocked: gold },
    { type: "token", unlocked: token },
  ];
  const tabs = [{ type: "base", unlocked: true }];
  for (const extra of extras) if (extra.unlocked) tabs.push({ type: extra.type, unlocked: true });
  for (const extra of extras) if (!extra.unlocked) tabs.push({ type: extra.type, unlocked: false });
  return tabs.slice(0, storagePageCount()).map((tab, index) => ({ ...tab, index }));
}

function storagePageIndexForType(type) {
  const found = storagePageDescriptors().find((tab) => tab.unlocked && tab.type === type);
  return found ? found.index : Math.max(0, state.account.storage.pagesUnlocked - 1);
}

// Buys the 1,000,000-gold storage page.
function unlockStorageGoldPage() {
  syncStorageCapacity();
  if (state.account.storage.page2Purchased || state.account.storage.pagesUnlocked >= storagePageCount()) return false;
  const cost = STORAGE_PAGE_2_UNLOCK_COST;
  if (state.inventory.gold < cost) {
    pushBattleLog(`Need ${cost.toLocaleString()} gold to unlock another storage page.`);
    battlePanelSignature = "";
    renderBattlePanel();
    return false;
  }
  state.inventory.gold -= cost;
  state.game.progress.gold = state.inventory.gold;
  state.battle.gold = state.inventory.gold;
  state.account.storage.page2Purchased = true;
  syncStorageCapacity();
  ensureStorageSlots();
  syncBossPartyInventoryCapacityFromState();
  state.storagePage = storagePageIndexForType("gold");
  pushBattleLog("Unlocked another storage page.");
  playSfx("ui.gold", { volume: 0.55, throttleMs: 80 });
  sceneSignature = "";
  gamePanelSignature = "";
  battlePanelSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  renderBattlePanel();
  return true;
}

// Buys the 250-token storage page (account-wide, server-authoritative).
function confirmStorageTokenPageUnlock() {
  state.pendingStorageUnlock = null;
  purchasePageUnlock(STORAGE_PAGE_UNLOCK_KEY, () => {
    state.account.storage.tokenPageUnlocked = true;
    syncStorageCapacity();
    ensureStorageSlots();
    syncBossPartyInventoryCapacityFromState();
    state.storagePage = storagePageIndexForType("token");
    pushBattleLog("Unlocked a new storage page with tokens.");
    playSfx("ui.gold", { volume: 0.55, throttleMs: 80 });
    gamePanelSignature = "";
    battlePanelSignature = "";
    renderGamePanel();
    renderBattlePanel();
    saveGameState(true);
  });
}

// A locked inventory tab was clicked: gold unlocks immediately (as before),
// token opens a confirm dialog and refreshes the live balance.
function triggerInventoryPageUnlock(type) {
  if (type === "gold") {
    unlockInventoryGoldPage();
    return;
  }
  state.pendingInventoryTokenUnlock = true;
  state.tokens.error = "";
  void fetchTokenBalance(true);
  sceneSignature = "";
  renderSceneOverlay();
}

// A locked storage tab was clicked: both gold and token show a confirm dialog.
function triggerStoragePageUnlock(type) {
  state.pendingStorageUnlock = type === "token" ? "token" : "gold";
  if (type === "token") {
    state.tokens.error = "";
    void fetchTokenBalance(true);
  }
  sceneSignature = "";
  renderSceneOverlay();
}

// Shared confirm/cancel routing for the inventory + storage page unlock dialogs.
function handlePageUnlockConfirmClick(event) {
  const invConfirm = event.target.closest("[data-confirm-inventory-token-unlock]");
  if (invConfirm && root.contains(invConfirm)) {
    confirmInventoryTokenPageUnlock();
    return true;
  }
  const invCancel = event.target.closest("[data-cancel-inventory-token-unlock]");
  if (invCancel && root.contains(invCancel)) {
    state.pendingInventoryTokenUnlock = false;
    sceneSignature = "";
    renderSceneOverlay();
    return true;
  }
  const storageGold = event.target.closest("[data-confirm-storage-gold-unlock]");
  if (storageGold && root.contains(storageGold)) {
    state.pendingStorageUnlock = null;
    unlockStorageGoldPage();
    return true;
  }
  const storageToken = event.target.closest("[data-confirm-storage-token-unlock]");
  if (storageToken && root.contains(storageToken)) {
    confirmStorageTokenPageUnlock();
    return true;
  }
  const storageCancel = event.target.closest("[data-cancel-storage-page-unlock]");
  if (storageCancel && root.contains(storageCancel)) {
    state.pendingStorageUnlock = null;
    sceneSignature = "";
    renderSceneOverlay();
    return true;
  }
  return false;
}

function buyAccountUpgrade(upgradeId) {
  state.account.upgrades = sanitizeAccountUpgradeState(state.account.upgrades);
  const upgrade = accountUpgradeById(upgradeId);
  if (!upgrade) return false;
  if (upgrade.planned) {
    pushBattleLog(`${upgrade.label} is not available yet.`);
    battlePanelSignature = "";
    renderBattlePanel();
    return false;
  }
  if (upgrade.requiresUpgradeId && !accountUpgradePurchased(upgrade.requiresUpgradeId)) {
    const prereq = accountUpgradeById(upgrade.requiresUpgradeId);
    pushBattleLog(`Unlock ${prereq?.label ?? "the prerequisite upgrade"} first.`);
    battlePanelSignature = "";
    renderBattlePanel();
    return false;
  }
  if (accountUpgradeIsMaxed(upgrade)) {
    pushBattleLog(`${upgrade.label} is already maxed.`);
    return false;
  }
  if (!canAffordAccountUpgrade(upgrade)) {
    pushBattleLog(`Need ${missingAccountUpgradeCostText(upgrade)} to unlock ${upgrade.label}.`);
    battlePanelSignature = "";
    renderBattlePanel();
    return false;
  }

  const previousTier = accountUpgradeTier(upgrade.id);
  if (!payAccountUpgradeCost(upgrade)) return false;
  state.game.progress.gold = state.inventory.gold;
  state.battle.gold = state.inventory.gold;
  if (!state.account.upgrades.tiers) state.account.upgrades.tiers = {};
  state.account.upgrades.tiers[upgrade.id] = previousTier + 1;
  normalizeAutoCastSpellsForClass(state.battle.combatClass);
  if (upgrade.effect === "baseStatBonus" || upgrade.effect === "baseLuck") {
    applyEquippedStatsToBattlePlayer();
    restoreBattlePlayerResources();
  }
  pushBattleLog(previousTier > 0
    ? `${upgrade.label} upgraded for all characters.`
    : `${upgrade.label} unlocked for all characters.`);
  playSfx("ui.gold", { volume: 0.55, throttleMs: 80 });
  sceneSignature = "";
  gamePanelSignature = "";
  battlePanelSignature = "";
  combatSkillBarSignature = "";
  hotbarSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  renderBattlePanel();
  renderCombatSkillBar();
  renderHotbar();
  saveGameState(true);
  return true;
}

function accountUpgradeGoldCost(upgrade) {
  return Math.max(0, Math.trunc(Number(upgrade?.cost) || 0));
}

function accountUpgradeItemCosts(upgrade) {
  return Array.isArray(upgrade?.itemCosts)
    ? upgrade.itemCosts
      .map((cost) => ({
        itemId: String(cost?.itemId ?? ""),
        quantity: Math.max(1, Math.trunc(Number(cost?.quantity) || 1)),
      }))
      .filter((cost) => cost.itemId && itemDefinition(cost.itemId))
    : [];
}

function inventoryItemQuantity(itemId) {
  return carriedInventoryEntries()
    .filter((entry) => entry.itemId === itemId)
    .reduce((total, entry) => total + Math.max(1, Math.trunc(Number(entry.quantity) || 1)), 0);
}

function canAffordAccountUpgrade(upgrade) {
  if (upgrade?.planned) return false;
  if (upgrade?.requiresUpgradeId && !accountUpgradePurchased(upgrade.requiresUpgradeId)) return false;
  if (accountUpgradeIsMaxed(upgrade)) return false;
  if (accountUpgradeUsesRebirthPoints(upgrade)) {
    const cost = accountUpgradeRebirthCost(upgrade);
    return cost != null && accountRebirthPoints() >= cost;
  }
  if (state.inventory.gold < accountUpgradeGoldCost(upgrade)) return false;
  return accountUpgradeItemCosts(upgrade)
    .every((cost) => inventoryItemQuantity(cost.itemId) >= cost.quantity);
}

function accountUpgradeCostText(upgrade) {
  const parts = [];
  const goldCost = accountUpgradeGoldCost(upgrade);
  if (goldCost > 0) parts.push(`${goldCost.toLocaleString()}g`);
  for (const cost of accountUpgradeItemCosts(upgrade)) {
    const item = itemDefinition(cost.itemId);
    parts.push(`${cost.quantity}x ${item?.name ?? cost.itemId} (Have ${inventoryItemQuantity(cost.itemId)})`);
  }
  return parts.length ? parts.join(" + ") : "Free";
}

function accountUpgradeEffectLabel(upgrade) {
  if (upgrade?.effectLabel) return upgrade.effectLabel;
  if (upgrade?.effect === "autocastSlots") return "Autocast slots";
  if (upgrade?.effect === "autoPotionSlots") return "Auto potion slots";
  if (upgrade?.effect === "xpBonusPercent") return "XP gained";
  if (upgrade?.effect === "goldBonusPercent") return "Monster kill gold";
  if (upgrade?.effect === "dropChanceBonusPercent") return "All drop chances";
  if (upgrade?.effect === "poisonAmuletStackMultiplier") return "Poison & amulet stack size";
  if (upgrade?.effect === "skillExperienceGainMaxBonus") return "Skill practice XP per cast";
  if (upgrade?.effect === "bonusAwakeningSoulChancePercent") return "Extra Awakening Soul chance";
  if (upgrade?.effect === "bossRespawnReductionPercent") return "Boss respawn time";
  if (upgrade?.effect === "miningSpeedBonusPercent") return "Mining speed";
  if (upgrade?.effect === "miningMinPurityFloor") return "Minimum ore purity";
  if (upgrade?.effect === "baseStatBonus") return rebirthStatUpgradeEffectLabel(upgrade);
  if (upgrade?.effect === "baseLuck") return "Base luck";
  if (upgrade?.effect === "gemMerchantUnlock") return "Gem Merchant";
  if (upgrade?.effect === "gemMerchantEfficiency") return "Conversion costs";
  if (upgrade?.effect === "bossEmpowerment") return "Boss empowerment";
  if (upgrade?.effect === "empoweredCraftingUnlock") return "Crafting cube";
  return "Upgrade";
}

function accountUpgradeCurrentValue(upgrade) {
  if (upgrade?.effect === "autocastSlots") return autoCastSlotLimit();
  if (upgrade?.effect === "autoPotionSlots") return autoPotionSlotLimit();
  return 0;
}

function accountUpgradeMaxValue(upgrade) {
  if (upgrade?.effect === "autocastSlots") return maxAutoCastSlotLimit();
  if (upgrade?.effect === "autoPotionSlots") return maxAutoPotionSlotLimit();
  return accountUpgradeCurrentValue(upgrade);
}

function accountUpgradeProgressText(upgrade) {
  if (upgrade?.planned && upgrade.progressText) return upgrade.progressText;
  const tier = accountUpgradeTier(upgrade.id);
  const step = Math.max(0, Math.trunc(Number(upgrade?.value) || 0));
  if (upgrade?.effect === "xpBonusPercent") {
    const current = tier * step;
    if (accountUpgradeIsMaxed(upgrade)) return `+${current}%`;
    return `+${current}% -> +${current + step}%`;
  }
  if (upgrade?.effect === "goldBonusPercent") {
    const current = tier * step;
    const maxPercent = step * accountUpgradeMaxTier(upgrade);
    if (accountUpgradeIsMaxed(upgrade)) return `+${current}%`;
    return `+${current}% -> +${Math.min(current + step, maxPercent)}%`;
  }
  if (upgrade?.effect === "dropChanceBonusPercent") {
    const stepValue = Math.max(0, Number(upgrade?.value) || 0);
    const current = tier * stepValue;
    const maxPercent = stepValue * accountUpgradeMaxTier(upgrade);
    const format = (value) => (Number.isInteger(value) ? `${value}%` : `${value.toFixed(1)}%`);
    if (accountUpgradeIsMaxed(upgrade)) return `+${format(current)}`;
    return `+${format(current)} -> +${format(Math.min(current + stepValue, maxPercent))}`;
  }
  if (upgrade?.effect === "poisonAmuletStackMultiplier") {
    return tier >= 1 ? "2x per stack" : "1x -> 2x per stack";
  }
  if (upgrade?.effect === "skillExperienceGainMaxBonus") {
    const currentMax = BASE_SKILL_EXPERIENCE_GAIN_MAX + tier * step;
    const maxTier = accountUpgradeMaxTier(upgrade);
    if (accountUpgradeIsMaxed(upgrade)) return `1-${currentMax} per cast`;
    return `1-${currentMax} -> 1-${BASE_SKILL_EXPERIENCE_GAIN_MAX + Math.min(tier + 1, maxTier) * step} per cast`;
  }
  if (upgrade?.effect === "bonusAwakeningSoulChancePercent") {
    const current = tier * step;
    const maxPercent = step * accountUpgradeMaxTier(upgrade);
    if (accountUpgradeIsMaxed(upgrade)) return `${current}%`;
    return `${current}% -> ${Math.min(current + step, maxPercent)}%`;
  }
  if (upgrade?.effect === "bossRespawnReductionPercent") {
    const current = tier * step;
    const maxPercent = step * accountUpgradeMaxTier(upgrade);
    if (accountUpgradeIsMaxed(upgrade)) return `-${current}%`;
    return `-${current}% -> -${Math.min(current + step, maxPercent)}%`;
  }
  if (upgrade?.effect === "miningSpeedBonusPercent") {
    const current = tier * step;
    const maxPercent = step * accountUpgradeMaxTier(upgrade);
    if (accountUpgradeIsMaxed(upgrade)) return `+${current}%`;
    return `+${current}% -> +${Math.min(current + step, maxPercent)}%`;
  }
  if (upgrade?.effect === "miningMinPurityFloor") {
    const minPurity = rebirthMiningMinPurity();
    const nextMin = Math.min(10, minPurity + step);
    if (accountUpgradeIsMaxed(upgrade)) return `Purity ${minPurity}-10 only`;
    if (tier <= 0) return `Purity 1-10 -> Purity ${nextMin}-10`;
    return `Purity ${minPurity}-10 -> Purity ${nextMin}-10`;
  }
  if (upgrade?.effect === "baseStatBonus" || upgrade?.effect === "baseLuck") {
    const current = tier * step;
    if (accountUpgradeIsMaxed(upgrade)) return `+${current}`;
    return `+${current} -> +${current + step}`;
  }
  if (upgrade?.effect === "bossEmpowerment") {
    return tier >= 1 ? "Unlocked" : "Locked -> Unlocked";
  }
  if (upgrade?.effect === "empoweredCraftingUnlock") {
    return tier >= 1 ? "Unlocked" : "Locked -> Unlocked";
  }
  if (upgrade?.effect === "gemMerchantUnlock") {
    return tier >= 1 ? "Unlocked" : "Locked -> Unlocked";
  }
  if (upgrade?.effect === "gemMerchantEfficiency") {
    const randomCost = gemMerchantRandomCost();
    const sameCost = gemMerchantSameCost();
    if (accountUpgradeIsMaxed(upgrade)) return `${randomCost} random / ${sameCost} matching`;
    const nextRandom = GEM_MERCHANT_RANDOM_BASE_COST - tier - 1;
    const nextSame = GEM_MERCHANT_SAME_BASE_COST - tier - 1;
    return `${randomCost} random / ${sameCost} matching -> ${nextRandom} / ${nextSame}`;
  }
  const current = accountUpgradeCurrentValue(upgrade);
  const max = accountUpgradeMaxValue(upgrade);
  if (accountUpgradeIsMaxed(upgrade)) return `${current}/${max}`;
  const next = Math.min(max, current + step);
  return `${current} -> ${next}`;
}

function accountUpgradeRequirementHtml(upgrade) {
  if (upgrade?.planned) {
    return `
      <div class="upgrade-material planned">
        <span class="upgrade-material-icon">?</span>
        <span>${escapeHtml(upgrade.requirementText ?? "Future requirement")}</span>
        <strong>Later</strong>
      </div>
    `;
  }
  if (upgrade?.requiresUpgradeId && !accountUpgradePurchased(upgrade.requiresUpgradeId)) {
    const prereq = accountUpgradeById(upgrade.requiresUpgradeId);
    return `
      <div class="upgrade-material missing">
        <span class="upgrade-material-icon">!</span>
        <span>Requires ${escapeHtml(prereq?.label ?? "unlock")}</span>
        <strong>Locked</strong>
      </div>
    `;
  }
  if (accountUpgradeUsesRebirthPoints(upgrade)) {
    const cost = accountUpgradeRebirthCost(upgrade);
    if (cost == null) {
      return `<div class="upgrade-material met"><span>Maxed</span></div>`;
    }
    const owned = accountRebirthPoints();
    return `
      <div class="upgrade-material ${owned >= cost ? "met" : "missing"}">
        <span class="upgrade-material-icon rebirth">P</span>
        <span>Rebirth Points</span>
        <strong>${owned}/${cost}</strong>
      </div>
    `;
  }
  const rows = [];
  const goldCost = accountUpgradeGoldCost(upgrade);
  if (goldCost > 0) {
    const owned = Math.max(0, Number(state.inventory.gold) || 0);
    rows.push(`
      <div class="upgrade-material ${owned >= goldCost ? "met" : "missing"}">
        <span class="upgrade-material-icon gold">G</span>
        <span>Gold</span>
        <strong>${owned.toLocaleString()}/${goldCost.toLocaleString()}</strong>
      </div>
    `);
  }
  for (const cost of accountUpgradeItemCosts(upgrade)) {
    const item = itemDefinition(cost.itemId);
    const owned = inventoryItemQuantity(cost.itemId);
    const met = owned >= cost.quantity;
    rows.push(`
      <div class="upgrade-material has-tooltip ${met ? "met" : "missing"}" data-tooltip-item="${escapeHtml(cost.itemId)}">
        ${itemIconHtml(item, 24)}
        <span>${escapeHtml(item?.name ?? cost.itemId)}</span>
        <strong>${owned}/${cost.quantity}</strong>
      </div>
    `);
  }
  return rows.length ? rows.join("") : `<div class="upgrade-material met"><span>Free</span></div>`;
}

function accountUpgradeSourceText(upgrade) {
  if (upgrade?.planned && upgrade.sourceHint) return upgrade.sourceHint;
  if (upgrade?.currency === "rebirthPoints") return "";
  const zones = [
    ...new Set(accountUpgradeItemCosts(upgrade).flatMap((cost) => {
      const item = itemDefinition(cost.itemId);
      return Array.isArray(item?.drop?.zones) ? item.drop.zones : [];
    })),
  ];
  const zoneText = zones.length ? zones.map(zoneLabel).join(", ") : "";
  if (upgrade?.sourceHint && zoneText) return `${upgrade.sourceHint} (${zoneText})`;
  if (upgrade?.sourceHint) return upgrade.sourceHint;
  return zoneText ? `Drops in ${zoneText}` : "Source not set";
}

function missingAccountUpgradeItemLabel(upgrade) {
  if (upgrade?.requiresUpgradeId && !accountUpgradePurchased(upgrade.requiresUpgradeId)) {
    return accountUpgradeById(upgrade.requiresUpgradeId)?.label ?? "Unlock";
  }
  if (accountUpgradeUsesRebirthPoints(upgrade)) return "Rebirth Points";
  for (const cost of accountUpgradeItemCosts(upgrade)) {
    const item = itemDefinition(cost.itemId);
    if (inventoryItemQuantity(cost.itemId) < cost.quantity) return item?.name ?? "Item";
  }
  return state.inventory.gold < accountUpgradeGoldCost(upgrade) ? "Gold" : "Item";
}

function missingAccountUpgradeCostText(upgrade) {
  const parts = [];
  if (accountUpgradeUsesRebirthPoints(upgrade)) {
    const cost = accountUpgradeRebirthCost(upgrade);
    if (cost != null && accountRebirthPoints() < cost) {
      parts.push(`${cost - accountRebirthPoints()} Rebirth Point${cost - accountRebirthPoints() === 1 ? "" : "s"}`);
    }
    return parts.length ? parts.join(", ") : "Rebirth Points";
  }
  const goldCost = accountUpgradeGoldCost(upgrade);
  if (state.inventory.gold < goldCost) parts.push(`${(goldCost - state.inventory.gold).toLocaleString()} gold`);
  for (const cost of accountUpgradeItemCosts(upgrade)) {
    const item = itemDefinition(cost.itemId);
    const missing = cost.quantity - inventoryItemQuantity(cost.itemId);
    if (missing > 0) parts.push(`${missing}x ${item?.name ?? cost.itemId}`);
  }
  return parts.length ? parts.join(", ") : "the required materials";
}

function payAccountUpgradeCost(upgrade) {
  if (!canAffordAccountUpgrade(upgrade)) return false;
  if (accountUpgradeUsesRebirthPoints(upgrade)) {
    const cost = accountUpgradeRebirthCost(upgrade);
    if (cost == null || accountRebirthPoints() < cost) return false;
    return payRebirthPoints(cost);
  }
  state.inventory.gold -= accountUpgradeGoldCost(upgrade);
  for (const cost of accountUpgradeItemCosts(upgrade)) {
    if (!removeInventoryItemQuantity(cost.itemId, cost.quantity)) return false;
  }
  return true;
}

function removeInventoryItemQuantity(itemId, quantity) {
  let remaining = Math.max(1, Math.trunc(Number(quantity) || 1));
  const entryIds = carriedInventoryEntries()
    .filter((entry) => entry.itemId === itemId)
    .map((entry) => entry.id);
  for (const entryId of entryIds) {
    const entry = inventoryEntryById(entryId);
    if (!entry) continue;
    const taken = Math.min(remaining, Math.max(1, Math.trunc(Number(entry.quantity) || 1)));
    if (!removeInventoryEntry(entry.id, taken)) return false;
    remaining -= taken;
    if (remaining <= 0) return true;
  }
  return false;
}

function allAccountUpgradeDefs() {
  return [...ACCOUNT_UPGRADE_DEFS, ...ACCOUNT_UPGRADE_PREVIEW_DEFS];
}

function upgradeSectionCategories(sectionId) {
  const section = ACCOUNT_UPGRADE_SECTIONS.find((entry) => entry.id === sectionId);
  return section?.categories ?? [];
}

function normalizeUpgradeSection(sectionId) {
  return ACCOUNT_UPGRADE_SECTIONS.some((entry) => entry.id === sectionId)
    ? sectionId
    : ACCOUNT_UPGRADE_SECTIONS[0].id;
}

function normalizeUpgradeCategory(categoryId, sectionId = state.upgradeSection) {
  const legacyCategory = String(categoryId ?? "");
  if (legacyCategory === "rebirth") {
    state.upgradeSection = "rebirth";
    return "stats";
  }
  const section = normalizeUpgradeSection(sectionId);
  const categories = upgradeSectionCategories(section);
  if (legacyCategory === "bosses" && section !== "rebirth") {
    state.upgradeSection = "rebirth";
    return categories.some((entry) => entry.id === "bosses") ? "bosses" : categories[0]?.id ?? "stats";
  }
  if (categories.some((entry) => entry.id === legacyCategory)) return legacyCategory;
  return categories[0]?.id ?? "combat";
}

function syncUpgradeNavigation() {
  state.upgradeSection = normalizeUpgradeSection(state.upgradeSection);
  state.upgradeCategory = normalizeUpgradeCategory(state.upgradeCategory, state.upgradeSection);
}

function activeUpgradeSection() {
  syncUpgradeNavigation();
  return ACCOUNT_UPGRADE_SECTIONS.find((entry) => entry.id === state.upgradeSection)
    ?? ACCOUNT_UPGRADE_SECTIONS[0];
}

function activeUpgradeCategory() {
  const section = activeUpgradeSection();
  return upgradeSectionCategories(section.id).find((entry) => entry.id === state.upgradeCategory)
    ?? upgradeSectionCategories(section.id)[0];
}

function accountUpgradeSection(upgrade) {
  if (upgrade?.section) return upgrade.section;
  if (upgrade?.currency === "rebirthPoints" || upgrade?.category === "bosses") return "rebirth";
  return "normal";
}

function accountUpgradesForSectionCategory(sectionId, categoryId) {
  return allAccountUpgradeDefs().filter((upgrade) => (
    accountUpgradeSection(upgrade) === sectionId && upgrade.category === categoryId
  ));
}

function categoryUpgradeCountText(sectionId, categoryId) {
  const upgrades = accountUpgradesForSectionCategory(sectionId, categoryId);
  const real = upgrades.filter((upgrade) => !upgrade.planned);
  if (!real.length) return "Planned";
  const totalTiers = real.reduce((sum, upgrade) => sum + accountUpgradeTier(upgrade.id), 0);
  if (real.some((upgrade) => !Number.isFinite(accountUpgradeMaxTier(upgrade)))) {
    return totalTiers > 0 ? `${totalTiers} bought` : "0 bought";
  }
  const maxed = real.filter((upgrade) => accountUpgradeIsMaxed(upgrade)).length;
  return `${maxed}/${real.length}`;
}

function sectionUpgradeCountText(sectionId) {
  const categories = upgradeSectionCategories(sectionId);
  const real = categories.flatMap((category) => accountUpgradesForSectionCategory(sectionId, category.id))
    .filter((upgrade) => !upgrade.planned);
  if (!real.length) return "Planned";
  const totalTiers = real.reduce((sum, upgrade) => sum + accountUpgradeTier(upgrade.id), 0);
  if (real.some((upgrade) => !Number.isFinite(accountUpgradeMaxTier(upgrade)))) {
    return totalTiers > 0 ? `${totalTiers} bought` : "0 bought";
  }
  const maxed = real.filter((upgrade) => accountUpgradeIsMaxed(upgrade)).length;
  return `${maxed}/${real.length}`;
}

function addInventoryItem(itemId, quantity = 1, options = {}) {
  syncInventoryCapacity();
  const item = itemDefinition(itemId);
  if (!item) return [];
  const added = [];
  let remaining = Math.max(1, Math.floor(Number(quantity) || 1));
  const maxStack = maxItemStack(item);

  while (remaining > 0) {
    if (isStackableItem(item)) {
      const existing = carriedInventoryEntries().find((entry) => entry.itemId === itemId && entry.quantity < maxStack);
      if (existing) {
        const add = Math.min(remaining, maxStack - existing.quantity);
        existing.quantity += add;
        remaining -= add;
        added.push(existing);
        continue;
      }
      const add = Math.min(remaining, maxStack);
      if (inventoryUsedSlots() >= state.inventory.maxSlots) break;
      const entry = createInventoryEntry(itemId, add);
      state.inventory.items.push(entry);
      added.push(entry);
      remaining -= add;
      continue;
    }

    if (inventoryUsedSlots() >= state.inventory.maxSlots) break;
    const entry = createInventoryEntry(itemId, 1, options.entryOptions ?? {});
    if (options.empowerDrop) applyEmpoweredDropRoll(entry, item);
    state.inventory.items.push(entry);
    added.push(entry);
    remaining -= 1;
  }

  syncBossPartyControlledInventoryFromState();
  gamePanelSignature = "";
  return added;
}

function hasInventorySpaceFor(itemId) {
  syncInventoryCapacity();
  ensureInventorySlots();
  const item = itemDefinition(itemId);
  if (!item) return false;
  if (isStackableItem(item)) {
    const maxStack = maxItemStack(item);
    if (carriedInventoryEntries().some((entry) => entry.itemId === itemId && entry.quantity < maxStack)) return true;
  }
  return inventoryUsedSlots() < state.inventory.maxSlots;
}

function availableInventoryCapacityForItem(item) {
  syncInventoryCapacity();
  if (!item) return 0;
  const freeSlots = Math.max(0, state.inventory.maxSlots - inventoryUsedSlots());
  if (!isStackableItem(item)) return freeSlots;
  const maxStack = maxItemStack(item);
  const partialSpace = carriedInventoryEntries()
    .filter((entry) => entry.itemId === item.id)
    .reduce((sum, entry) => sum + Math.max(0, maxStack - Math.max(1, Math.trunc(Number(entry.quantity) || 1))), 0);
  return partialSpace + freeSlots * maxStack;
}

function availableHotbarCapacityForPotion(item) {
  if (!isPotionItem(item)) return 0;
  const maxStack = maxItemStack(item);
  let capacity = 0;
  for (let slot = 0; slot < HOTBAR_SLOT_COUNT; slot++) {
    const entry = hotbarEntryAtSlot(slot);
    if (entry?.itemId === item.id) {
      capacity += Math.max(0, maxStack - Math.max(1, Math.trunc(Number(entry.quantity) || 1)));
    } else if (!state.hotbar.slots[slot]) {
      capacity += isStackableItem(item) ? maxStack : 1;
    }
  }
  return capacity;
}

function availablePurchaseCapacityForItem(item) {
  if (!item) return 0;
  if (isPotionItem(item)) {
    return availableInventoryCapacityForItem(item) + availableHotbarCapacityForPotion(item);
  }
  return availableInventoryCapacityForItem(item);
}

function addPurchasedPotionsToHotbarFirst(itemId, quantity = 1) {
  const item = itemDefinition(itemId);
  const requested = Math.max(0, Math.floor(Number(quantity) || 0));
  if (!item || !isPotionItem(item) || requested <= 0) {
    return { added: 0, remaining: requested };
  }

  const maxStack = maxItemStack(item);
  let remaining = requested;
  let added = 0;

  for (let slot = 0; slot < HOTBAR_SLOT_COUNT && remaining > 0; slot++) {
    const entry = hotbarEntryAtSlot(slot);
    if (!entry || entry.itemId !== itemId) continue;
    const stack = Math.max(1, Math.trunc(Number(entry.quantity) || 1));
    if (stack >= maxStack) continue;
    const add = Math.min(remaining, maxStack - stack);
    entry.quantity = stack + add;
    remaining -= add;
    added += add;
  }

  for (let slot = 0; slot < HOTBAR_SLOT_COUNT && remaining > 0; slot++) {
    if (state.hotbar.slots[slot]) continue;
    const add = isStackableItem(item) ? Math.min(remaining, maxStack) : 1;
    const entry = createInventoryEntry(itemId, add);
    entry.slot = null;
    state.inventory.items.push(entry);
    state.hotbar.slots[slot] = entry.id;
    remaining -= add;
    added += add;
  }

  ensureInventorySlots();
  return { added, remaining };
}

function inventoryQuantityForItem(itemId) {
  return state.inventory.items
    .filter((entry) => entry.itemId === itemId && !isEquippedEntry(entry.id))
    .reduce((sum, entry) => sum + Math.max(1, Math.trunc(Number(entry.quantity) || 1)), 0);
}

function createInventoryEntry(itemId, quantity = 1, options = {}) {
  const slot = nextFreeInventorySlot();
  const item = itemDefinition(itemId);
  const entry = {
    id: allocateInventoryEntryId(),
    itemId,
    quantity: Math.max(1, Math.trunc(Number(quantity) || 1)),
    slot: Number.isInteger(slot) ? slot : null,
    ...normalizeInventoryEntryFields({}, item),
  };
  if (options.smithLevel != null) {
    entry.smithLevel = Math.max(0, Math.trunc(Number(options.smithLevel) || 0));
  }
  if (options.weaponRefineLevel != null) {
    entry.weaponRefineLevel = sanitizeWeaponRefineLevel(options.weaponRefineLevel);
  }
  if (options.bonusStats) {
    entry.bonusStats = sanitizeItemBonusStats(options.bonusStats);
  }
  if (options.empowered) entry.empowered = true;
  if (options.empowerTier != null) {
    entry.empowerTier = Math.max(0, Math.min(4, Math.trunc(Number(options.empowerTier) || 0)));
  }
  if (options.empowerBonusStats) {
    entry.empowerBonusStats = sanitizeItemBonusStats(options.empowerBonusStats);
  }
  if (options.empowerSpellBonuses) {
    entry.empowerSpellBonuses = sanitizeEmpowerSpellBonuses(options.empowerSpellBonuses);
  }
  const dura = sanitizeEntryDurability(options, item);
  if (dura) {
    entry.maxDura = dura.maxDura;
    entry.currentDura = dura.currentDura;
  }
  return entry;
}

function createOreInventoryEntry(itemId, purity) {
  const item = itemDefinition(itemId);
  if (!item || !isOreItem(item)) return createInventoryEntry(itemId, 1);
  const maxPurity = Math.max(1, Math.floor(itemDefinitionMaxDura(item) / ORE_PURITY_UNIT));
  const purityClamped = Math.max(1, Math.min(maxPurity, Math.trunc(Number(purity) || 1)));
  return createInventoryEntry(itemId, 1, { currentDura: purityClamped * ORE_PURITY_UNIT });
}

function removeInventoryEntry(entryId, quantity = 1) {
  const entry = inventoryEntryById(entryId);
  if (!entry || isEquippedEntry(entry.id)) return false;
  entry.quantity -= Math.max(1, Math.floor(Number(quantity) || 1));
  if (entry.quantity <= 0) {
    clearHotbarEntry(entry.id);
    state.inventory.items = state.inventory.items.filter((candidate) => candidate.id !== entry.id);
  }
  ensureInventorySlots();
  gamePanelSignature = "";
  sceneSignature = "";
  hotbarSignature = "";
  syncBossPartyControlledInventoryFromState();
  return true;
}

function consumeOneInventoryUnit(entryId) {
  const entry = inventoryEntryById(entryId);
  if (!entry || isEquippedEntry(entry.id)) return false;
  const quantity = Math.max(1, Math.trunc(Number(entry.quantity) || 1));
  if (quantity > 1) {
    entry.quantity = quantity - 1;
    ensureInventorySlots();
    gamePanelSignature = "";
    sceneSignature = "";
    hotbarSignature = "";
    syncBossPartyControlledInventoryFromState();
    return true;
  }
  return removeInventoryEntry(entry.id, 1);
}

function sellInventoryEntry(entryId) {
  const entry = inventoryEntryById(entryId);
  const item = entry ? itemDefinition(entry.itemId) : null;
  if (!entry || !item || isEquippedEntry(entry.id) || isHotbarEntry(entry.id) || isInventoryEntrySaved(entry)) return false;

  const quantity = Math.max(1, Number(entry.quantity) || 1);
  const value = itemSellValue(item, quantity);
  if (value <= 0) return false;

  removeInventoryEntry(entry.id, quantity);
  state.inventory.gold += value;
  state.game.progress.gold = state.inventory.gold;
  state.battle.gold = state.game.progress.gold;
  playSfx("ui.gold", { volume: 0.55, throttleMs: 80 });
  pushBattleLog(`Sold ${quantity > 1 ? `${quantity}x ` : ""}${item.name} for ${value} gold.`);
  hideItemTooltip();
  sceneSignature = "";
  gamePanelSignature = "";
  battlePanelSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  renderBattlePanel();
  return true;
}

function isJunkOreItem(item) {
  return Boolean(item) && isOreItem(item) && !NON_JUNK_ORE_ITEM_IDS.has(item.id);
}

function isInventoryEntrySaved(entry) {
  return entry?.inventoryMark === "saved";
}

function isInventoryEntryJunk(entry) {
  return entry?.inventoryMark === "junk";
}

function canMarkInventoryEntry(entry) {
  return Boolean(entry?.id && inventoryEntryById(entry.id) && !isEquippedEntry(entry.id) && !isHotbarEntry(entry.id));
}

function cycleInventoryMark(entry) {
  if (!canMarkInventoryEntry(entry)) return false;
  const mark = entry.inventoryMark ?? null;
  entry.inventoryMark = mark === null ? "junk" : mark === "junk" ? "saved" : null;
  syncBossPartyControlledInventoryFromState();
  playSfx("item.move", { volume: 0.32, throttleMs: 60 });
  gamePanelSignature = "";
  sceneSignature = "";
  battlePanelSignature = "";
  saveGameState(true);
  renderSceneOverlay();
  renderGamePanel();
  renderBattlePanel();
  return true;
}

function inventoryMarkOverlayHtml(entry) {
  if (isInventoryEntryJunk(entry)) {
    return `<span class="inventory-mark inventory-mark-junk" aria-label="Junk">✕</span>`;
  }
  if (isInventoryEntrySaved(entry)) {
    return `<span class="inventory-mark inventory-mark-saved" aria-label="Saved">🔒</span>`;
  }
  return "";
}

function inventoryMarkClass(entry) {
  if (isInventoryEntryJunk(entry)) return " mark-junk";
  if (isInventoryEntrySaved(entry)) return " mark-saved";
  return "";
}

function inventoryEmpoweredClass(entry) {
  const tier = Math.max(0, Math.trunc(Number(entry?.empowerTier) || 0));
  return entry?.empowered && tier > 0 ? " empowered" : "";
}

function itemTooltipMarkHtml(entry) {
  if (!canMarkInventoryEntry(entry)) return "";
  const label = isInventoryEntryJunk(entry) ? "Junk" : isInventoryEntrySaved(entry) ? "Saved" : "Neutral";
  return `<span>Mark: ${label} (Space to cycle)</span>`;
}

const HELP_TOOLTIP_HTML = {
  "inventory-marks": `
    <strong>Marking items</strong>
    <span>Hover a bag item and press <strong>Space</strong> to mark it junk (✕). Junk items can be sold with Sell all junk.</span>
    <span>Press <strong>Space</strong> again to mark it saved (🔒). Saved copies are kept when smithing two of the same item and cannot be sold manually.</span>
    <span>Press <strong>Space</strong> once more to clear the mark.</span>
  `,
};

function weaponRefineStagedRecord(entryId) {
  return state.weaponRefine?.stagedEntries?.[entryId] ?? null;
}

function isWeaponRefineStagedEntry(entryId) {
  return Boolean(weaponRefineStagedRecord(entryId));
}

function weaponRefineEntryById(entryId) {
  return weaponRefineStagedRecord(entryId)?.entry ?? inventoryEntryById(entryId);
}

function stageWeaponRefineEntry(entry) {
  if (!entry || isWeaponRefineStagedEntry(entry.id)) return true;
  if (isEquippedEntry(entry.id) || isHotbarEntry(entry.id)) return false;
  ensureInventorySlots();
  const index = state.inventory.items.findIndex((candidate) => candidate.id === entry.id);
  if (index < 0) return false;
  const returnSlot = Number.isInteger(entry.slot) ? entry.slot : null;
  const [stagedEntry] = state.inventory.items.splice(index, 1);
  if (!state.weaponRefine.stagedEntries) state.weaponRefine.stagedEntries = {};
  state.weaponRefine.stagedEntries[stagedEntry.id] = { entry: stagedEntry, returnSlot };
  gamePanelSignature = "";
  return true;
}

function discardWeaponRefineStagedEntry(entryId) {
  if (!weaponRefineStagedRecord(entryId)) return false;
  delete state.weaponRefine.stagedEntries[entryId];
  return true;
}

function unstageWeaponRefineEntry(entryId, targetSlot = null) {
  const staged = weaponRefineStagedRecord(entryId);
  if (!staged) return false;
  delete state.weaponRefine.stagedEntries[entryId];
  const entry = staged.entry;
  const preferredSlot = Number.isInteger(targetSlot)
    ? targetSlot
    : (Number.isInteger(staged.returnSlot) ? staged.returnSlot : null);
  entry.slot = preferredSlot;
  state.inventory.items.push(entry);
  ensureInventorySlots();
  gamePanelSignature = "";
  sceneSignature = "";
  return true;
}

function clearWeaponRefineResultFxTimer() {
  if (state.weaponRefine?.resultFxTimer != null) {
    window.clearTimeout(state.weaponRefine.resultFxTimer);
    state.weaponRefine.resultFxTimer = null;
  }
}

function weaponRefineResultFxKind() {
  const fx = state.weaponRefine?.resultFx;
  if (!fx) return null;
  if (performance.now() >= fx.until) {
    state.weaponRefine.resultFx = null;
    return null;
  }
  return fx.kind;
}

function weaponRefineResultFxActive() {
  return Boolean(weaponRefineResultFxKind());
}

function playWeaponRefineResultFx(success, crit = false) {
  clearWeaponRefineResultFxTimer();
  state.weaponRefine.resultFx = {
    kind: success ? (crit ? "crit" : "success") : "fail",
    until: performance.now() + WEAPON_REFINE_RESULT_FX_MS,
  };
}

function playWeaponRefineResultSfx(success, crit = false) {
  if (success && crit) {
    playSfx("level.up", { volume: 0.5, throttleMs: 120 });
    return;
  }
  if (success) {
    playSfx("item.equip.weapon", { volume: 0.48, throttleMs: 120 });
    return;
  }
  playSfx("weapon.hit.club", { volume: 0.42, throttleMs: 120 });
}

function restoreAllWeaponRefineStagedEntries() {
  clearWeaponRefineResultFxTimer();
  state.weaponRefine.resultFx = null;
  const stagedIds = Object.keys(state.weaponRefine?.stagedEntries ?? {});
  for (const entryId of stagedIds) {
    unstageWeaponRefineEntry(entryId);
  }
  state.weaponRefine.weaponEntryId = null;
  state.weaponRefine.oreEntryIds = Array(WEAPON_REFINE_ORE_SLOTS).fill(null);
  state.weaponRefine.materialEntryIds = Array(WEAPON_REFINE_MATERIAL_SLOTS).fill(null);
}

function resetWeaponRefineState() {
  restoreAllWeaponRefineStagedEntries();
  state.weaponRefine = createDefaultWeaponRefineState();
}

function weaponRefineUsedEntryIds() {
  const board = state.weaponRefine;
  const ids = new Set();
  if (board.weaponEntryId) ids.add(board.weaponEntryId);
  for (const id of board.oreEntryIds) if (id) ids.add(id);
  for (const id of board.materialEntryIds) if (id) ids.add(id);
  return ids;
}

function isRefineJewelleryItem(item) {
  return Boolean(item?.slot) && REFINE_JEWELLERY_SLOTS.has(item.slot);
}

function canPlaceWeaponRefineWeapon(entry, item) {
  if (!entry || !item || item.slot !== "weapon") return false;
  if (!isWeaponRefineStagedEntry(entry.id) && (isEquippedEntry(entry.id) || isHotbarEntry(entry.id))) return false;
  const used = weaponRefineUsedEntryIds();
  if (used.has(entry.id) && state.weaponRefine.weaponEntryId !== entry.id) return false;
  if (sanitizeWeaponRefineLevel(entry.weaponRefineLevel) >= WEAPON_REFINE_MAX) return false;
  return true;
}

function canPlaceWeaponRefineOre(entry, item, targetIndex = -1) {
  if (!entry || !item || item.id !== REFINER_ORE_ITEM_ID) return false;
  if (!isWeaponRefineStagedEntry(entry.id) && (isEquippedEntry(entry.id) || isHotbarEntry(entry.id))) return false;
  if (state.weaponRefine.weaponEntryId === entry.id) return false;
  if (state.weaponRefine.materialEntryIds.includes(entry.id)) return false;
  const oreIndex = state.weaponRefine.oreEntryIds.indexOf(entry.id);
  if (oreIndex >= 0 && oreIndex !== targetIndex) return true;
  return !usedWeaponRefineEntryOnOtherBoardSlot(entry.id, "ore", targetIndex);
}

function canPlaceWeaponRefineMaterial(entry, item, targetIndex = -1) {
  if (!entry || !isRefineJewelleryItem(item)) return false;
  if (!isWeaponRefineStagedEntry(entry.id) && (isEquippedEntry(entry.id) || isHotbarEntry(entry.id))) return false;
  if (state.weaponRefine.weaponEntryId === entry.id) return false;
  if (state.weaponRefine.oreEntryIds.includes(entry.id)) return false;
  const materialIndex = state.weaponRefine.materialEntryIds.indexOf(entry.id);
  if (materialIndex >= 0 && materialIndex !== targetIndex) return true;
  return !usedWeaponRefineEntryOnOtherBoardSlot(entry.id, "material", targetIndex);
}

function usedWeaponRefineEntryOnOtherBoardSlot(entryId, kind, targetIndex = -1) {
  const board = state.weaponRefine;
  if (board.weaponEntryId === entryId) return true;
  const oreIndex = board.oreEntryIds.indexOf(entryId);
  if (oreIndex >= 0 && !(kind === "ore" && oreIndex === targetIndex)) return true;
  const materialIndex = board.materialEntryIds.indexOf(entryId);
  if (materialIndex >= 0 && !(kind === "material" && materialIndex === targetIndex)) return true;
  return false;
}

function refineEligibleInventoryEntries(kind) {
  ensureInventorySlots();
  return inventoryEntries()
    .map((entry) => ({ entry, item: itemDefinition(entry.itemId) }))
    .filter(({ entry, item }) => {
      if (!item) return false;
      if (kind === "weapon") return canPlaceWeaponRefineWeapon(entry, item);
      if (kind === "ore") return canPlaceWeaponRefineOre(entry, item);
      if (kind === "material") return canPlaceWeaponRefineMaterial(entry, item);
      return false;
    });
}

function weaponRefineSlotEntry(kind, index = 0) {
  const board = state.weaponRefine;
  let entryId = null;
  if (kind === "weapon") entryId = board.weaponEntryId;
  else if (kind === "ore") entryId = board.oreEntryIds[index] ?? null;
  else if (kind === "material") entryId = board.materialEntryIds[index] ?? null;
  if (!entryId) return { entry: null, item: null };
  const entry = weaponRefineEntryById(entryId);
  return { entry, item: entry ? itemDefinition(entry.itemId) : null };
}

function selectWeaponRefineSlot(kind, index = 0) {
  state.weaponRefine.picker = { kind, index: Math.max(0, Math.trunc(Number(index) || 0)) };
  sceneSignature = "";
  renderSceneOverlay();
  playSfx("ui.button", { volume: 0.32, throttleMs: 80 });
}

function clearWeaponRefineSlot(kind, index = 0, { targetSlot = null } = {}) {
  const board = state.weaponRefine;
  let entryId = null;
  if (kind === "weapon") entryId = board.weaponEntryId;
  else if (kind === "ore") entryId = board.oreEntryIds[index] ?? null;
  else if (kind === "material") entryId = board.materialEntryIds[index] ?? null;

  if (kind === "weapon") board.weaponEntryId = null;
  else if (kind === "ore") board.oreEntryIds[index] = null;
  else if (kind === "material") board.materialEntryIds[index] = null;

  if (entryId) unstageWeaponRefineEntry(entryId, targetSlot);
  sceneSignature = "";
  gamePanelSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  playSfx("ui.button", { volume: 0.28, throttleMs: 80 });
}

function handleWeaponRefineSlotClick(kind, index = 0) {
  if (kind !== "weapon") return;
  const slotIndex = Math.max(0, Math.trunc(Number(index) || 0));
  const { entry } = weaponRefineSlotEntry(kind, slotIndex);
  const picker = state.weaponRefine.picker;
  const isSelected = picker?.kind === kind && picker.index === slotIndex;
  if (entry && isSelected) {
    clearWeaponRefineSlot(kind, slotIndex);
    return;
  }
  selectWeaponRefineSlot(kind, slotIndex);
}

function assignWeaponRefineSlot(kind, index, entryId, { fromRefine = null } = {}) {
  const slotIndex = Math.max(0, Math.trunc(Number(index) || 0));
  const entry = weaponRefineEntryById(entryId);
  const item = entry ? itemDefinition(entry.itemId) : null;
  if (!entry || !item) return false;

  if (kind === "weapon") {
    if (!canPlaceWeaponRefineWeapon(entry, item)) return false;
  } else if (kind === "ore") {
    if (!canPlaceWeaponRefineOre(entry, item, slotIndex)) return false;
  } else if (kind === "material") {
    if (!canPlaceWeaponRefineMaterial(entry, item, slotIndex)) return false;
  } else {
    return false;
  }

  const board = state.weaponRefine;
  if (!isWeaponRefineStagedEntry(entryId) && !stageWeaponRefineEntry(entry)) return false;

  let occupiedEntryId = null;
  if (kind === "weapon") occupiedEntryId = board.weaponEntryId;
  else if (kind === "ore") occupiedEntryId = board.oreEntryIds[slotIndex] ?? null;
  else if (kind === "material") occupiedEntryId = board.materialEntryIds[slotIndex] ?? null;
  if (occupiedEntryId && occupiedEntryId !== entryId) {
    if (kind === "weapon") board.weaponEntryId = null;
    else if (kind === "ore") board.oreEntryIds[slotIndex] = null;
    else board.materialEntryIds[slotIndex] = null;
    unstageWeaponRefineEntry(occupiedEntryId);
  }

  if (fromRefine?.kind === "ore") board.oreEntryIds[fromRefine.index] = null;
  if (fromRefine?.kind === "material") board.materialEntryIds[fromRefine.index] = null;

  const prevOre = board.oreEntryIds.indexOf(entryId);
  if (prevOre >= 0 && (kind !== "ore" || prevOre !== slotIndex)) board.oreEntryIds[prevOre] = null;
  const prevMaterial = board.materialEntryIds.indexOf(entryId);
  if (prevMaterial >= 0 && (kind !== "material" || prevMaterial !== slotIndex)) {
    board.materialEntryIds[prevMaterial] = null;
  }
  if (board.weaponEntryId === entryId && kind !== "weapon") board.weaponEntryId = null;

  if (kind === "weapon") board.weaponEntryId = entryId;
  else if (kind === "ore") board.oreEntryIds[slotIndex] = entryId;
  else board.materialEntryIds[slotIndex] = entryId;

  sceneSignature = "";
  gamePanelSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  playSfx("ui.button", { volume: 0.35, throttleMs: 80 });
  return true;
}

function assignWeaponRefinePick(entryId) {
  const picker = state.weaponRefine.picker;
  if (!picker || picker.kind !== "weapon") return false;
  return assignWeaponRefineSlot("weapon", 0, entryId);
}

function weaponRefineBoardReady() {
  return Boolean(state.weaponRefine.weaponEntryId);
}

function weaponRefineOreCount() {
  return state.weaponRefine.oreEntryIds.filter(Boolean).length;
}

function weaponRefineMaterialCount() {
  return state.weaponRefine.materialEntryIds.filter(Boolean).length;
}

function refineOffensiveStatSum(stats, key) {
  const range = stats?.[key];
  return Math.trunc(Number(range?.[0]) || 0) + Math.trunc(Number(range?.[1]) || 0);
}

function weaponRefineBoardEntries(kind) {
  const board = state.weaponRefine;
  const entryIds = kind === "ore" ? board.oreEntryIds : board.materialEntryIds;
  return entryIds
    .filter(Boolean)
    .map((entryId) => {
      const entry = weaponRefineEntryById(entryId);
      const item = entry ? itemDefinition(entry.itemId) : null;
      return entry && item ? { entry, item } : null;
    })
    .filter(Boolean);
}

function weaponRefineExistingStatPenalty(entry) {
  if (sanitizeWeaponRefineLevel(entry?.weaponRefineLevel) < WEAPON_REFINE_PENALTY_FROM_LEVEL) return 0;
  const bonusStats = sanitizeItemBonusStats(entry?.bonusStats);
  const addedStats = Math.trunc(Number(bonusStats.dc?.[1]) || 0)
    + Math.trunc(Number(bonusStats.mc?.[1]) || 0)
    + Math.trunc(Number(bonusStats.sc?.[1]) || 0);
  return Math.min(
    WEAPON_REFINE_EXISTING_STAT_PENALTY_CAP,
    addedStats * WEAPON_REFINE_EXISTING_STAT_PENALTY,
  );
}

function pickWeaponRefineStatKey(totalDC, totalMC, totalSC) {
  if (totalDC >= totalMC && totalDC >= totalSC && totalDC > 0) return { key: "dc", value: totalDC };
  if (totalMC >= totalDC && totalMC >= totalSC && totalMC > 0) return { key: "mc", value: totalMC };
  if (totalSC >= totalDC && totalSC >= totalMC && totalSC > 0) return { key: "sc", value: totalSC };
  return { key: null, value: 0 };
}

function weaponRefineItemSuccessFromStat(refineStat) {
  let remaining = Math.max(0, Math.trunc(Number(refineStat) || 0));
  let bonus = 0;
  const tier1 = Math.min(WEAPON_REFINE_ITEM_TIER1_STAT, remaining);
  bonus += tier1 * WEAPON_REFINE_ITEM_TIER1_RATE;
  remaining -= tier1;
  const tier2 = Math.min(WEAPON_REFINE_ITEM_TIER2_STAT, remaining);
  bonus += tier2 * WEAPON_REFINE_ITEM_TIER2_RATE;
  remaining -= tier2;
  bonus += remaining * WEAPON_REFINE_ITEM_TIER3_RATE;
  return Math.min(WEAPON_REFINE_ITEM_SUCCESS_CAP, bonus);
}

function collectWeaponRefineIngredients() {
  const board = state.weaponRefine;
  const weaponEntry = board.weaponEntryId ? weaponRefineEntryById(board.weaponEntryId) : null;
  const weaponItem = weaponEntry ? itemDefinition(weaponEntry.itemId) : null;
  let totalDC = 0;
  let totalMC = 0;
  let totalSC = 0;
  let itemAmount = 0;
  let totalOrePurity = 0;
  let oreAmount = 0;

  for (const { entry, item } of weaponRefineBoardEntries("material")) {
    const stats = itemEntryStats(entry, item);
    const dc = refineOffensiveStatSum(stats, "dc");
    const mc = refineOffensiveStatSum(stats, "mc");
    const sc = refineOffensiveStatSum(stats, "sc");
    if (dc <= 0 && mc <= 0 && sc <= 0) continue;
    totalDC += dc;
    totalMC += mc;
    totalSC += sc;
    itemAmount += 1;
  }

  for (const { entry, item } of weaponRefineBoardEntries("ore")) {
    totalOrePurity += orePurity(entry, item);
    oreAmount += 1;
  }

  return {
    weaponEntry,
    weaponItem,
    totalDC,
    totalMC,
    totalSC,
    itemAmount,
    orePurity: totalOrePurity,
    oreAmount,
  };
}

function computeWeaponRefineChance(ingredients = collectWeaponRefineIngredients()) {
  const {
    weaponEntry,
    weaponItem,
    totalDC,
    totalMC,
    totalSC,
    itemAmount,
    orePurity,
    oreAmount,
  } = ingredients;

  if (!weaponEntry || !weaponItem || itemAmount <= 0 || oreAmount <= 0) {
    return {
      chance: 0,
      statKey: null,
      statValue: 0,
      autoFail: true,
      reason: "Need at least one black iron ore and one jewellery item with DC, MC, or SC.",
    };
  }

  const { key: statKey, value: refineStat } = pickWeaponRefineStatKey(totalDC, totalMC, totalSC);
  if (!statKey || refineStat <= 0) {
    return {
      chance: 0,
      statKey: null,
      statValue: 0,
      autoFail: true,
      reason: "Jewellery must contribute DC, MC, or SC.",
    };
  }

  const itemSuccess = weaponRefineItemSuccessFromStat(refineStat);
  const oreSuccess = Math.min(
    WEAPON_REFINE_ORE_SUCCESS_CAP,
    (oreAmount * WEAPON_REFINE_ORE_PER_PIECE) + (orePurity * WEAPON_REFINE_PURITY_PER_POINT),
  );

  const penalty = weaponRefineExistingStatPenalty(weaponEntry);
  const chance = Math.max(
    0,
    Math.min(
      WEAPON_REFINE_MAX_CHANCE,
      Math.round(itemSuccess + oreSuccess - penalty),
    ),
  );

  return {
    chance,
    statKey,
    statValue: refineStat,
    autoFail: false,
    itemSuccess,
    oreSuccess,
    penalty,
    oreAmount,
    itemAmount,
    orePurity,
  };
}

function weaponRefineGoldCost(weaponEntry) {
  const nextLevel = sanitizeWeaponRefineLevel(weaponEntry?.weaponRefineLevel) + 1;
  return WEAPON_REFINE_GOLD_PER_LEVEL * nextLevel;
}

function weaponRefineCostPreview() {
  if (!weaponRefineBoardReady()) return null;
  const weaponEntry = weaponRefineEntryById(state.weaponRefine.weaponEntryId);
  if (!weaponEntry) return null;
  const cost = weaponRefineGoldCost(weaponEntry);
  return {
    cost,
    canAfford: state.inventory.gold >= cost,
  };
}

function chargeWeaponRefineGold(cost) {
  const amount = Math.max(0, Math.trunc(Number(cost) || 0));
  if (state.inventory.gold < amount) return false;
  state.inventory.gold -= amount;
  state.game.progress.gold = state.inventory.gold;
  state.battle.gold = state.inventory.gold;
  return true;
}

function weaponRefineChancePreview() {
  if (!weaponRefineBoardReady()) return null;
  return computeWeaponRefineChance();
}

function weaponRefineChanceText(preview = weaponRefineChancePreview()) {
  if (!preview) return "Place a weapon to preview success chance.";
  if (preview.autoFail) return `0% — ${preview.reason}`;
  const statLabel = smithStatLabel(preview.statKey);
  return `${preview.chance}% success · targets +${WEAPON_REFINE_STAT_INCREASE} ${statLabel} · ${WEAPON_REFINE_CRIT_CHANCE}% crit for ×${WEAPON_REFINE_CRIT_MULTIPLIER}`;
}

function weaponRefineCostText(costPreview = weaponRefineCostPreview()) {
  if (!costPreview) return "Place a weapon to see refine cost.";
  const afford = costPreview.canAfford ? "" : " — not enough gold";
  return `Cost: ${costPreview.cost.toLocaleString()} gold${afford}`;
}

function rollWeaponRefineSuccess(chance) {
  const clamped = Math.max(0, Math.min(WEAPON_REFINE_MAX_CHANCE, Math.trunc(Number(chance) || 0)));
  if (clamped <= 0) return false;
  const roll = Math.floor(Math.random() * WEAPON_REFINE_MAX_CHANCE) + 1;
  return roll <= clamped;
}

function rollWeaponRefineCrit() {
  return Math.random() * 100 < WEAPON_REFINE_CRIT_CHANCE;
}

function consumeWeaponRefineStagedMaterials() {
  const board = state.weaponRefine;
  const consumed = new Set();
  for (const entryId of [...board.oreEntryIds, ...board.materialEntryIds]) {
    if (!entryId || consumed.has(entryId)) continue;
    consumed.add(entryId);
    discardWeaponRefineStagedEntry(entryId);
  }
  board.oreEntryIds = Array(WEAPON_REFINE_ORE_SLOTS).fill(null);
  board.materialEntryIds = Array(WEAPON_REFINE_MATERIAL_SLOTS).fill(null);
}

function applyWeaponRefineSuccess(weaponEntry, statKey, amount) {
  weaponEntry.bonusStats = sanitizeItemBonusStats(weaponEntry.bonusStats);
  weaponEntry.bonusStats[statKey][1] += Math.max(1, Math.trunc(Number(amount) || 1));
  weaponEntry.weaponRefineLevel = sanitizeWeaponRefineLevel(
    sanitizeWeaponRefineLevel(weaponEntry.weaponRefineLevel) + 1,
  );
}

function openWeaponRefineScene() {
  if (state.game.mode !== "town") return;
  state.activeScene = "weaponRefine";
  state.openScenes.inventory = true;
  if (!state.weaponRefine.picker) state.weaponRefine.picker = { kind: "weapon", index: 0 };
  pushSceneWindow("weaponRefine");
  sceneSignature = "";
  gamePanelSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  playSfx("ui.button", { volume: 0.35, throttleMs: 120 });
}

function craftingCubeStagedRecord(entryId) {
  return state.craftingCube?.stagedEntries?.[entryId] ?? null;
}

function isCraftingCubeStagedEntry(entryId) {
  return Boolean(craftingCubeStagedRecord(entryId));
}

function craftingCubeEntryById(entryId) {
  return craftingCubeStagedRecord(entryId)?.entry ?? inventoryEntryById(entryId);
}

function stageCraftingCubeEntry(entry) {
  if (!entry || isCraftingCubeStagedEntry(entry.id)) return true;
  if (isEquippedEntry(entry.id) || isHotbarEntry(entry.id)) return false;
  ensureInventorySlots();
  const index = state.inventory.items.findIndex((candidate) => candidate.id === entry.id);
  if (index < 0) return false;
  const returnSlot = Number.isInteger(entry.slot) ? entry.slot : null;
  const [stagedEntry] = state.inventory.items.splice(index, 1);
  if (!state.craftingCube.stagedEntries) state.craftingCube.stagedEntries = {};
  state.craftingCube.stagedEntries[stagedEntry.id] = { entry: stagedEntry, returnSlot };
  gamePanelSignature = "";
  return true;
}

function discardCraftingCubeStagedEntry(entryId) {
  if (!craftingCubeStagedRecord(entryId)) return false;
  delete state.craftingCube.stagedEntries[entryId];
  return true;
}

function unstageCraftingCubeEntry(entryId, targetSlot = null) {
  const staged = craftingCubeStagedRecord(entryId);
  if (!staged) return false;
  delete state.craftingCube.stagedEntries[entryId];
  const entry = staged.entry;
  const preferredSlot = Number.isInteger(targetSlot)
    ? targetSlot
    : (Number.isInteger(staged.returnSlot) ? staged.returnSlot : null);
  entry.slot = preferredSlot;
  state.inventory.items.push(entry);
  ensureInventorySlots();
  gamePanelSignature = "";
  sceneSignature = "";
  return true;
}

function restoreAllCraftingCubeStagedEntries() {
  const stagedIds = Object.keys(state.craftingCube?.stagedEntries ?? {});
  for (const entryId of stagedIds) {
    unstageCraftingCubeEntry(entryId);
  }
  if (state.craftingCube) {
    state.craftingCube.slotEntryIds = Array(CRAFTING_CUBE_SLOT_COUNT).fill(null);
    state.craftingCube.feedback = null;
    state.craftingCube.feedbackKind = null;
    state.craftingCube.lastRerollNotice = null;
    clearCraftingCubeTargetedSelections();
  }
}

function resetCraftingCubeState() {
  restoreAllCraftingCubeStagedEntries();
  state.craftingCube = createDefaultCraftingCubeState();
}

function craftingCubeUsedEntryIds() {
  return new Set(state.craftingCube?.slotEntryIds?.filter(Boolean) ?? []);
}

function canPlaceCraftingCubeItem(entry, targetIndex = -1) {
  if (!entry) return false;
  if (!isCraftingCubeStagedEntry(entry.id) && (isEquippedEntry(entry.id) || isHotbarEntry(entry.id))) return false;
  const used = craftingCubeUsedEntryIds();
  if (used.has(entry.id)) {
    const slotIndex = state.craftingCube.slotEntryIds.indexOf(entry.id);
    if (slotIndex < 0 || slotIndex !== targetIndex) return false;
  }
  return true;
}

function craftingCubeSlotEntry(index = 0) {
  const entryId = state.craftingCube?.slotEntryIds?.[index] ?? null;
  if (!entryId) return { entry: null, item: null };
  const entry = craftingCubeEntryById(entryId);
  return { entry, item: entry ? itemDefinition(entry.itemId) : null };
}

function clearCraftingCubeTargetedSelections() {
  if (!state.craftingCube) return;
  state.craftingCube.targetedEmpowerSlotIndex = null;
  state.craftingCube.targetedEmpowerSwapSlotA = null;
  state.craftingCube.targetedEmpowerSwapSlotB = null;
}

function setCraftingCubeFeedback(message, kind = "error") {
  if (!state.craftingCube) state.craftingCube = createDefaultCraftingCubeState();
  state.craftingCube.feedback = message || null;
  state.craftingCube.feedbackKind = message ? kind : null;
}

function clearCraftingCubeBoard() {
  if (!state.craftingCube) return;
  const stagedIds = Object.keys(state.craftingCube.stagedEntries ?? {});
  for (const entryId of stagedIds) {
    unstageCraftingCubeEntry(entryId);
  }
  state.craftingCube.slotEntryIds = Array(CRAFTING_CUBE_SLOT_COUNT).fill(null);
  state.craftingCube.lastRerollNotice = null;
  clearCraftingCubeTargetedSelections();
}

function inventoryCraftingAutofillEntries() {
  return state.inventory.items.filter((entry) => entry
    && !isEquippedEntry(entry.id)
    && !isHotbarEntry(entry.id));
}

function autofillCraftingCubeForRecipe(recipeId) {
  if (!state.craftingCube) state.craftingCube = createDefaultCraftingCubeState();
  clearCraftingCubeBoard();
  const entryIds = craftingCubeAutofillEntryIds(
    recipeId,
    inventoryCraftingAutofillEntries(),
    itemDefinition,
  );
  entryIds.forEach((entryId, index) => {
    assignCraftingCubeSlot(index, entryId, { silent: true });
  });
  state.craftingCube.feedback = null;
  state.craftingCube.feedbackKind = null;
  gamePanelSignature = "";
  saveGameState(true);
}

function clearCraftingCubeSlot(index = 0, { targetSlot = null } = {}) {
  const slotIndex = Math.max(0, Math.trunc(Number(index) || 0));
  const entryId = state.craftingCube?.slotEntryIds?.[slotIndex] ?? null;
  state.craftingCube.slotEntryIds[slotIndex] = null;
  if (entryId) unstageCraftingCubeEntry(entryId, targetSlot);
  saveGameState(true);
  sceneSignature = "";
  gamePanelSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  playSfx("ui.button", { volume: 0.28, throttleMs: 80 });
}

function assignCraftingCubeSlot(index, entryId, { fromCube = null, silent = false } = {}) {
  const slotIndex = Math.max(0, Math.trunc(Number(index) || 0));
  const entry = craftingCubeEntryById(entryId);
  if (!entry || !canPlaceCraftingCubeItem(entry, slotIndex)) return false;

  const board = state.craftingCube;
  if (!isCraftingCubeStagedEntry(entryId) && !stageCraftingCubeEntry(entry)) return false;

  const occupiedEntryId = board.slotEntryIds[slotIndex] ?? null;
  if (occupiedEntryId && occupiedEntryId !== entryId) {
    board.slotEntryIds[slotIndex] = null;
    unstageCraftingCubeEntry(occupiedEntryId);
  }

  if (fromCube?.index != null) {
    board.slotEntryIds[fromCube.index] = null;
  }

  const prevSlot = board.slotEntryIds.indexOf(entryId);
  if (prevSlot >= 0 && prevSlot !== slotIndex) board.slotEntryIds[prevSlot] = null;

  board.slotEntryIds[slotIndex] = entryId;
  if (!silent) {
    board.feedback = null;
    board.feedbackKind = null;
    board.lastRerollNotice = null;
    clearCraftingCubeTargetedSelections();
    sceneSignature = "";
    gamePanelSignature = "";
    renderSceneOverlay();
    renderGamePanel();
    playSfx("ui.button", { volume: 0.35, throttleMs: 80 });
    saveGameState(true);
  }
  return true;
}

function craftingCubeFilledSlotCount() {
  return state.craftingCube?.slotEntryIds?.filter(Boolean).length ?? 0;
}

function craftingCubeSalvageEntries() {
  return (state.craftingCube?.slotEntryIds ?? [])
    .filter(Boolean)
    .map((entryId) => craftingCubeEntryById(entryId))
    .filter(Boolean);
}

function craftingCubeBoardEntries() {
  return (state.craftingCube?.slotEntryIds ?? [])
    .filter(Boolean)
    .map((entryId) => {
      const entry = craftingCubeEntryById(entryId);
      const item = entry ? itemDefinition(entry.itemId) : null;
      return entry && item ? { entry, item } : null;
    })
    .filter(Boolean);
}

function consumeStagedCraftingCubeEntryQuantity(entryId, quantity = 1) {
  const entry = craftingCubeEntryById(entryId);
  if (!entry) return false;
  const qty = Math.max(1, Math.trunc(Number(entry.quantity) || 1));
  const take = Math.min(qty, Math.max(1, Math.trunc(Number(quantity) || 1)));
  if (take >= qty) {
    const slotIndex = state.craftingCube.slotEntryIds.indexOf(entryId);
    if (slotIndex >= 0) state.craftingCube.slotEntryIds[slotIndex] = null;
    discardCraftingCubeStagedEntry(entryId);
  } else {
    entry.quantity = qty - take;
  }
  return true;
}

function attemptCraftingCubeSalvage() {
  if (state.craftingCube?.mode !== "salvage") return false;
  const validation = validateCraftingCubeSalvageEntries(craftingCubeSalvageEntries());
  if (!validation.ok) {
    setCraftingCubeFeedback(validation.error);
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
    return false;
  }

  const entryIds = state.craftingCube.slotEntryIds.filter(Boolean);
  for (const entryId of entryIds) {
    discardCraftingCubeStagedEntry(entryId);
  }
  state.craftingCube.slotEntryIds = Array(CRAFTING_CUBE_SLOT_COUNT).fill(null);
  state.craftingCube.feedback = null;
  state.craftingCube.feedbackKind = null;

  const crystalItem = itemDefinition(HAVOC_CRYSTAL_ITEM_ID);
  addInventoryItem(HAVOC_CRYSTAL_ITEM_ID, validation.totalCrystals);
  const crystalName = crystalItem?.name ?? "Havoc Crystal";
  const itemLabel = entryIds.length === 1 ? "item" : "items";
  const crystalLabel = validation.totalCrystals === 1 ? crystalName : `${crystalName}s`;
  pushBattleLog(`Salvaged ${entryIds.length} empowered ${itemLabel} for ${validation.totalCrystals} ${crystalLabel}.`);
  addLootNotice(`${validation.totalCrystals}× ${crystalName}`, "item");

  hideItemTooltip();
  sceneSignature = "";
  gamePanelSignature = "";
  saveGameState(true);
  renderSceneOverlay();
  renderGamePanel();
  playSfx("item.pickup", { volume: 0.42, throttleMs: 120 });
  return true;
}

function canAffordCraftingCubeGold(recipeId) {
  const cost = craftingCubeRecipeGoldCost(recipeId);
  if (cost <= 0) return true;
  return (Number(state.inventory?.gold) || 0) >= cost;
}

function reportCraftingCubeGoldShortfall(recipeId) {
  const cost = craftingCubeRecipeGoldCost(recipeId);
  setCraftingCubeFeedback(`Need ${cost.toLocaleString("en-US")} gold to craft this.`);
  sceneSignature = "";
  renderSceneOverlay();
  playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
}

function spendCraftingCubeGold(recipeId) {
  const cost = craftingCubeRecipeGoldCost(recipeId);
  if (cost <= 0) return;
  state.inventory.gold = Math.max(0, (Number(state.inventory?.gold) || 0) - cost);
  state.game.progress.gold = state.inventory.gold;
  state.battle.gold = state.inventory.gold;
}

function attemptCraftingCubeFocusPrismCraft() {
  if (state.craftingCube?.mode !== "craft") return false;
  const validation = validateCraftingCubeFocusPrismCraft(craftingCubeBoardEntries());
  if (!validation.ok) {
    setCraftingCubeFeedback(validation.error);
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
    return false;
  }

  if (!canAffordCraftingCubeGold(CRAFTING_CUBE_FOCUS_PRISM_RECIPE_ID)) {
    reportCraftingCubeGoldShortfall(CRAFTING_CUBE_FOCUS_PRISM_RECIPE_ID);
    return false;
  }

  consumeStagedCraftingCubeEntryQuantity(
    validation.crystalEntry.id,
    CRAFTING_CUBE_FOCUS_PRISM_CRYSTAL_COST,
  );
  spendCraftingCubeGold(CRAFTING_CUBE_FOCUS_PRISM_RECIPE_ID);
  state.craftingCube.feedback = null;
  state.craftingCube.feedbackKind = null;
  state.craftingCube.lastRerollNotice = null;

  const prismItem = itemDefinition(FOCUS_PRISM_ITEM_ID);
  addInventoryItem(FOCUS_PRISM_ITEM_ID, 1);
  const prismName = prismItem?.name ?? "Focus Prism";
  pushBattleLog(`Crafted 1 ${prismName} from ${CRAFTING_CUBE_FOCUS_PRISM_CRYSTAL_COST} Havoc Crystals.`);
  addLootNotice(`1× ${prismName}`, "item");

  hideItemTooltip();
  sceneSignature = "";
  gamePanelSignature = "";
  saveGameState(true);
  renderSceneOverlay();
  renderGamePanel();
  playSfx("item.pickup", { volume: 0.42, throttleMs: 120 });
  return true;
}

function setCraftingCubeTargetedEmpowerSlot(slotIndex) {
  if (!state.craftingCube) state.craftingCube = createDefaultCraftingCubeState();
  const pick = Math.trunc(Number(slotIndex) || 0);
  if (state.craftingCube.targetedEmpowerSlotIndex === pick) return;
  state.craftingCube.targetedEmpowerSlotIndex = pick;
  state.craftingCube.feedback = null;
  state.craftingCube.feedbackKind = null;
  sceneSignature = "";
  renderSceneOverlay();
  playSfx("ui.button", { volume: 0.28, throttleMs: 80 });
}

function setCraftingCubeTargetedEmpowerSwapSlot(side, slotIndex) {
  if (!state.craftingCube) state.craftingCube = createDefaultCraftingCubeState();
  const pick = Math.trunc(Number(slotIndex) || 0);
  const key = String(side ?? "").toLowerCase() === "b" ? "targetedEmpowerSwapSlotB" : "targetedEmpowerSwapSlotA";
  if (state.craftingCube[key] === pick) return;
  state.craftingCube[key] = pick;
  state.craftingCube.feedback = null;
  state.craftingCube.feedbackKind = null;
  sceneSignature = "";
  renderSceneOverlay();
  playSfx("ui.button", { volume: 0.28, throttleMs: 80 });
}

function announceCraftingCubeEmpowerReroll(empoweredItem, empoweredEntry, reroll) {
  const itemName = itemDisplayName(empoweredItem, empoweredEntry);
  const removedLabel = formatEmpowerAppliedChangeLabel(reroll.removedRoll, reroll.removedAmount);
  const addedLabel = formatEmpowerAppliedChangeLabel(reroll.newRoll, reroll.appliedAmount);
  state.craftingCube.lastRerollNotice = { removed: removedLabel, added: addedLabel };
  clearCraftingCubeTargetedSelections();
  pushBattleLog(`${itemName}: removed ${removedLabel}. Added ${addedLabel}.`);
  addLootNotice(`Removed ${removedLabel}`, "item");
  addLootNotice(`Added ${addedLabel}`, "level");
}

function announceCraftingCubeEmpowerSwap(swap) {
  const nameA = itemDisplayName(swap.itemA, swap.entryA);
  const nameB = itemDisplayName(swap.itemB, swap.entryB);
  const removedA = formatEmpowerAppliedChangeLabel(swap.rollA, swap.amountA);
  const addedA = formatEmpowerAppliedChangeLabel(swap.rollB, swap.amountB);
  const removedB = formatEmpowerAppliedChangeLabel(swap.rollB, swap.amountB);
  const addedB = formatEmpowerAppliedChangeLabel(swap.rollA, swap.amountA);
  state.craftingCube.lastRerollNotice = {
    swap: true,
    items: [
      { name: nameA, removed: removedA, added: addedA },
      { name: nameB, removed: removedB, added: addedB },
    ],
  };
  clearCraftingCubeTargetedSelections();
  pushBattleLog(`${nameA}: swapped ${removedA} for ${addedA} from ${nameB}.`);
  pushBattleLog(`${nameB}: swapped ${removedB} for ${addedB} from ${nameA}.`);
  addLootNotice(`${nameA}: ${removedA} → ${addedA}`, "item");
  addLootNotice(`${nameB}: ${removedB} → ${addedB}`, "level");
}

function attemptCraftingCubeEmpowerSwap() {
  if (state.craftingCube?.mode !== "craft") return false;
  const validation = validateCraftingCubeEmpowerSwap(craftingCubeBoardEntries());
  if (!validation.ok) {
    setCraftingCubeFeedback(validation.error);
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
    return false;
  }

  if (!canAffordCraftingCubeGold(CRAFTING_CUBE_EMPOWER_SWAP_RECIPE_ID)) {
    reportCraftingCubeGoldShortfall(CRAFTING_CUBE_EMPOWER_SWAP_RECIPE_ID);
    return false;
  }

  const swap = swapRandomEmpowermentsBetweenEntries(
    validation.empoweredEntryA,
    validation.empoweredItemA,
    validation.empoweredEntryB,
    validation.empoweredItemB,
  );
  if (!swap.ok) {
    setCraftingCubeFeedback(swap.error);
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
    return false;
  }

  consumeStagedCraftingCubeEntryQuantity(
    validation.crystalEntry.id,
    CRAFTING_CUBE_EMPOWER_SWAP_CRYSTAL_COST,
  );
  spendCraftingCubeGold(CRAFTING_CUBE_EMPOWER_SWAP_RECIPE_ID);
  state.craftingCube.feedback = null;
  state.craftingCube.feedbackKind = null;

  announceCraftingCubeEmpowerSwap(swap);

  hideItemTooltip();
  applyEquippedStatsToBattlePlayer();
  sceneSignature = "";
  gamePanelSignature = "";
  saveGameState(true);
  renderSceneOverlay();
  renderGamePanel();
  playSfx("item.equip.weapon", { volume: 0.4, throttleMs: 120 });
  return true;
}

function attemptCraftingCubeTargetedEmpowerSwap() {
  if (state.craftingCube?.mode !== "craft") return false;
  const validation = validateCraftingCubeTargetedEmpowerSwap(craftingCubeBoardEntries());
  if (!validation.ok) {
    setCraftingCubeFeedback(validation.error);
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
    return false;
  }

  const choicesA = empowerSlotChoiceLabels(validation.empoweredEntryA, validation.empoweredItemA);
  const choicesB = empowerSlotChoiceLabels(validation.empoweredEntryB, validation.empoweredItemB);
  const slotA = Math.trunc(Number(state.craftingCube?.targetedEmpowerSwapSlotA) || 0);
  const slotB = Math.trunc(Number(state.craftingCube?.targetedEmpowerSwapSlotB) || 0);
  if (!choicesA.some((choice) => choice.index === slotA) || !choicesB.some((choice) => choice.index === slotB)) {
    setCraftingCubeFeedback("Select an empowerment on each item to swap.");
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
    return false;
  }

  if (!canAffordCraftingCubeGold(CRAFTING_CUBE_TARGETED_EMPOWER_SWAP_RECIPE_ID)) {
    reportCraftingCubeGoldShortfall(CRAFTING_CUBE_TARGETED_EMPOWER_SWAP_RECIPE_ID);
    return false;
  }

  const swap = swapEmpowermentsAtSlotIndices(
    validation.empoweredEntryA,
    validation.empoweredItemA,
    slotA,
    validation.empoweredEntryB,
    validation.empoweredItemB,
    slotB,
  );
  if (!swap.ok) {
    setCraftingCubeFeedback(swap.error);
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
    return false;
  }

  consumeStagedCraftingCubeEntryQuantity(
    validation.focusPrismEntry.id,
    CRAFTING_CUBE_TARGETED_EMPOWER_SWAP_PRISM_COST,
  );
  consumeStagedCraftingCubeEntryQuantity(validation.adamantineEntry.id, 1);
  spendCraftingCubeGold(CRAFTING_CUBE_TARGETED_EMPOWER_SWAP_RECIPE_ID);
  state.craftingCube.feedback = null;
  state.craftingCube.feedbackKind = null;

  announceCraftingCubeEmpowerSwap(swap);

  hideItemTooltip();
  applyEquippedStatsToBattlePlayer();
  sceneSignature = "";
  gamePanelSignature = "";
  saveGameState(true);
  renderSceneOverlay();
  renderGamePanel();
  playSfx("item.equip.weapon", { volume: 0.4, throttleMs: 120 });
  return true;
}

function attemptCraftingCubeEmpowerReroll() {
  if (state.craftingCube?.mode !== "craft") return false;
  const validation = validateCraftingCubeEmpowerReroll(craftingCubeBoardEntries());
  if (!validation.ok) {
    setCraftingCubeFeedback(validation.error);
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
    return false;
  }

  if (!canAffordCraftingCubeGold(CRAFTING_CUBE_EMPOWER_REROLL_RECIPE_ID)) {
    reportCraftingCubeGoldShortfall(CRAFTING_CUBE_EMPOWER_REROLL_RECIPE_ID);
    return false;
  }

  const reroll = rollEmpowermentReroll(validation.empoweredEntry, validation.empoweredItem);
  if (!reroll.ok) {
    setCraftingCubeFeedback(reroll.error);
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
    return false;
  }

  consumeStagedCraftingCubeEntryQuantity(validation.crystalEntry.id, 1);
  spendCraftingCubeGold(CRAFTING_CUBE_EMPOWER_REROLL_RECIPE_ID);
  state.craftingCube.feedback = null;
  state.craftingCube.feedbackKind = null;

  announceCraftingCubeEmpowerReroll(validation.empoweredItem, validation.empoweredEntry, reroll);

  hideItemTooltip();
  applyEquippedStatsToBattlePlayer();
  sceneSignature = "";
  gamePanelSignature = "";
  saveGameState(true);
  renderSceneOverlay();
  renderGamePanel();
  playSfx("item.equip.weapon", { volume: 0.4, throttleMs: 120 });
  return true;
}

function attemptCraftingCubeTargetedEmpowerReroll() {
  if (state.craftingCube?.mode !== "craft") return false;
  const validation = validateCraftingCubeTargetedEmpowerReroll(craftingCubeBoardEntries());
  if (!validation.ok) {
    setCraftingCubeFeedback(validation.error);
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
    return false;
  }

  const slotChoices = empowerSlotChoiceLabels(validation.empoweredEntry, validation.empoweredItem);
  const slotIndex = Math.trunc(Number(state.craftingCube?.targetedEmpowerSlotIndex) || 0);
  if (!slotChoices.some((choice) => choice.index === slotIndex)) {
    setCraftingCubeFeedback("Select an empowerment to reroll.");
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
    return false;
  }

  if (!canAffordCraftingCubeGold(CRAFTING_CUBE_TARGETED_EMPOWER_REROLL_RECIPE_ID)) {
    reportCraftingCubeGoldShortfall(CRAFTING_CUBE_TARGETED_EMPOWER_REROLL_RECIPE_ID);
    return false;
  }

  const reroll = rollEmpowermentRerollAtSlot(
    validation.empoweredEntry,
    validation.empoweredItem,
    slotIndex,
  );
  if (!reroll.ok) {
    setCraftingCubeFeedback(reroll.error);
    sceneSignature = "";
    renderSceneOverlay();
    playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
    return false;
  }

  consumeStagedCraftingCubeEntryQuantity(
    validation.crystalEntry.id,
    CRAFTING_CUBE_TARGETED_EMPOWER_REROLL_CRYSTAL_COST,
  );
  consumeStagedCraftingCubeEntryQuantity(validation.adamantineEntry.id, 1);
  spendCraftingCubeGold(CRAFTING_CUBE_TARGETED_EMPOWER_REROLL_RECIPE_ID);
  state.craftingCube.feedback = null;
  state.craftingCube.feedbackKind = null;

  announceCraftingCubeEmpowerReroll(validation.empoweredItem, validation.empoweredEntry, reroll);

  hideItemTooltip();
  applyEquippedStatsToBattlePlayer();
  sceneSignature = "";
  gamePanelSignature = "";
  saveGameState(true);
  renderSceneOverlay();
  renderGamePanel();
  playSfx("item.equip.weapon", { volume: 0.4, throttleMs: 120 });
  return true;
}

function craftingCubeRecipeValidation(recipeId, boardEntries = craftingCubeBoardEntries()) {
  if (recipeId === CRAFTING_CUBE_FOCUS_PRISM_RECIPE_ID) {
    return validateCraftingCubeFocusPrismCraft(boardEntries);
  }
  if (recipeId === CRAFTING_CUBE_EMPOWER_REROLL_RECIPE_ID) {
    return validateCraftingCubeEmpowerReroll(boardEntries);
  }
  if (recipeId === CRAFTING_CUBE_TARGETED_EMPOWER_REROLL_RECIPE_ID) {
    return validateCraftingCubeTargetedEmpowerReroll(boardEntries);
  }
  if (recipeId === CRAFTING_CUBE_EMPOWER_SWAP_RECIPE_ID) {
    return validateCraftingCubeEmpowerSwap(boardEntries);
  }
  if (recipeId === CRAFTING_CUBE_TARGETED_EMPOWER_SWAP_RECIPE_ID) {
    return validateCraftingCubeTargetedEmpowerSwap(boardEntries);
  }
  return { ok: false, error: "Select a recipe." };
}

function craftingCubeSelectedRecipeDef() {
  const recipeId = state.craftingCube?.selectedRecipeId;
  return CRAFTING_CUBE_RECIPES.find((recipe) => recipe.id === recipeId) ?? null;
}

function canAttemptCraftingCubeCraft() {
  if (state.craftingCube?.mode !== "craft") return false;
  const recipeId = state.craftingCube?.selectedRecipeId;
  if (!recipeId) return false;
  const validation = craftingCubeRecipeValidation(recipeId);
  if (!validation.ok) return false;
  if (recipeId === CRAFTING_CUBE_TARGETED_EMPOWER_REROLL_RECIPE_ID) {
    const choices = empowerSlotChoiceLabels(validation.empoweredEntry, validation.empoweredItem);
    const slotIndex = Math.trunc(Number(state.craftingCube?.targetedEmpowerSlotIndex) || 0);
    return choices.some((choice) => choice.index === slotIndex);
  }
  if (recipeId === CRAFTING_CUBE_TARGETED_EMPOWER_SWAP_RECIPE_ID) {
    const choicesA = empowerSlotChoiceLabels(validation.empoweredEntryA, validation.empoweredItemA);
    const choicesB = empowerSlotChoiceLabels(validation.empoweredEntryB, validation.empoweredItemB);
    const slotA = Math.trunc(Number(state.craftingCube?.targetedEmpowerSwapSlotA) || 0);
    const slotB = Math.trunc(Number(state.craftingCube?.targetedEmpowerSwapSlotB) || 0);
    return choicesA.some((choice) => choice.index === slotA)
      && choicesB.some((choice) => choice.index === slotB);
  }
  return true;
}

function attemptCraftingCubeCraft() {
  const recipeId = state.craftingCube?.selectedRecipeId;
  if (recipeId === CRAFTING_CUBE_FOCUS_PRISM_RECIPE_ID) return attemptCraftingCubeFocusPrismCraft();
  if (recipeId === CRAFTING_CUBE_EMPOWER_REROLL_RECIPE_ID) return attemptCraftingCubeEmpowerReroll();
  if (recipeId === CRAFTING_CUBE_TARGETED_EMPOWER_REROLL_RECIPE_ID) return attemptCraftingCubeTargetedEmpowerReroll();
  if (recipeId === CRAFTING_CUBE_EMPOWER_SWAP_RECIPE_ID) return attemptCraftingCubeEmpowerSwap();
  if (recipeId === CRAFTING_CUBE_TARGETED_EMPOWER_SWAP_RECIPE_ID) return attemptCraftingCubeTargetedEmpowerSwap();
  setCraftingCubeFeedback("Select a recipe from the Recipes panel.");
  sceneSignature = "";
  renderSceneOverlay();
  playSfx("ui.button", { volume: 0.28, throttleMs: 120 });
  return false;
}

function setCraftingCubeMode(mode) {
  const next = String(mode ?? "").toLowerCase();
  if (!CRAFTING_CUBE_MODES.includes(next)) return;
  if (!state.craftingCube) state.craftingCube = createDefaultCraftingCubeState();
  if (state.craftingCube.mode === next) return;
  state.craftingCube.mode = next;
  state.craftingCube.feedback = null;
  state.craftingCube.feedbackKind = null;
  state.craftingCube.lastRerollNotice = null;
  clearCraftingCubeTargetedSelections();
  sceneSignature = "";
  renderSceneOverlay();
  playSfx("ui.button", { volume: 0.32, throttleMs: 80 });
}

function toggleCraftingCubeRecipesPanel() {
  if (!state.craftingCube) state.craftingCube = createDefaultCraftingCubeState();
  const next = !state.craftingCube.recipesOpen;
  state.craftingCube.recipesOpen = next;
  if (next) {
    state.craftingCube.mode = "craft";
    if (!state.craftingCube.selectedRecipeId) {
      state.craftingCube.selectedRecipeId = CRAFTING_CUBE_RECIPES[0]?.id ?? null;
    }
    pushSceneWindow("craftingCubeRecipes");
  } else {
    removeSceneWindowFromStack("craftingCubeRecipes");
  }
  state.craftingCube.feedback = null;
  state.craftingCube.feedbackKind = null;
  sceneSignature = "";
  renderSceneOverlay();
  playSfx("ui.button", { volume: 0.32, throttleMs: 80 });
}

function selectCraftingCubeRecipe(recipeId) {
  const next = String(recipeId ?? "");
  if (!CRAFTING_CUBE_RECIPES.some((recipe) => recipe.id === next)) return;
  if (!state.craftingCube) state.craftingCube = createDefaultCraftingCubeState();
  state.craftingCube.selectedRecipeId = next;
  state.craftingCube.mode = "craft";
  state.craftingCube.feedback = null;
  state.craftingCube.feedbackKind = null;
  if (!state.craftingCube.recipesOpen) state.craftingCube.recipesOpen = true;
  pushSceneWindow("craftingCubeRecipes");
  autofillCraftingCubeForRecipe(next);
  sceneSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  playSfx("ui.button", { volume: 0.28, throttleMs: 80 });
}

function openCraftingCubeScene() {
  if (state.game.mode !== "town" || !empoweredCraftingUnlocked()) return;
  state.activeScene = "craftingCube";
  state.openScenes.inventory = true;
  if (!state.craftingCube) state.craftingCube = createDefaultCraftingCubeState();
  pushSceneWindow("craftingCube");
  sceneSignature = "";
  gamePanelSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  playSfx("ui.button", { volume: 0.35, throttleMs: 120 });
}

function finalizeWeaponRefineOutcome({
  success,
  crit,
  preview,
  weaponEntryId,
  weaponEntry,
  weaponItem,
  weaponName,
  statLabel,
  statGain,
}) {
  consumeWeaponRefineStagedMaterials();
  state.weaponRefine.weaponEntryId = null;
  state.weaponRefine.resultFx = null;
  state.weaponRefine.resultFxTimer = null;

  if (success) {
    applyWeaponRefineSuccess(weaponEntry, preview.statKey, statGain);
    unstageWeaponRefineEntry(weaponEntryId);
    const critNote = crit ? " Critical success!" : "";
    pushBattleLog(`${weaponName} refined: +${statGain} ${statLabel}.${critNote}`);
    addLootNotice(`${weaponItem.name} +${statGain} ${statLabel}`, "item");
  } else {
    discardWeaponRefineStagedEntry(weaponEntryId);
    pushBattleLog(`${weaponName} shattered during refining (${preview.chance}% chance).`);
  }

  hideItemTooltip();
  applyEquippedStatsToBattlePlayer();
  sceneSignature = "";
  gamePanelSignature = "";
  battlePanelSignature = "";
  playerHudSignature = "";
  saveGameState(true);
  renderSceneOverlay();
  renderGamePanel();
  renderBattlePanel();
  renderPlayerResourceHud();
}

function attemptWeaponRefine() {
  if (weaponRefineResultFxActive()) return false;
  if (!weaponRefineBoardReady()) {
    pushBattleLog("Place a weapon on the refine table first.");
    return false;
  }

  const weaponEntryId = state.weaponRefine.weaponEntryId;
  const weaponEntry = weaponRefineEntryById(weaponEntryId);
  const weaponItem = weaponEntry ? itemDefinition(weaponEntry.itemId) : null;
  if (!weaponEntry || !weaponItem || weaponItem.slot !== "weapon") {
    pushBattleLog("The selected weapon is no longer available.");
    resetWeaponRefineState();
    sceneSignature = "";
    gamePanelSignature = "";
    renderSceneOverlay();
    renderGamePanel();
    return false;
  }
  if (sanitizeWeaponRefineLevel(weaponEntry.weaponRefineLevel) >= WEAPON_REFINE_MAX) {
    pushBattleLog(`${itemDisplayName(weaponItem, weaponEntry)} is already at refine +${WEAPON_REFINE_MAX}.`);
    return false;
  }

  const preview = computeWeaponRefineChance(collectWeaponRefineIngredients());
  if (preview.autoFail) {
    pushBattleLog(preview.reason);
    return false;
  }

  const goldCost = weaponRefineGoldCost(weaponEntry);
  if (!chargeWeaponRefineGold(goldCost)) {
    pushBattleLog(`Need ${goldCost.toLocaleString()} gold to refine ${itemDisplayName(weaponItem, weaponEntry)}.`);
    battlePanelSignature = "";
    playerHudSignature = "";
    renderBattlePanel();
    renderPlayerResourceHud();
    return false;
  }
  playSfx("ui.gold", { volume: 0.42, throttleMs: 120 });

  const weaponName = itemDisplayName(weaponItem, weaponEntry);
  const statLabel = smithStatLabel(preview.statKey);
  const success = rollWeaponRefineSuccess(preview.chance);
  const crit = success && rollWeaponRefineCrit();
  const statGain = crit
    ? WEAPON_REFINE_STAT_INCREASE * WEAPON_REFINE_CRIT_MULTIPLIER
    : WEAPON_REFINE_STAT_INCREASE;

  playWeaponRefineResultFx(success, crit);
  playWeaponRefineResultSfx(success, crit);
  sceneSignature = "";
  gamePanelSignature = "";
  battlePanelSignature = "";
  playerHudSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  renderBattlePanel();
  renderPlayerResourceHud();

  state.weaponRefine.resultFxTimer = window.setTimeout(() => {
    finalizeWeaponRefineOutcome({
      success,
      crit,
      preview,
      weaponEntryId,
      weaponEntry,
      weaponItem,
      weaponName,
      statLabel,
      statGain,
    });
  }, WEAPON_REFINE_RESULT_FX_MS);

  return success;
}

function junkOreInventoryEntries() {
  ensureInventorySlots();
  return inventoryEntries()
    .map((entry) => ({ entry, item: itemDefinition(entry.itemId) }))
    .filter(({ entry, item }) => isJunkOreItem(item)
      && !isEquippedEntry(entry.id)
      && !isHotbarEntry(entry.id)
      && itemSellValue(item, Math.max(1, Number(entry.quantity) || 1)) > 0);
}

function junkOreSellPreview() {
  const rows = junkOreInventoryEntries();
  const count = rows.reduce((sum, { entry }) => sum + Math.max(1, Number(entry.quantity) || 1), 0);
  const gold = rows.reduce((sum, { entry, item }) => {
    const quantity = Math.max(1, Number(entry.quantity) || 1);
    return sum + itemSellValue(item, quantity);
  }, 0);
  return { count, gold };
}

function junkMarkedInventoryEntries() {
  ensureInventorySlots();
  return inventoryEntries()
    .map((entry) => ({ entry, item: itemDefinition(entry.itemId) }))
    .filter(({ entry, item }) => isInventoryEntryJunk(entry)
      && !isEquippedEntry(entry.id)
      && !isHotbarEntry(entry.id)
      && item
      && itemSellValue(item, Math.max(1, Number(entry.quantity) || 1)) > 0);
}

function junkMarkedSellPreview() {
  const rows = junkMarkedInventoryEntries();
  const count = rows.reduce((sum, { entry }) => sum + Math.max(1, Number(entry.quantity) || 1), 0);
  const gold = rows.reduce((sum, { entry, item }) => {
    const quantity = Math.max(1, Number(entry.quantity) || 1);
    return sum + itemSellValue(item, quantity);
  }, 0);
  return { count, gold };
}

function sellAllJunkMarkedInventory() {
  const rows = junkMarkedInventoryEntries();
  if (!rows.length) {
    pushBattleLog("No junk-marked items to sell.");
    battlePanelSignature = "";
    renderBattlePanel();
    return false;
  }

  let soldCount = 0;
  let totalGold = 0;
  for (const { entry, item } of rows) {
    const quantity = Math.max(1, Number(entry.quantity) || 1);
    const value = itemSellValue(item, quantity);
    if (value <= 0) continue;
    if (!removeInventoryEntry(entry.id, quantity)) continue;
    soldCount += quantity;
    totalGold += value;
  }

  if (soldCount <= 0) {
    pushBattleLog("No junk-marked items to sell.");
    battlePanelSignature = "";
    renderBattlePanel();
    return false;
  }

  state.inventory.gold += totalGold;
  state.game.progress.gold = state.inventory.gold;
  state.battle.gold = state.game.progress.gold;
  syncBossPartyControlledInventoryFromState();
  playSfx("ui.gold", { volume: 0.55, throttleMs: 80 });
  pushBattleLog(`Sold ${soldCount} junk-marked item${soldCount === 1 ? "" : "s"} for ${totalGold} gold.`);
  hideItemTooltip();
  sceneSignature = "";
  gamePanelSignature = "";
  battlePanelSignature = "";
  hotbarSignature = "";
  renderSceneOverlay();
  renderGamePanel();
  renderBattlePanel();
  renderHotbar();
  return true;
}

